# BorЕҜvka
<!-- more -->
жұӮжңҖе°Ҹз”ҹжҲҗж ‘еёёз”Ёз®—жі•жңү $Kruskal$ е’Ң $Prime$ з®—жі•пјҢдёӢйқўд»Ӣз»Қз¬¬дёүз§ҚжұӮжңҖе°Ҹз”ҹжҲҗж ‘зҡ„з®—жі• вҖ”вҖ” $BorЕҜvka$гҖӮ

з®—жі•зҡ„жү§иЎҢжөҒзЁӢеҰӮдёӢпјҡ
1.  еҜ№жҜҸдёҖдёӘиҝһйҖҡеқ—пјҢи®°еҪ•дёҚеңЁз”ҹжҲҗж ‘дёӯпјҢд»ҺиҝҷдёӘеқ—еҮәеҸ‘пјҢиғҪеҲ°иҫҫеҲ«зҡ„иҒ”йҖҡеқ—зҡ„й•ҝеәҰжңҖе°Ҹзҡ„иҫ№гҖӮпјҲжіЁпјҡй•ҝеәҰзӣёеҗҢйҖүзј–еҸ·е°Ҹзҡ„иҫ№пјҢдҝқиҜҒдёӨдёӘиҒ”йҖҡеқ—дә’иҝһж—¶йҖүзҡ„иҫ№жҳҜдёҖиҮҙзҡ„пјҢеҗҰеҲҷжңүеҸҜиғҪеҮәзҺ°зҺҜпјү

1. е°ҶдёҠдёҖжӯҘйҖүдёӯзҡ„иҫ№еҠ е…ҘжңҖе°Ҹз”ҹжҲҗж ‘гҖӮ

1. йҮҚеӨҚдёҠиҝ°жӯҘйӘӨпјҢзӣҙеҲ°жІЎжңүиҫ№еҸҜд»ҘеҠ е…ҘгҖӮ


![еҠЁеӣҫ](https://upload.wikimedia.org/wikipedia/commons/2/2e/Boruvka%27s_algorithm_%28Sollin%27s_algorithm%29_Anim.gif)

$BorЕҜvka$ з®—жі•жј”зӨәеҠЁеӣҫеҰӮдёҠпјҲжәҗпјҡWikimedia)

з”ұдәҺжҜҸж¬ЎеҗҲе№¶зҡ„ж—¶й—ҙеӨҚжқӮеәҰдёә $O(M)$пјҢжҜҸж¬ЎеҗҲе№¶еҗҺпјҢиҝһйҖҡеқ—зҡ„дёӘж•°еҮҸе°‘дёҖеҚҠпјҢеӣ жӯӨжҖ»зҡ„ж—¶й—ҙеӨҚжқӮеәҰжҳҜ $O(MlogN)$ зҡ„гҖӮ

# дҫӢйўҳ
## P3366 жЁЎжқҝ-жңҖе°Ҹз”ҹжҲҗж ‘
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P3366)
### Solution
з”Ёе№¶жҹҘйӣҶе®№жҳ“е®һзҺ°дёҠиҝ°иҝҮзЁӢгҖӮеҜ№дәҺеӣҫзҡ„иҝһйҖҡжҖ§зҡ„еҲӨж–ӯпјҢеҸҜд»ҘејҖдёҖдёӘеҸҳйҮҸи®°еҪ•еҠ е…Ҙиҫ№зҡ„жҖ»ж•°пјҢеҰӮжһңжҖ»ж•°дёҚжҳҜ $n-1$ иҜҙжҳҺеӣҫдёҚиҝһйҖҡгҖӮ
### Code
```cpp жЁЎжқҝ-жңҖе°Ҹз”ҹжҲҗж ‘
#include <bits/stdc++.h>

using namespace std;

int n, m, u, v, fa[5005], miEdge[5005];
bool used[200005];

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Egde {
    int to, from, len;
} e[200005];

int find(int x) {
    if (fa[x] != x) fa[x] = find(fa[x]);
    return fa[x];
}

void Boruvka() {
    int merged = 0;
    long long sum = 0;
    for (int i = 1; i <= n; i++) fa[i] = i;

    bool tag = true;
    while (tag) {
        tag = false;
        fill(miEdge + 1, miEdge + n + 1, 0);
        for (int i = 1; i <= m; i++) {
            if (used[i]) continue;
            int r1 = find(e[i].from), r2 = find(e[i].to);
            if (r1 == r2) continue;
            if (!miEdge[r1] || e[i].len < e[miEdge[r1]].len) miEdge[r1] = i;
            if (!miEdge[r2] || e[i].len < e[miEdge[r2]].len) miEdge[r2] = i;
        }
        for (int i = 1; i <= n; i++) {
            if (miEdge[i] && !used[miEdge[i]]) {
                tag = true;
                merged++;
                int eid = miEdge[i];
                sum += e[eid].len;
                used[eid] = 1;
                fa[find(e[eid].from)] = find(e[eid].to);
            }
        }
    }
    if (merged == n - 1)
        cout << sum;
    else
        cout << "orz";
}

int main() {
    read(n), read(m);
    for (int i = 1; i <= m; i++) read(e[i].from), read(e[i].to), read(e[i].len);
    Boruvka();
    return 0;
}
```

## CF888G Xor-MST
[йўҳзӣ®й“ҫжҺҘ](https://codeforces.ml/problemset/problem/888/G)
### Description
з»ҷеҮәе®Ңе…Ёеӣҫ $K_n$пјҢд»»ж„ҸдёӨзӮ№ $i,j$ зҡ„иҫ№жқғдёә $a_i вҠ• a_j$пјҢжұӮиҜҘеӣҫзҡ„жңҖе°Ҹз”ҹжҲҗж ‘гҖӮ
### Solution
з”ұдәҺиҫ№жңү $n*(n+1)/2$ жқЎпјҢеӣ жӯӨиҖғиҷ‘дҪҝз”Ё $BorЕҜvka$ з®—жі•гҖӮеҜ№жүҖжңүиҠӮзӮ№е»әз«ӢдёҖдёӘе…ЁеұҖ $trie$пјҢеҗҢж—¶жҜҸдёӘиҒ”йҖҡеқ—еҗ„иҮӘз»ҙжҠӨдёҖдёӘ $trie$гҖӮжұӮдёҚеұһдәҺжҹҗдёҖиҒ”йҖҡеқ—зҡ„жңҖе°Ҹзҡ„иҫ№еҸҜд»ҘйҖҡиҝҮеңЁе…ЁеұҖ $trie$ е’ҢеҪ“еүҚиҝһйҖҡеқ—зҡ„ $trie$ дёҠеҜ№ $size$ дҪңе·®иҙӘеҝғең°жұӮеҫ—пјҢиҖҢеҠ е…ҘдёҖжқЎиҫ№е°ұжҳҜе°ҶдёӨдёӘ $trie$ еҗҲе№¶гҖӮдёҠиҝ°и§Јжі•ж—¶й—ҙеӨҚжқӮеәҰжҳҜ $O(nlog{n}log{\max\limits_{i=1}^{n}a[i]})$гҖӮ
### Code
```cpp Xor-MST
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 2E5 + 5;
int n, m, a[MAXN], fa[MAXN], root[MAXN], minEdge[MAXN], nxt[MAXN];

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Trie {
    int son[2], sz, id;
    Trie() { son[0] = son[1] = sz = id = 0; }
} tr[MAXN * 31 * 2];

void insert(int root, int id) {
    static int cntNode = n + 1;
    int cur = root;
    for (int i = 30; ~i; i--) {
        int to = (a[id] >> i) & 1;
        if (!tr[cur].son[to]) tr[cur].son[to] = ++cntNode;
        cur = tr[cur].son[to];
        tr[cur].sz++;
    }
    tr[cur].id = id;
}

int merge(int root1, int root2) {
    if (!root1 || !root2) return root1 + root2;
    tr[root1].sz += tr[root2].sz;
    for (int i = 0; i < 2; i++)
        tr[root1].son[i] = merge(tr[root1].son[i], tr[root2].son[i]);
    return root1;
}

int query(int root1, int root2, int val) {
    for (int i = 30; ~i; i--) {
        int to = (val >> i) & 1;
        if (tr[tr[root1].son[to]].sz > tr[tr[root2].son[to]].sz)
            root1 = tr[root1].son[to], root2 = tr[root2].son[to];
        else
            root1 = tr[root1].son[to ^ 1], root2 = tr[root2].son[to ^ 1];
    }
    return tr[root1].id;
}

int find(int x) {
    if (fa[x] != x) fa[x] = find(fa[x]);
    return fa[x];
}

void Boruvka() {
    long long sum = 0;
    for (int i = 1; i <= n; i++) fa[i] = i, insert(root[i], i);
    bool tag = true;
    while (tag) {
        tag = false;
        fill(minEdge + 1, minEdge + n + 1, -1);
        for (int i = 1; i <= n; i++) {
            int r1 = find(i);
            int id = query(root[0], root[r1], a[i]);
            if (!id) continue;
            int len = a[id] ^ a[i];
            int r2 = find(id);
            if (minEdge[r1] == -1 || len < minEdge[r1])
                minEdge[r1] = len, nxt[r1] = r2;
            if (minEdge[r2] == -1 || len < minEdge[r2])
                minEdge[r2] = len, nxt[r2] = r1;
        }
        for (int i = 1; i <= n; i++) {
            if (minEdge[i] != -1 && find(i) != find(nxt[i])) {
                tag = true;
                merge(root[find(i)], root[find(nxt[i])]);
                sum += minEdge[i];
                fa[find(nxt[i])] = i;
            }
        }
    }
    cout << sum;
}

int main() {
    read(n);
    for (int i = 1; i <= n; i++) read(a[i]);
    sort(a + 1, a + n + 1);
    for (int i = 0; i <= n; i++) root[i] = i + 1;
    for (int i = 1; i <= n; i++) insert(root[0], i);
    Boruvka();
    return 0;
}
```

