## Solution
йҰ–е…ҲеҜ№дәҺдёҖжқЎиҫ№пјҢе®ғдјҡиў«и®Ўз®—**дёӨз«Ҝзҡ„еӯҗж ‘еӨ§е°Ҹзҡ„д№ҳз§Ҝ**ж¬ЎгҖӮиҰҒи®©зӯ”жЎҲжңҖеӨ§пјҢйӮЈд№Ҳиў«и®Ўз®—ж¬Ўж•°жңҖеӨҡзҡ„иҫ№зҡ„иҫ№жқғеә”дёәжңҖеӨ§зҡ„зәҰж•°пјҢдҫқжӯӨзұ»жҺЁгҖӮжіЁж„ҸеҰӮжһңиҙЁеӣ ж•°дёӘж•°и¶…иҝҮ $n - 1$пјҢеҲҷе°ҶжңҖеӨ§зҡ„еҮ дёӘиҙЁеӣ еӯҗд№ҳиө·жқҘпјҢеҲҶй…Қз»ҷиў«и®Ўз®—жңҖеӨҡзҡ„иҫ№гҖӮ
## Code
```cpp Maximum Distributed Tree
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 1e5 + 5, MOD = 1e9 + 7;

int tc, n, m;
vector<int> G[MAXN], cnt;
array<int, MAXN> w, sz;

void dfs(int cur, int fa) {
    sz[cur] = 1;
    for (auto& to : G[cur]) {
        if (to == fa) continue;
        dfs(to, cur);
        sz[cur] += sz[to];
    }
    cnt.push_back(sz[cur] * (n - sz[cur]));
}

signed main() {
    ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> tc;
    while (tc--) {
        cin >> n;
        for (int i = 1; i <= n; i++) G[i].clear();
        cnt.clear();
        for (int i = 1, u, v; i < n; i++) {
            cin >> u >> v;
            G[u].push_back(v), G[v].push_back(u);
        }
        cin >> m;
        for (int i = 1; i <= m; i++) cin >> w[i];
        for (int i = m + 1; i <= n - 1; i++) w[i] = 1;
        sort(w.begin() + 1, w.begin() + max(n, m + 1)), reverse(w.begin() + 1, w.begin() + max(m + 1, n));
        dfs(1, 0);
        sort(cnt.begin(), cnt.end()), reverse(cnt.begin(), cnt.end());
        int ans = 0;
        if (n - 1 >= m) {
            for (int i = 0; i < n - 1; i++)
                (ans += cnt[i] % MOD * w[i + 1] % MOD) %= MOD;
        }
        else {
            for (int i = 1; i < n - 1; i++) {
                (ans += cnt[i] % MOD * w[m - n + 2 + i] % MOD) %= MOD;
            }
            int tmp = 1;
            for (int i = 1; i <= m - n + 2; i++)
                (tmp *= w[i]) %= MOD;
            (ans += tmp * cnt[0] % MOD) %= MOD;
        }
        cout << ans << "\n";
    }
    return 0;
}
```

# E Divide Square
## Solution
жңүдёӨз§Қжғ…еҶөдјҡдҪҝзӯ”жЎҲеҠ дёҖпјҡиҙҜз©ҝж•ҙдёӘзҹ©еҪўзҡ„зӣҙзәҝпјҢжҲ–дёӨжқЎзӣҙзәҝзӣёдәӨгҖӮ

жұӮзӣҙзәҝдәӨзӮ№пјҡеҸҜд»Ҙе°Ҷж°ҙе№ізәҝж®өжҢүе·Ұз«ҜзӮ№жҺ’еәҸпјҢе·Ұз«ҜзӮ№зӣёеҗҢжҢүеҸіз«ҜзӮ№жҺ’еәҸгҖӮе№¶е°Ҷз«–зӣҙзәҝж®өзҡ„ $x$ еқҗж Үд№ҹеҠ е…ҘпјҢиӢҘ $x$ еқҗж ҮдёҺж°ҙе№ізәҝж®өе·Ұз«ҜзӮ№зӣёеҗҢпјҢдјҳе…ҲиҖғиҷ‘ж°ҙе№ізәҝж®өгҖӮ

з»ҹи®ЎдәӨзӮ№ж•°пјҡеҸҜд»ҘйҖҡиҝҮж ‘зҠ¶ж•°з»„еҜ№ $y$ иҝӣиЎҢеҢәй—ҙ $[y_l, y_r]$ жҹҘиҜўпјҢеҠ е…ҘжҲ–еҲ йҷӨж°ҙе№ізәҝеҲҷеҜ№ж°ҙе№ізәҝзҡ„ $y$ еҚ•зӮ№дҝ®ж”№гҖӮ

еҠ е…ҘжҲ–еҲ йҷӨж°ҙе№ізәҝеҸҜйҖҡиҝҮйҳҹеҲ—е®һзҺ°пјҢеҰӮжһңеҸіз«ҜзӮ№е°ҸдәҺеҪ“еүҚз«–зӣҙзәҝзҡ„ $x$пјҢеҲҷеҮәйҳҹпјҢе№¶йҖҡиҝҮж ‘зҠ¶ж•°з»„еҜ№ $y$ иҝӣиЎҢеҚ•зӮ№дҝ®ж”№гҖӮ

жіЁж„Ҹпјҡж ‘зҠ¶ж•°з»„дёҚжҳҜ 0 based зҡ„пјҢйңҖе°Ҷеқҗж ҮйғҪеҠ  1гҖӮ
## Code
```cpp Divide Square
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 1e6 + 6, MOD = 1e9 + 7, MAXZ = 1e5 + 5;

int n, m, tmp[MAXZ], y[MAXZ], l1[MAXZ], r1[MAXZ], x[MAXZ], l2[MAXZ], r2[MAXZ];
LL ans(1);

struct BIT {
    int lowbit(int x) { return x & (-x); }

    void add(int x, LL val) {
        while (x < MAXN) c[x] += val, x += lowbit(x);
    }

    LL query(int x, int res = 0) {
        while (x) res += c[x], x -= lowbit(x);
        return res;
    }
    array<LL, MAXN> c;
} bit[3];
/*range [l, r] add val*/
inline void add(int l, int r, LL val) {
    bit[1].add(l, val), bit[1].add(r + 1, -val);
    bit[2].add(l, val * l), bit[2].add(r + 1, -val * (r + 1));
}
/*range [l, r] sum query*/
inline LL query(int l, int r, LL res = 0) {
    res = bit[0].query(r) + bit[1].query(r) * (r + 1) - bit[2].query(r);
    res -= bit[0].query(l - 1) + bit[1].query(l - 1) * l - bit[2].query(l - 1);
    return res;
}

struct Node {
    Node() = default;
    Node(int _type, int _l, int _r, int _x) :
        type(_type), l(_l), r(_r), x(_x) {}

    friend inline bool operator<(const Node& lhs, const Node& rhs) {
        if (lhs.l == rhs.l) {
            if (lhs.type == rhs.type) return lhs.r < rhs.r;
            return lhs.type < rhs.type; 
        }
        return lhs.l < rhs.l;
    }

    int type, l, r, x; //type == 0 horizontal ==1 vertical
};
vector<Node> vec;

int main() {
    ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++) {
        cin >> y[i] >> l1[i] >> r1[i];
        y[i]++, l1[i]++, r1[i]++;
        if (l1[i] == 1 && r1[i] == 1000001) ans++;
        vec.emplace_back(0, l1[i], r1[i], y[i]);
    }
    for (int i = 1; i <= m; i++) {
        cin >> x[i] >> l2[i] >> r2[i];
        x[i]++, l2[i]++, r2[i]++;
        if (l2[i] == 1 && r2[i] == 1000001) ans++;
        vec.emplace_back(1, x[i], l2[i], r2[i]);
    }
    sort(vec.begin(), vec.end());
    queue<int> q;
    for (int i = 0; i < vec.size(); i++) {
        if (vec[i].type == 0) {
            add(vec[i].x, vec[i].x, 1);
            q.push(i);
        } else {
            while (!q.empty() && vec[q.front()].r < vec[i].l) {
                add(vec[q.front()].x, vec[q.front()].x, -1);
                q.pop();
            }
            ans += query(vec[i].r, vec[i].x);
        }
    }
    cout << ans << "\n";
    return 0;
}
```

# F Reverse and Swap
## Solution
иҖғиҷ‘зәҝж®өж ‘з»ҙжҠӨпјҢи®ҫзәҝж®өж ‘д»ҺдёҠеҫҖдёӢжҳҜз¬¬ 0 еұӮпјҢз¬¬ 1 еұӮпјҢз¬¬ 2 еұӮпјҢ...пјҢз¬¬ n еұӮгҖӮйӮЈд№Ҳ $swap(k)$ ж“ҚдҪңе°ұжҳҜз»ҷз¬¬ $n - k + 1$ еұӮжүҖжңүиҠӮзӮ№жү“дёҠдәӨжҚўж Үи®°пјҢ$reverse(k)$ ж“ҚдҪңе°ұжҳҜз»ҷз¬¬ $n - k$ еҲ° $n$ еұӮзҡ„жүҖжңүиҠӮзӮ№жү“дёҠж Үи®°гҖӮ

дёҖз§ҚеҒҡжі•жҳҜз”Ё $tag[]$ и®°еҪ•жҜҸдёҖеұӮзҡ„дәӨжҚўж Үи®°пјҢз„¶еҗҺжҜҸдёӘиҠӮзӮ№д№ҹжңүдёҖдёӘ $tag$ ж Үи®°пјҢеҰӮжһңиҠӮзӮ№зҡ„ $tag$ е’ҢиҠӮзӮ№еҜ№еә”еұӮзҡ„ $tag[depth]$ дёҚеҗҢпјҢеҲҷдәӨжҚўе…¶е·ҰеҸіе„ҝеӯҗпјҢе№¶дҝ®ж”№ tagгҖӮ
жіЁпјҡеҪ“еҢәй—ҙзҝ»иҪ¬зҡ„жҳҜдёҖдёӘж•ҙеҢәй—ҙж—¶жүҚиғҪз”Ёзәҝж®өж ‘дәӨжҚўе·ҰеҸіе„ҝеӯҗпјҢе…¶ж¬Ўз»“жһ„дҪ“дёӯдёҚе»әи®®дҝқеӯҳиҠӮзӮ№ $l, r$ дҝЎжҒҜпјҲдёҚж–№дҫҝдәӨжҚўе·ҰеҸіе„ҝеӯҗпјҢеӣ дёәе·ҰеҸіе„ҝеӯҗзҡ„ $l, r$ йғҪиҰҒеҸҳпјүпјҢеҸҜд»ҘзӣҙжҺҘдҪңдёәеҮҪж•°еҸӮж•°гҖӮ

еҸҰдёҖз§ҚеҒҡжі•жҳҜж №жҚ®еұӮж Үи®°зЎ®е®ҡеҫҖе·ҰдәҢеӯҗиҝҳжҳҜеҸіе„ҝеӯҗиө°пјҢеҗҢж—¶и®Ўз®—еҸҳеҢ–еҗҺзҡ„еҢәй—ҙгҖӮ

## Code
```cpp Reverse and Swap method1
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 3e5 + 5, MOD = 1e9 + 7;

template<typename T>
inline void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

int bit, n, q, a[MAXN], tag[19], tot;

struct SegTree {
    SegTree* lson, *rson;
    int tag, depth;
    long long sum;
} *root, tree[MAXN << 1];

inline void update(SegTree* root) {
    root->sum = root->lson->sum + root->rson->sum;
}

inline void build(SegTree*& root, int L, int R, int depth) {
    root = &tree[tot++], root->depth = depth;
    if (L == R) { root->sum = a[L]; return; }
    int mid = (L + R) >> 1;
    build(root->lson, L, mid, depth + 1);
    build(root->rson, mid + 1, R, depth + 1);
    update(root);
}

inline void checkTag(SegTree* root) {
    if (root->tag != tag[root->depth]) {
        root->tag = tag[root->depth];
        swap(root->lson, root->rson);
    }
}

inline void modify(SegTree* root, int pos, int val, int L = 1, int R = n) {
    if (L == pos && R == pos) {
        root->sum = val;
        return;
    }
    checkTag(root);
    int mid = (L + R) >> 1;
    if (pos <= mid) modify(root->lson, pos, val, L, mid);
    else modify(root->rson, pos, val, mid + 1, R);
    update(root);
}

inline long long query(SegTree* root, int l, int r, int L = 1, int R = n) {
    if (l <= L && R <= r) return root->sum;
    checkTag(root);
    int mid = (L + R) >> 1;
    long long res = 0;
    if (l <= mid) res += query(root->lson, l, r, L, mid);
    if (r > mid) res += query(root->rson, l, r, mid + 1, R);
    update(root);
    return res;
}

int main() {
    read(bit), read(q), n = pow(2, bit);
    for (int i = 1; i <= n; i++) read(a[i]);
    build(root, 1, n, 0);
    while (q--) {
        int opt, x, k, l, r;
        read(opt);
        if (opt == 1) read(x), read(k), modify(root, x, k);
        else if (opt == 2) {
            read(k);
            for (int i = bit - k; i <= bit; i++) tag[i] ^= 1;
        } else if (opt == 3) read(k), tag[bit - k - 1] ^= 1;
        else read(l), read(r), printf("%lld\n", query(root, l, r));
    }
    return 0;
}
```

```cpp Reverse and Swap method2
#include <bits/stdc++.h>

using namespace std;
typedef long long LL;

const int MAXN = 3E5;
int n, q, a[MAXN], x, k, l, r, tag[19];

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Node {
    Node* son[2];
    int l, r;
    LL sum;
} * root;

void update(Node* cur) { cur->sum = cur->son[0]->sum + cur->son[1]->sum; }

void build(Node*& cur, int l, int r) {
    cur = new Node;
    cur->l = l, cur->r = r;
    if (l == r) {
        cur->sum = a[l];
        return;
    }
    int mid = l + r >> 1;
    build(cur->son[0], l, mid);
    build(cur->son[1], mid + 1, r);
    update(cur);
}

void replace(Node* cur, int x, int val, int layer) {
    if (cur->l == x && cur->r == x) {
        cur->sum = val;
        return;
    }
    int mid = cur->l + cur->r >> 1;
    int st = tag[layer];
    int len = st ? (cur->r - cur->l + 1) >> 1 : 0;
    if (x <= mid)
        replace(cur->son[st], x + len, val, layer + 1);
    else
        replace(cur->son[!st], x - len, val, layer + 1);
    update(cur);
}

LL sum(Node* cur, int l, int r, int layer) {
    if (cur->l == l && cur->r == r) return cur->sum;
    int mid = cur->l + cur->r >> 1;
    int st = tag[layer];
    int len = st ? (cur->r - cur->l + 1) >> 1 : 0;

    if (r <= mid)
        return sum(cur->son[st], l + len, r + len, layer + 1);
    else if (l > mid)
        return sum(cur->son[!st], l - len, r - len, layer + 1);
    else
        return sum(cur->son[st], l + len, mid + len, layer + 1) +
               sum(cur->son[!st], mid + 1 - len, r - len, layer + 1);
}
int main() {
    read(n), read(q);
    for (int i = 1; i <= 1 << n; i++) read(a[i]);
    build(root, 1, 1 << n);
    while (q--) {
        int type;
        read(type);
        switch (type) {
            case 1:
                read(x), read(k);
                replace(root, x, k, 0);
                break;
            case 2:
                read(k);
                for (int i = n - k; i <= n; i++) tag[i] ^= 1;
                break;
            case 3:
                read(k);
                tag[n - k - 1] ^= 1;
                break;
            case 4:
                read(l), read(r);
                printf("%lld\n", sum(root, l, r, 0));
                break;
            default:
                break;
        }
    }
    return 0;
}
```

