## Solution
йҰ–е…ҲпјҢз”ұдәҺж•°еҲ—дёӯжҜҸдёӘж•°иҮіе°‘дёә 3пјҢеӣ жӯӨж•°еҲ—й•ҝеәҰжңҖеӨ§дёә $L=\frac{S}{3}$гҖӮи®ҫ $dp[i][j]$ иЎЁзӨәжһ„жҲҗй•ҝеәҰдёә $i$пјҢе’Ңдёә $j$ зҡ„ж•°еҲ—ж–№жЎҲж•°пјҢйӮЈд№ҲжңҖеҗҺзӯ”жЎҲдёә $\sum\limits_{i=1}^{L}dp[i][S]$гҖӮжҳ“еҫ—зҠ¶жҖҒиҪ¬з§»ж–№зЁӢдёә $dp[i][j]=\sum\limits_{k=(i-1)*3}^{j-3}dp[i-1][k],jвҲҲ[i*3,S]$гҖӮеҰӮжһңзӣҙжҺҘиҪ¬з§»ж—¶й—ҙеӨҚжқӮеәҰдёә$O(S^2L)$пјҢдҪҶ $\sum\limits_{k=(i-1)*3}^{j-3}dp[i-1][k]$ еҸҜд»Ҙз”ЁеҲ©з”ЁеүҚзјҖе’Ң $O(1)$ жұӮеҫ—пјҢеҗҢж—¶ $dp[i][j]$ з¬¬дёҖз»ҙеҸҜд»Ҙж»ҡжҺүпјҢеӣ жӯӨеӨҚжқӮеәҰеҸҜйҷҚиҮі $O(SL)$гҖӮ

## Code
```cpp Redistribution
#include <bits/stdc++.h>

using namespace std;
const int MOD = 1E9 + 7;
int dp[2005], sum[2005];
int len, s, ans;

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

int main() {
    cin >> s;
    len = s / 3;
    dp[0] = 1;
    for (int i = 0; i <= s; i++) sum[i] = 1;
    for (int i = 1; i <= len; i++) {
        for (int j = i * 3; j <= s; j++)
            dp[j] = (sum[j - 3] - (i > 1 ? sum[(i - 1) * 3 - 1] : 0)) % MOD;
        ans += dp[s], ans %= MOD;
        for (int j = 0; j <= s; j++) sum[j] = 0;
        for (int j = i * 3 - 1; j <= s; j++)
            sum[j] = (sum[j - 1] + dp[j]) % MOD;
    }
    cout << (ans + MOD) % MOD;
    return 0;
}
```

