   - з»јдёҠеҸҜзҹҘпјҢжҜҸдёӘеқ—еӨ§е°ҸеңЁ $[B,3B]$ д№Ӣй—ҙпјҢж»Ўи¶ійўҳзӣ®иҰҒжұӮгҖӮ


## Code
```cpp зҺӢе®ӨиҒ”йӮҰ
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 1e3 + 5;

int n, b, ans, u, v;
int p[MAXN], pro[MAXN], belong[MAXN];

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct edge {
    int to, nxt;
} e[MAXN << 1];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

stack<int> s;
void dfs(int now, int fa) {
    int tmp = s.size();
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != fa) {
            dfs(to, now);
            if (s.size() - tmp >= b) {
                pro[++ans] = now;
                while (s.size() > tmp) {
                    int cur = s.top();
                    s.pop();
                    belong[cur] = ans;
                }
            }
        }
    }
    s.push(now);
}

int main() {
    read(n), read(b);
    fill(p, p + n + 1, -1);
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v);
        addEdge(u, v), addEdge(v, u);
    }
    dfs(1, 1);
    if (!ans) pro[++ans] = 1;
    while (!s.empty()) {
        int tmp = s.top();
