    if (!hson[now]) return;
    dfs2(hson[now], tp);
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != f[now] && to != hson[now]) dfs2(to, to);
    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[C[now]];
        tot += 1ll * W[cntC[C[now]]] * V[C[now]];
    } else {
        tot -= 1ll * W[cntC[C[now]]] * V[C[now]];
        --cntC[C[now]];
    }
    vis[now] ^= 1;
}

void change(Replace &rep) {
    if (vis[rep.id]) {
        modify(rep.id);
        swap(rep.type, C[rep.id]);
        modify(rep.id);
    } else
        swap(rep.type, C[rep.id]);
}

int main() {
    read(n), read(m), read(Q);
    fill(p + 1, p + n + 1, -1);
    for (int i = 1; i <= m; i++) read(V[i]);
    for (int i = 1; i <= n; i++) read(W[i]);
    int x, y, t;
    for (int i = 1; i <= n - 1; i++) {
        read(x), read(y);
        addEdge(x, y), addEdge(y, x);
    }
    for (int i = 1; i <= n; i++) read(C[i]);
    B = pow(n, 2.0 / 3);  //дёҚиҰҒеҝҳдәҶ.0!
    dfs(1, 1), dfs2(1, 1);
    for (int i = 1; i <= Q; i++) {
        read(type);
        if (type == 1) {
            cntQ++;
            read(x), read(y);
            if (in[x] > in[y]) swap(x, y);
            q[cntQ].lca = lca(x, y);
            if (q[cntQ].lca == x) {
                q[cntQ].l = in[x];
                q[cntQ].r = in[y];
                q[cntQ].lca = 0;
            } else {
                q[cntQ].l = out[x];
                q[cntQ].r = in[y];
            }
            q[cntQ].id = cntQ;
            q[cntQ].t = cntR;
        } else {
            cntR++;
            read(x), read(y);
            r[cntR].id = x, r[cntR].type = y;
        }
    }
    for (int i = 1; i <= 2 * n; i++) belong[i] = (i - 1) / B + 1;
    sort(q + 1, q + cntQ + 1);
    x = 1, y = 0, t = 0;
    for (int i = 1; i <= cntQ; i++) {
        while (x < q[i].l) modify(from[x++]);
        while (x > q[i].l) modify(from[--x]);
        while (y > q[i].r) modify(from[y--]);
        while (y < q[i].r) modify(from[++y]);
        while (t < q[i].t) change(r[++t]);
        while (t > q[i].t) change(r[t--]);
        if (q[i].lca) modify(q[i].lca);
        ans[q[i].id] = tot;
        if (q[i].lca) modify(q[i].lca);
    }
    for (int i = 1; i <= cntQ; i++) printf("%lld\n", ans[i]);
    return 0;
}
