# D Moving Piece
## Description
жңү $n$ дёӘж јеӯҗжҺ’жҲҗдёҖеҲ—гҖӮз»ҷе®ҡ $1, 2, ..., n$ зҡ„жҺ’еҲ— $P_1, P_2, ..., P_n$пјҢд»ҘеҸҠж•°з»„$C_1, C_2, ..., C_n$пјҢиЎЁзӨәж јеӯҗ $i$ иғҪиҫҫеҲ° $P_i$пјҢиҺ·еҫ—зҡ„еҲҶж•°дёә $C_{P_i}$гҖӮд»Һд»»ж„ҸдёҖзӮ№еҮәеҸ‘иө° $K$ жӯҘпјҢжұӮиғҪиҺ·еҫ—зҡ„жңҖеӨ§еҲҶж•°гҖӮ
## Solution
$O(N^2)$пјҡ
д»ҘжҜҸдёӘзӮ№дҪңдёәиө·зӮ№ $st$пјҢжұӮеҮәи·Ҝеҫ„пјҢи®°еҪ•зҺҜзҡ„иө·зӮ№ $cyBeg$ е’Ңз»ҲзӮ№ $cyEnd$ (з»ҲзӮ№жҢҮеҶҚиө°дёҖжӯҘиғҪеӣһеҲ°зҺҜзҡ„иө·зӮ№зҡ„иҠӮзӮ№)гҖӮ
жұӮиө·зӮ№ $st$ еҲ° $cyEnd$ зҡ„ $C$ еүҚзјҖе’ҢпјҢд»ҘеҸҠеүҚзјҖе’Ңдёӯзҡ„жңҖеӨ§еҖјгҖӮе№¶жұӮеҮәзҺҜдёҠзҡ„ $C$ жҖ»е’ҢпјҢд»ҘеҸҠд»Һ $cyBeg$ ејҖе§Ӣзҡ„еүҚзјҖе’ҢеҸҠе…¶жңҖеӨ§еҖјгҖӮ
еҲӨж–ӯиғҪеҗҰиө°е®Ңж•ҙдёӘзҺҜпјҢиӢҘзҺҜдёәжӯЈзҺҜпјҢеҲҷеҸҜд»ҘдёҖзӣҙиө°еҲ°иӢҘе№ІеңҲзӣҙеҲ°дёҚиғҪеҶҚиө°е®Ңж•ҙдёӘзҺҜпјҢжҲ–иҖ…е°‘иө°дёҖеңҲеҶҚеҠ дёҠеүҚзјҖе’ҢжңҖеӨ§еҖј (иҷҪз„¶зҺҜжҳҜжӯЈзҺҜпјҢдҪҶеҸҜиғҪзҺҜдёҠеӯҳеңЁдёҖдёӘжһҒе°ҸеҖјпјҢе°‘иө°дёҖеңҲеҸҚиҖҢиғҪдҪҝзӯ”жЎҲжӣҙеӨ§)гҖӮ
$O(nlogn)$пјҡ
йҖҡиҝҮ $P$ жұӮеҮәжҜҸдёӘзӮ№зҡ„е…ҘеәҰпјҢд»Һе…ҘеәҰдёә 0 зҡ„зӮ№ејҖе§Ӣ $dfs$ е»әеӣҫ (иӢҘжІЎжңүзӮ№е…ҘеәҰдёә 0пјҢеҲҷжүҖжңүзӮ№еңЁзҺҜдёҠпјҢд»»ж„ҸжүҫдёҖдёӘзӮ№дёәиө·зӮ№еҚіеҸҜ)пјҢе№¶и®°еҪ•жҜҸдёӘзӮ№жҳҜеҗҰеңЁзҺҜдёҠгҖӮеҲҶиө·зӮ№еңЁзҺҜдёҠе’ҢдёҚеңЁзҺҜдёҠпјҢиө·зӮ№еңЁзҺҜдёҠйңҖеҲҶж®өи®Ёи®әпјҢз„¶еҗҺеҸҜз”Ёж”ҜжҢҒеҢәй—ҙдҝ®ж”№жҹҘиҜўзҡ„ж•°жҚ®з»“жһ„з»ҙжҠӨеҢәй—ҙжңҖеӨ§еҖјгҖӮд№ҹжңүmultisetеҒҡжі• [link](https://codeforces.ml/blog/entry/81458?#comment-681192)гҖӮ
## Code
```cpp Moving Piece O(N^2)
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 5e3 + 5;

int n, k, ans(-1e18), cyBeg, cyEnd;
array<int, MAXN> to, c, vis, pre, preMax;
vector<int> node;

inline void dfs(int cur) {
    vis[cur] = true;
    node.push_back(cur);
    if (vis[to[cur]]) {
        cyEnd = node.size() - 1; //зҺҜз»ҲзӮ№
        for (int i = 0; i < node.size(); i++)
            if (node[i] == to[cur]) {
                cyBeg = i; //зҺҜиө·зӮ№
                break;
            }
    }
    else dfs(to[cur]);
}

inline void search(int st) {
    node.clear();
    fill(vis.begin(), vis.end(), 0);
    fill(pre.begin(), pre.end(), 0);
    fill(preMax.begin(), preMax.end(), -1e18);
    cyBeg = cyEnd = -1;
    dfs(st);
    for (int i = 1; i < node.size(); i++)
        pre[i] = pre[i - 1] + c[node[i]], preMax[i] = max(preMax[i - 1], pre[i]);
    ans = max(ans, preMax[min(k, (int)node.size() - 1)]);
    if (k <= cyEnd || cyBeg == - 1 || cyEnd == -1) return;
    if (cyBeg == 0) { //дёҖејҖе§Ӣе°ұжңүзҺҜ
        int valC = pre[cyEnd] + c[node[cyBeg]];
        if (valC < 0) return;
        int tim = k / node.size(), res = k % node.size();
        ans = max(ans, tim * valC + max(0LL, preMax[res]));
        ans = max(ans, (tim - 1) * valC + max(0LL, preMax[cyEnd]));
        return;
    }
    int tmp = pre[cyBeg - 1];
    fill(pre.begin(), pre.end(), 0);
    fill(preMax.begin(), preMax.end(), -1e18);
    int valC = 0, cSize = cyEnd - cyBeg + 1, tim, res;
    for (int i = cyBeg; i <= cyEnd; i++) { //зҺҜдёҠеүҚзјҖе’Ң
        valC += c[node[i]];
        pre[i] = pre[i - 1] + c[node[i]];
        preMax[i] = max(preMax[i - 1], pre[i]);
    }
    if (valC < 0) return;
    k -= cyBeg - 1, tim = k / cSize, res = k % cSize;
    ans = max(ans, tmp + valC * tim + max(0LL, preMax[cyBeg + res - 1]));
    ans = max(ans, tmp + valC * (tim - 1) + max(0LL, preMax[cyEnd]));
}

signed main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 1; i <= n; i++) cin >> to[i];
    for (int i = 1; i <= n; i++) cin >> c[i];
    for (int i = 1; i <= n; i++) search(i);
    cout << ans << endl;
    return 0;
}
```

# E Picking Goods
## Description
[йўҳзӣ®й“ҫжҺҘ](https://atcoder.jp/contests/abc175/tasks/abc175_e)
## Solution
и®ҫ $dp[i][j][k]$ иЎЁзӨәеҪ“еүҚдёәз¬¬ $i$ иЎҢпјҢз¬¬$j$ еҲ—пјҢз¬¬ $i$ иЎҢйҖүдәҶ $k$ дёӘж•°зҡ„жңҖеӨ§еҖјгҖӮзҠ¶жҖҒиҪ¬з§»жҳҺжҳҫгҖӮ
## Code
```cpp Picking Goods
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 3e3 + 3;

LL R, C, K;
LL dp[MAXN][MAXN][5], mp[MAXN][MAXN];

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> R >> C >> K;
    for (int i = 1; i <= K; i++) {
        int r, c, v;
        cin >> r >> c >> v;
        mp[r][c] = v;
    }
    for (int i = 1; i <= R; i++)
        for (int j = 1; j <= C; j++) {
            for (int cnti = 0; cnti < 4; cnti++) {
                    //дёҚйҖү
                    dp[i][j][cnti] = max(dp[i][j][cnti], dp[i][j - 1][cnti]);
                    for (int cntj = 0; cntj < 4; cntj++)
                        dp[i][j][cnti] = max(dp[i][j][cnti], dp[i - 1][j][cntj]);
                    //йҖү
                    dp[i][j][cnti + 1] = max(dp[i][j][cnti + 1], dp[i][j - 1][cnti] + mp[i][j]);
                    for (int cntj = 0; cntj < 4; cntj++)
                        dp[i][j][cnti + 1] = max(dp[i][j][cnti + 1], dp[i - 1][j][cntj] + mp[i][j]);
            }
        }
    LL ans = 0;
    for (int i = 0; i < 4; i++) ans = max(ans, dp[R][C][i]);
    cout << ans << endl;
    return 0;
}

```

# F Making Palindrome
## Description
жұӮе°ҶдёҖдәӣеӯ—з¬ҰдёІ $S_1, S_2, ..., S_n$ жӢјжҺҘдёәеӣһж–ҮдёІзҡ„жңҖе°Ҹд»Јд»· ( $S_i$ еҸҜеӨҡж¬Ўиў«йҖүпјҢжҜҸйҖүдёҖж¬Ўд»Јд»·дёә $C_i$ )гҖӮдёҚиғҪжӢјжҲҗеӣһж–ҮдёІеҲҷиҫ“еҮә -1гҖӮ
## Solution
е°Ҷзӣ®ж Үеӣһж–ҮдёІеҲҶдёәе·ҰеҸідёӨйғЁеҲҶпјҢи®ҫе·Ұиҫ№зҡ„еӯ—з¬ҰдёІдёә $l = s_{l_1}, s_{l_2}, ..., s_{l_j}$пјҢеҸіиҫ№зҡ„еӯ—з¬ҰдёІдёә $r = s_{r_k}, ..., s_{r_2}, s_{r_1}$гҖӮиҰҒдҪҝ $l, r$ жһ„жҲҗеӣһж–ҮдёІпјҢеҲҷйңҖиҰҒ $s_{l_1}$ зҡ„еүҚзјҖдёҺ $s_{r_1}$ еӣһж–ҮпјҢжҲ–иҖ… $s_{l_1}$ дёҺ $s_{r_1}$ зҡ„еҗҺзјҖеӣһж–ҮпјҢе№¶дё”е°Ҷеӣһж–ҮйғЁеҲҶж¶ҲеҺ»еҗҺзҡ„ $l, r$ д№ҹж»Ўи¶ідёҠиҝ°жқЎд»¶ (жӯӨж—¶ $s_{l_i}$ е’Ң $s_{r_i}$ еҸҜиғҪеҸӘжҳҜ $S$ зҡ„дёҖйғЁеҲҶ)гҖӮ
дәҺжҳҜеҸҜд»ҘиҖғиҷ‘и®ҫеҪ“еүҚзҠ¶жҖҒдёә $state = \{ string_l, string_r \}$пјҢеҗ‘еӯ—з¬ҰдёІй•ҝеәҰе°Ҹзҡ„дёҖиҫ№еҠ е…Ҙж–°еӯ—з¬ҰдёІиҝӣиЎҢжӢјжҺҘпјҢе№¶ж¶ҲеҺ»еӣһж–ҮйғЁеҲҶпјҢзӣҙеҲ° $l, r$ йғҪдёәз©әпјҢжҲ–иҖ…дёҖдёӘжҳҜеӣһж–ҮдёІпјҢдёҖдёӘжҳҜз©әдёІдёәжӯўпјҢз„¶еҗҺи·‘ $dijkstra$ еҚіеҸҜгҖӮ

## Code
```cpp Making Palindrome
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 55;

struct Node {
    Node() = default;
    Node(LL _c, string& _l, string& _r) : c(_c), l(_l), r(_r) {}
    LL c;
    string l, r;
    friend inline bool operator<(const Node& lhs, const Node& rhs) {
        return lhs.c > rhs.c;
    }
};
LL n, cost[MAXN];
string s[MAXN], emps("");

inline bool isPalindrome(const string& tmp) {
    for (int i = 0; i < tmp.size() /2 + 1; i++)
        if (tmp[i] != tmp[tmp.size() - 1 - i]) return false;
    return true;
}
/*еҲ йҷӨl, rе…¬е…ұйғЁеҲҶ @return l, rз¬¬дёҖдёӘдёҚеҗҢзҡ„дҪҚзҪ®*/
inline int check(string& l, string& r) {
    int i = 0;
    for (; i < min(l.size(), r.size()); i++)
        if (l[i] != r[r.size() - 1 - i]) break;
    l = l.substr(i), r = r.substr(0, r.size() - i);
    return i;
}

priority_queue<Node, vector<Node>> q;
map<string, map<string, bool>> vis;
inline void dijkstra() {
    while (!q.empty()) {
        auto cur = q.top();
        q.pop();
        if (vis[cur.l][cur.r]) continue; //l, r и®ҝй—®иҝҮ
        if (isPalindrome(cur.l) && cur.r.empty()) { //е·Ұиҫ№жҳҜеӣһж–Ү
            cout << cur.c << endl;
            return;
        } else if (isPalindrome(cur.r) && cur.l.empty()) { //еҸіиҫ№жҳҜеӣһж–Ү
            cout << cur.c << endl;
            return;
        } else if (cur.l.empty() && cur.r.empty()) { //йғҪжҳҜз©әеӯ—з¬ҰдёІ
            cout << cur.c << endl;
            return;
        } else {
            for (int i = 1; i <= n; i++) {
                Node tmp(cur.c, cur.l, cur.r);
                if (tmp.l.size() >= tmp.r.size()) { //е·Ұиҫ№жҜ”еҸіиҫ№й•ҝпјҢеҠ еҲ°еҸіиҫ№
                    tmp.r = s[i] + tmp.r, tmp.c += cost[i];
                    int id = check(tmp.l, tmp.r);
                    if (id && (tmp.l.empty() || tmp.r.empty())) q.push(tmp);
                } else { //е·Ұиҫ№жҜ”еҸіиҫ№зҹӯпјҢеҠ еҲ°е·Ұиҫ№
                    tmp.l = tmp.l + s[i], tmp.c += cost[i];
                    int id = check(tmp.l, tmp.r);
                    if (id && (tmp.l.empty() || tmp.r.empty())) q.push(tmp);
                }
            }
        }
        vis[cur.l][cur.r] = true;
    }
    cout << -1 << endl;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> s[i] >> cost[i];
        q.push(Node(cost[i], s[i], emps));
        q.push(Node(cost[i], emps, s[i]));
    }
    dijkstra();
    return 0;
}
```

