# Solution
жңҖеӨ§еӣӣиҫ№еҪўзҡ„йЎ¶зӮ№дёҖе®ҡеңЁеҮёеҢ…дёҠгҖӮ
еҪ“еҮёеҢ…йЎ¶зӮ№ж•°еӨ§дәҺ 3 ж—¶пјҢе…ҲйҖүеҸ–дёҖжқЎеҜ№и§’зәҝпјҢеҲҷе…¶е®ғдёӨдёӘзӮ№еҲ°еҜ№и§’зәҝзҡ„и·қзҰ»е…·жңүеҚ•еі°жҖ§пјҢеҘ—ж—ӢиҪ¬еҚЎеЈіеҚіеҸҜжұӮеҮәжңҖеӨ§еӣӣиҫ№еҪўйқўз§ҜгҖӮ
еҪ“еҮёеҢ…йЎ¶зӮ№ж•°зӯүдәҺ 3 ж—¶пјҢжңҖеӨ§еӣӣиҫ№еҪўйқўз§ҜдёәеҮёеҢ…йқўз§ҜеҮҸеҺ»еҶ…йғЁзӮ№дёҺеҮёеҢ…дёҠзҡ„зӮ№жһ„жҲҗзҡ„жңҖе°Ҹзҡ„дёүи§’еҪўйқўз§ҜгҖӮ
еҪ“еҮёеҢ…йЎ¶зӮ№ж•°зӯүдәҺ 2 ж—¶пјҢйқўз§Ҝдёә 0гҖӮ
# Code
```cpp жңҖеӨ§еҶ…жҺҘеӣӣиҫ№еҪў
#include <bits/stdc++.h>
#define PI acos(-1)

using namespace std;

constexpr int MAXN = 3e3 + 3;

struct Vec2 {
    Vec2() = default;
    Vec2(double _x, double _y) : x(_x), y(_y) {}

    friend inline bool operator<(const Vec2& a, const Vec2& b) {
        return fabs(a.x - b.x) < 1e-8 ? a.y < b.y : a.x < b.x;
    }

    friend inline Vec2 operator-(const Vec2& a, const Vec2& b) {
        return Vec2(a.x - b.x, a.y - b.y);
    }

    friend inline double operator*(const Vec2& a, const Vec2& b) {
        return a.x * b.y - a.y * b.x;  //Г—
    }
    double x = 0, y = 0;
} vec[MAXN], cov[MAXN];
int n, top, Up;

inline void convex() {
    top = 0, Up = 0;
    sort(vec + 1, vec + n + 1);
    for (int i = 1; i <= n; i++) {  //дёӢеҮёеЈі
        while (top > 1 && (cov[top] - cov[top - 1]) * (vec[i] - cov[top]) < 1e-8)
            cov[top--] = Vec2(0, 0);
        cov[++top] = vec[i];
    }
    Up = top;                          //дёҠеҮёеЈіиө·зӮ№
    for (int i = n - 1; i > 0; i--) {  //дёҠеҮёеЈі
        while (top > Up && (cov[top] - cov[top - 1]) * (vec[i] - cov[top]) < 1e-8)
            cov[top--] = Vec2(0, 0);
        cov[++top] = vec[i];
    }
}

inline double calc(double res = .0) {
    if (top <= 3) return 0.0; //еҮёеҢ…еҸӘжңү2дёӘзӮ№
    if (top == 4) ; //еҮёеҢ…еҸӘжңү3дёӘзӮ№
    for (int i = 1; i < top; i++) {
        int up = (i + 2) % (top - 1) == 0 ? (i + 2) : (i + 2) % (top - 1);
        int down = i;
        for (int j = i + 2; j < i + top - 2; j++) {
            auto s = cov[i], t = cov[j % (top - 1) == 0 ? j : j % (top - 1)];
            while (true) {
                auto s1 = fabs((t - cov[up]) * (s - cov[up]));
                auto s2 = fabs((t - cov[up + 1]) * (s - cov[up + 1]));
                if (s1 < s2 + 1e-8) up = up % (top - 1) + 1;
                else break;
            }
            while (true) {
                auto s1 = fabs((t - cov[down]) * (s - cov[down]));
                auto s2 = fabs((t - cov[down + 1]) * (s - cov[down + 1]));
                if (s1 < s2 + 1e-8) down = down % (top - 1) + 1;
                else break;
            }
            res = max(res, fabs((cov[up]- s) * (cov[up] - t)) +
                               fabs((cov[down] - s) * (cov[down] - t)));
        }
    }
    return res / 2;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> vec[i].x >> vec[i].y;
    convex();
    cout << setprecision(3) << fixed << calc() << endl;;
    return 0;
}
```

