## зҹ©йҳөж ‘
е®ҡд№үеӣҫж— еҗ‘еӣҫ $G$ зҡ„жӢүжҷ®жӢүж–Ҝзҹ©йҳө (Laplacian matrix) $L(G)$
$$
L_{ij} =
\begin{cases}
-m_{ij} & i \ne\ j, i дёҺ j д№Ӣй—ҙжңү m_{ij}жқЎиҫ№\\
deg(i) & i = j, deg(i) дёәзӮ№ i зҡ„еәҰ\\
\end{cases}
$$
еҲҷ $G$ зҡ„з”ҹжҲҗж ‘дёӘж•°зӯүдәҺ $detL_0$пјҢе…¶дёӯ $L_0$ жҳҜеҺ»жҺү $L$ зҡ„ з¬¬ $i$ иЎҢпјҢз¬¬ $i$ еҲ—еҫ—еҲ°зҡ„еӯҗзҹ©йҳө ($i$ д»»ж„Ҹ)гҖӮе…·дҪ“иҜҒжҳҺи§Ғ [еҸӮиҖғиө„ж–ҷ](https://zhuanlan.zhihu.com/p/108209378)гҖӮ
йӮЈд№Ҳе°ұеҸҜд»ҘеҢ–зҹ©йҳө $L_0$ дёәдёҠдёүи§’зҹ©йҳөпјҢеҚіеҸҜжұӮеҮә $detL_0$гҖӮ
### Code
```cpp template
inline void add(int u, int v) { //еҠ иҫ№
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

LL G[MAXN][MAXN];
inline LL Gauss(int tot) { //й«ҳж–Ҝж¶Ҳе…ғ
    LL ans = 1;
    for (int i = 1; i < tot; i++) {
        for (int j = i + 1; j < tot; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < tot; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}
```
