## HEOI2015 е°ҸZзҡ„жҲҝй—ҙ
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P4111)
### Solution
жЁЎжқҝйўҳпјҢдёҚиҝҮжіЁж„ҸдёҚиҰҒе»әйҮҚиҫ№гҖӮ
### Code
```cpp е°ҸZзҡ„жҲҝй—ҙ
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 2000;
constexpr int MOD = 1e9;

int n, m, tot, mp[MAXN][MAXN];

LL G[MAXN][MAXN];
inline LL Gauss() {
    LL ans = 1;
    for (int i = 1; i < tot; i++) {
        for (int j = i + 1; j < tot; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < tot; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) {
    if (u > v) return;
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++) {
            char ch;
            cin >> ch;
            if (ch == '.') mp[i][j] = ++tot;
        }
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++) {
            int u = mp[i][j], v;
            if (!u) continue;
            if (v = mp[i - 1][j]) add(u, v);
            if (v = mp[i + 1][j]) add(u, v);
            if (v = mp[i][j - 1]) add(u, v);
            if (v = mp[i][j + 1]) add(u, v);
        }
    cout << Gauss() << endl;
    return 0;
}
```

## B SHOI2016 й»‘жҡ—еүҚзҡ„е№»жғід№Ў
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P4336)
### Solution
зҹ©йҳөж ‘+е®№ж–Ҙ+зҠ¶жҖҒеҺӢзј©гҖӮ
д»Ө $P_i$ иЎЁзӨәдәӢд»¶: з¬¬ $i$ дёӘе…¬еҸёжІЎжңүеҸӮдёҺдҝ®е»әгҖӮз”ұе®№ж–ҘеҺҹзҗҶжңү $|\overline{P_1} \cap \overline{P_2} \cap ...\cap \overline{P_{n-k}}|= N-\sum\limits_{1<=i<={n-k}}|P_i|+\sum\limits_{1<=i<j<={n-k}}|P_i\cap P_j|$ $-\sum\limits_{1<=i<j<q<={n-k}}|P_i\cap P_j\cap P_q|+...+(-1)^{n-k}|P_1\cap P_2 \cap ...\cap P_{n-k}|$гҖӮеҺӢзј©е…¬еҸёзҡ„еҸӮдёҺзҠ¶жҖҒеҚіеҸҜгҖӮ
### Code
```cpp й»‘жҡ—еүҚзҡ„е№»жғід№Ў
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MOD = 1e9 + 7;

int n, m, tot;
vector<pair<int, int>> vec[20];

LL G[20][20];
inline LL Gauss() {
    LL ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) {
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 0, cnt; i < n - 1; i++) {
        cin >> cnt;
        for (int j = 1, u, v; j <= cnt; j++) {
            cin >> u >> v;
            vec[i].emplace_back(u, v);
        }
    }
    LL ans = 0;
    for (int st = 0; st < (1 << (n - 1)); st++) {
        int cnt = 0;
        memset(G, 0, sizeof(G));
        for (int i = 0; i < n - 1; i++)
            if (st & (1 << i)) {
                for (auto& e : vec[i])
                    add(e.first, e.second);
                cnt++;
            }
        if ((n - cnt - 1) & 1) ans = (ans - Gauss()) % MOD;
        else ans = (ans + Gauss()) % MOD;
    }
    cout << (ans + MOD) % MOD << endl;
    return 0;
}
```

## C SDOI2014 йҮҚе»ә
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P3317)
### Solution
жҲ‘д»¬е·ІзҹҘеҸҳе…ғзҹ©йҳөж ‘еҸҜд»ҘжұӮ $\sum_T \prod_{e \in T} p_e$гҖӮ
иҖҢжң¬йўҳйңҖиҰҒжұӮ $\sum_T \{ \prod_{e \in T} p_e \prod_{e \notin T} (1 - p_e) \}$гҖӮеҸҳжҚўеҸҜеҫ—пјҡ
$$\sum_T \{ \prod_{e \in T} p_e \prod_{e \notin T} (1 - p_e) \}$$
$$= \sum_T \{ \prod_{e \in T} p_e \frac{\prod_e (1 - p_e)}{\prod_{e \in T} (1-p_e)} \}$$
$$= \prod_e (1 - p_e) (\sum_T \prod_{e \in T} \frac{p_e}{1-p_e})$$
з„¶еҗҺд»Ҙ $\frac{p_e}{1 - p_e}$ дёәиҫ№жқғдҪҝз”ЁеҸҳе…ғзҹ©йҳөж ‘жұӮиҫ№жқғз§Ҝзҡ„е’ҢеҚіеҸҜгҖӮ
### Code
```cpp йҮҚе»ә
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

int n;
double ans(1), eps = 1e-8;

double G[55][55], p[55][55];
inline double Gauss() {
    double ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[i][i]) < eps) swap(G[i], G[j]), ans = -ans;
            else break;
        }
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[j][i]) < eps) continue;
            double tmp = G[j][i] / G[i][i];
            for (int k = i; k < n; k++)
                G[j][k] -= tmp * G[i][k];
        }
        ans = ans * G[i][i];
    }
    return ans;
}

inline void add(int u, int v, double val) {
    G[u][u] += val, G[v][v] += val;
    G[u][v] -= val, G[v][u] -= val;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cout << setprecision(4) << fixed;
    cin >> n;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= n; j++) {
            cin >> p[i][j];
            if (i >= j) continue;
            double tmp = fabs(1.0 - p[i][j]) < eps ? eps : fabs(1.0 - p[i][j]);
            ans *= tmp, p[i][j] /= tmp;
            add(i, j, p[i][j]);
        }
    cout << ans * fabs(Gauss()) << endl;
    return 0;
}
```

## D HDUеӨҡж Ў Expectation
