## E жңҖе°Ҹз”ҹжҲҗж ‘и®Ўж•°
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P4208)
### Solution
жңҖе°Ҹз”ҹжҲҗж ‘жңүдёҖдёӘжҖ§иҙЁжҳҜпјҢеҗҢдёҖиҫ№жқғзҡ„иҫ№зҡ„ж•°зӣ®жҳҜзӣёеҗҢзҡ„гҖӮиҖғиҷ‘е…ҲйҡҸж„Ҹз”ҹжҲҗдёҖдёӘжңҖе°Ҹз”ҹжҲҗж ‘пјҢз„¶еҗҺеҜ№з”ҹжҲҗж ‘дёҠзҡ„жҜҸдёӘжқғеҖји®Ўз®—иҙЎзҢ® (зӣёеҗҢиҫ№жқғеҸӘи®Ўз®—дёҖж¬Ў)гҖӮ
е…·дҪ“жқҘиҜҙпјҢе°ұжҳҜжһҡдёҫжңҖе°Ҹз”ҹжҲҗж ‘дёҠзҡ„иҫ№пјҢе°Ҷе…¶еҲ йҷӨ (и®ҫиҫ№жқғдёә $w_i$пјҢзӣёеҗҢиҫ№жқғеҸӘеҲ йҷӨдёҖж¬Ў)пјҢз„¶еҗҺеҫ—еҲ°иӢҘе№ІиҝһйҖҡеқ— (зј©жҲҗдёҖдёӘзӮ№)гҖӮеҶҚз”ЁжүҖжңүиҫ№жқғдёә $w_i$ зҡ„иҫ№жҠҠиҝһйҖҡеқ—иҝһжҺҘиө·жқҘпјҢеҜ№иҝҷдәӣиҝһйҖҡеқ—зҡ„з”ҹжҲҗж ‘и®Ўж•°пјҢжңҖеҗҺд№ҳжі•еҺҹзҗҶеҫ—еҲ°жңҖз»Ҳзӯ”жЎҲгҖӮ
### Code
```cpp жңҖе°Ҹз”ҹжҲҗж ‘и®Ўж•°
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 105;
constexpr int MOD = 31011;

int n, m, ans = 1, fa[MAXN], vis[MAXN], belong[MAXN];
vector<pair<int, pair<int, int>>> vec, eTree;

inline int find(int x) { return fa[x] == x ? x : fa[x] = find(fa[x]); }

inline void Union(int a, int b) {
    int r1 = find(a), r2 = find(b);
    if (r1 != r2) fa[r1] = r2;
}

inline void kruskal(int cnt = 0) {
    for (int i = 1; i <= n; i++) fa[i] = i;
    sort(vec.begin(), vec.end());
    for (auto& e : vec) {
        int w = e.first, u = e.second.first, v = e.second.second;
        if (find(u) != find(v)) {
            cnt++;
            Union(u, v);
            eTree.push_back(make_pair(w, make_pair(u, v)));
        }
        if (cnt == n - 1) break;
    }
}

int G[MAXN][MAXN];
inline LL Gauss(int n) {
    LL ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) { G[u][u]++, G[v][v]++, G[u][v]--, G[v][u]--; }

inline int calc(int res = 1) {
    for (int i = 0; i < eTree.size(); i++) {
        if (i && eTree[i - 1].first == eTree[i].first) continue;
        int cnt = 0;
        memset(G, 0, sizeof(G)), memset(vis, 0, sizeof(vis));
        for (int j = 1; j <= n; j++) fa[j] = j;
        for (auto& e : eTree) { //з”ҹжҲҗж ‘дёҠжқғеҖјдёҚдёәeTree[i]зҡ„иҫ№пјҢжұӮеҮәиҒ”йҖҡеқ—
            int w = e.first, u = e.second.first, v = e.second.second;
            if (w == eTree[i].first) continue;
            Union(u, v);
        }
        for (int j = 1; j <= n; j++) {//еӨ„зҗҶиҝһйҖҡеқ—ж•°зӣ® ж–№дҫҝеҗҺз»ӯз”ҹжҲҗж ‘Gaussи®Ўж•°
            if (!vis[find(j)]) vis[find(j)] = ++cnt;
            belong[j] = vis[find(j)];
        }
        for (auto& e : vec) { //жүҖжңүиҫ№пјҢе°ҶиҝһйҖҡеқ—зӣёиҝһ
            int w = e.first, u = e.second.first, v = e.second.second;
            if (w != eTree[i].first) continue;
            add(belong[u], belong[v]); //еҠ иҫ№
        }
        res = res * Gauss(cnt) % MOD;
    }
    return res;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1, u, v, w; i <= m; i++) {
        cin >> u >> v >> w;
        vec.push_back(make_pair(w, make_pair(u, v)));
    }
    kruskal();
    cout << calc() << endl;
    return 0;
}
```

## жңүеҗ‘еӣҫзҡ„жңүж №жңҖе°Ҹз”ҹжҲҗж ‘и®Ўж•°
### Description
