### Solution
жұӮд»Ҙ 1 дёәж №зҡ„з”ҹжҲҗж ‘ж•°йҮҸгҖӮ
жһ„йҖ зҹ©йҳө $A$пјҡ $i != j$пјҢ$a_{ij}$ иЎЁзӨә $i$ еҲ° $j$ зҡ„жңүеҗ‘иҫ№ж•°зҡ„зӣёеҸҚж•°пјӣ$a_{ii}$ дёә $i$ зҡ„еҮәеәҰгҖӮ
иҜҘзҹ©йҳөеҺ»жҺүз¬¬ 1 иЎҢпјҢз¬¬ 1 еҲ—еҚідёәд»Ҙ 1 дёәж №зҡ„з”ҹжҲҗж ‘ж•°йҮҸгҖӮ
### Code
```cpp CQOI2018 зӨҫдәӨзҪ‘з»ң
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 1e3 + 3, MOD = 1e4 + 7;

int n, m, u, v;

int G[MAXN][MAXN];
inline int Gauss(int n, int res = 1) {
    for (int i = 2; i <= n; i++) {
        for (int j = i + 1; j <= n; j++) {
            while (G[j][i]) {
                int t = G[i][i] / G[j][i];
                for (int k = i; k <= n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                res = -res;
            }
        }
        res = res * G[i][i] % MOD;
    }
    return (res + MOD) % MOD;
}
/*д»Һ u еҲ° v зҡ„жңүеҗ‘иҫ№*/
inline void add(int u, int v) { G[u][v]--, G[u][u]++; }

signed main() {
