## Solution
жһҡдёҫ $a вҲҲ [l,r]$пјҢз”ұдәҺ $b-c вҲҲ [l-r,r-l]$пјҢж•… $l-r \le m-na \le r-l$ дё” $n \ge 1$пјҢз”ұжӯӨеҸҜеҫ— $\lceil \frac{m-(r-l)}a \rceil \le n \le \lfloor \frac{m+(r-l)}a \rfloor$пјҢдё” $n \ge 1$гҖӮиҝҷдёӘиҢғеӣҙеҶ…зҡ„ $n$ йғҪеҜ№еә”дёҖз»„и§ЈгҖӮдёәдәҶж–№дҫҝпјҢеҸ–дёҠз•Ңд»Је…Ҙ, еҸҜжҺЁеҮә $b-c$гҖӮж №жҚ® $b-c$ зҡ„жӯЈиҙҹеҲҶзұ»жһ„йҖ еҚіеҸҜгҖӮ

## Code
```cpp Dubious Cyrpto
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;
int T;
ll m, l, r;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> T;
    while (T--) {
        cin >> l >> r >> m;
        for (ll a = l; a <= r; a++) {
            ll k = (m + r - l) / a;
            if (k > 0) {
                ll delta = m - k * a;
                if (delta < 0 && delta >= l - r) {
                    cout << a << " " << r + delta << " " << r << endl;
                    break;
                } else if (delta >= 0 && delta <= r - l) {
                    cout << a << " " << l + delta << " " << l << endl;
                    break;
                }
            }
        }
    }
    return 0;
}
