# C Choosing Flowers
[йўҳзӣ®й“ҫжҺҘ](https://codeforces.ml/contest/1379/problem/C)

## Solution
жҳҫз„¶пјҢд»·еҖјеӨ§зҡ„иҠұеә”е°ҪеҸҜиғҪеӨҡйҖүпјҢдәҺжҳҜе°ҶжүҖжңүд»·еҖјд»ҺеӨ§еҲ°е°ҸжҺ’еәҸеҗҺиҙӘеҝғзҡ„йҖүеҸ–д»·еҖјеӨ§зҡ„иҠұгҖӮи®ҫеҪ“еүҚжһҡдёҫеҲ°зҡ„д»·еҖјдёә $c_i$пјҢеҜ№еә”зј–еҸ·дёә $f_i$ зҡ„иҠұпјҢжңүеҰӮдёӢжғ…еҪўпјҡ
- иӢҘ $c_i = a_{f_i}$пјҢеҲҷдёҖе®ҡд№° $f_i$пјҢеҫ—еҲ°д»·еҖј $a_{f_i}$пјҢдё”иҝҳйңҖиҙӯд№°зҡ„иҠұзҡ„ж•°зӣ®еҮҸ 1
- иӢҘ $c_i = b_{f_i}$пјҢеҲҷжңүдёүз§Қжғ…еҶөпјҡ
  - иӢҘ $f_i$ жІЎжңүиў«д№°иҝҮпјҢе…Ҳд№°дёҖж¬Ў $f_i$пјҢеҫ—еҲ°д»·еҖј $a_{f_i}$гҖӮеү©дёӢзҡ„е…ЁйғЁд№° $f_i$, жҜҸдёӘд»·еҖјдёә $b_{f_i}$
  - иӢҘ $f_i$ е·Іиў«д№°иҝҮпјҢеҲҷеү©дёӢзҡ„е…ЁйғЁд№° $f_i$, жҜҸдёӘд»·еҖјдёә $b_{f_i}$
  - дёҚд№° $f_i$пјҢз»§з»ӯеҗ‘еҗҺиҖғиҷ‘

е®№жҳ“иҜҒжҳҺжІЎжңүжҜ”дёҠиҝ°ж–№ејҸжӣҙдјҳзҡ„йҖүжі•гҖӮ

## Code
```cpp Choosing Flowers
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 100005;
int a[MAXN], b[MAXN], n, m, T;
vector<tuple<int, bool, int> > cost;
bool vis[MAXN];

bool cmp(tuple<int, bool, int> &a, tuple<int, bool, int> &b) {
    return get<0>(a) > get<0>(b);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> T;
    while (T--) {
        cin >> n >> m;
        cost.clear();
        fill(vis + 1, vis + m + 1, 0);
        ll tmp = 0, ans = 0;
        for (int i = 1; i <= m; i++) {
            cin >> a[i] >> b[i];
            cost.push_back(make_tuple(a[i], 0, i));
            cost.push_back(make_tuple(b[i], 1, i));
        }
        sort(cost.begin(), cost.end(), cmp);
        for (int i = 0; i < cost.size(); i++) {
            int val = get<0>(cost[i]);
            bool type = get<1>(cost[i]);
            int id = get<2>(cost[i]);
            if (type) {
                if (vis[id])
                    ans = max(ans, tmp + 1ll * n * val);
                else
                    ans = max(ans, tmp + a[id] + 1ll * (n - 1) * val);
            } else {
                tmp += val;
                n--;
                vis[id] = 1;
            }
            if (!n) {
                ans = max(ans, tmp);
                break;
            }
        }
        cout << ans << '\n';
    }
    return 0;
}

```


# D New Passenger Trams
[йўҳзӣ®й“ҫжҺҘ](https://codeforces.ml/contest/1379/problem/D)

## Solution
и®ҫз¬¬дёҖиҫҶе®ўиҪҰеҸ‘иҪҰж—¶й—ҙдёә $t$пјҢ$t вҲҲ [0, \frac{M}2 - 1]$пјҢйӮЈд№Ҳеә”иҜҘиў«еҲ йҷӨзҡ„иҙ§иҪҰ $i$ зҡ„еҸ‘иҪҰж—¶й—ҙеә”иҜҘж»Ўи¶і $h_iM+m_i вҲҲ[t-k+1+j * \frac{M}2,t-1+j*\frac{M}2]$пјҢз§»йЎ№еҫ— $m_i вҲҲ[t-k+1+(j-2h_i) * \frac{M}2,t-1+(j-2h_i)*\frac{M}2]$пјҢе…¶дёӯ $j$ дёәд»»ж„Ҹж•ҙж•°гҖӮз”ұдәҺ $m_iвҲҲ[0,M-1]$пјҢеҲҷеҸҜиғҪзҡ„ $j$ зҡ„еҸ–еҖјдёә $2h_i$ д»ҘеҸҠ $2h_i+1$гҖӮе°ҶиҝҷдёӨдёӘеҸ–еҖјеҲҶеҲ«д»Је…ҘеҸҜеҫ— $m_i вҲҲ [t-k+1,t-1]вҲӘ [t-k+1 +\frac{M}2,t-1+\frac{M}2]$гҖӮйңҖиҰҒжіЁж„Ҹзҡ„жҳҜеҜ№дәҺеҢәй—ҙ$[t-k+1,t-1]$пјҢе…¶е·Ұз«ҜзӮ№еҸҜиғҪе°ҸдәҺ $0$пјҢжӯӨж—¶йңҖиҰҒе°ҶеҢәй—ҙд»Һ $0$ жӢҶжҲҗдёӨеҚҠпјҢе№¶е°Ҷе°ҸдәҺйӣ¶зҡ„йғЁеҲҶеҜ№ $M$ еҸ–жЁЎпјҢеҫ—$m_iвҲҲ[t-k+1+M,M-1]вҲӘ[0,t-1]вҲӘ[t-k+1 +\frac{M}2,t-1+\frac{M}2]$гҖӮе®№жҳ“еҸ‘зҺ°еҪ“ $k=1$ ж—¶дёҚеӯҳеңЁеҢ…еҗ«иҙ§иҪҰеҸ‘иҪҰж—¶й—ҙзҡ„еҢәй—ҙпјҢеҚіжІЎжңүиҙ§иҪҰйңҖиҰҒиў«еҲ еҺ»пјҢзӣҙжҺҘиҫ“еҮә $0$ $0$ еҚіеҸҜгҖӮ

д»ҺдёҠиҝ°жҺЁеҜјеҸҜзҹҘпјҢдёҖиҫҶиҙ§иҪҰжҳҜеҗҰиў«еҲ йҷӨд»…еҸ–еҶідәҺ $m_i$ е’Ң $t$гҖӮжіЁж„ҸеҲ°иҙ§иҪҰеҸ‘иҪҰж—¶й—ҙжҖ»ж•°дёҚи¶…иҝҮ $10^5$ дёӘпјҢдё”еҜ№дәҺ $m_i$ еҸҜд»ҘеҸҚжҺЁеҮәдјҡеҜјиҮҙе®ғиў«еҲ йҷӨзҡ„ $t$ зҡ„еҢәй—ҙпјҡ
- иӢҘ $t \ge k-1$пјҢеҲҷ $tвҲҲ[m_i+1, m_i+k-1]вҲӘ[m_i+1 -\frac{M}2, m_i+k-1-\frac{M}2]$
- иӢҘ $t \le k-2$пјҢеҲҷ $tвҲҲ[0, m_i+k-1-M]вҲӘ[m_i+1 -\frac{M}2, m_i+k-1-\frac{M}2]вҲӘ[m_i+1, k-2]$

еӣ жӯӨеҸҜд»ҘжһҡдёҫжүҖжңүиҙ§иҪҰ $i$пјҢеҜ№ $m_i$ еҜ№еә”зҡ„дёҚеҗҲжі•ж—¶й—ҙж®өиҝӣиЎҢеҢәй—ҙеўһеҖјж“ҚдҪңпјҢжңҖеҗҺз»ҹи®ЎеҢәй—ҙжңҖе°ҸеҖје°ұжҳҜйңҖиҰҒиў«еҲ еҺ»зҡ„иҙ§иҪҰзҡ„жңҖе°‘ж•°зӣ®пјҢдё”еҢәй—ҙжңҖе°ҸеҖјзҡ„дҪҚзҪ®еҜ№еә”жңҖдјҳеҸ‘иҪҰж—¶й—ҙгҖӮиҝҷж ·й—®йўҳиҪ¬еҢ–жҲҗеҢәй—ҙжӣҙж–°дёҺжұӮеҢәй—ҙжңҖеҖјпјҢз”ЁеҠЁжҖҒејҖзӮ№зәҝж®өж ‘з»ҙжҠӨеҚіеҸҜгҖӮ

## Code
```cpp New Passenger Trams
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 1e5 + 5;
ll n, H, M, k;
ll h[MAXN], m[MAXN];

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Node {
    Node *lson, *rson;
    int l, r;
    ll id, lazy;
    ll mi;
} * root, node[MAXN * 64];

Node* newNode(ll l, ll r) {
    static int tot;
    node[tot].l = l, node[tot].r = r;
    node[tot].lazy = 0;
    node[tot].mi = 0, node[tot].id = l;
    return &node[tot++];
}

void pushdown(Node* cur) {
    if (cur->lson) {
        cur->lson->mi += cur->lazy;
        cur->lson->lazy += cur->lazy;
    }
    if (cur->rson) {
        cur->rson->mi += cur->lazy;
        cur->rson->lazy += cur->lazy;
    }
    cur->lazy = 0;
}

void update(Node* cur) {
    if (cur->lson->mi <= cur->rson->mi)
        cur->mi = cur->lson->mi, cur->id = cur->lson->id;
    else
        cur->mi = cur->rson->mi, cur->id = cur->rson->id;
}

void insert(Node* cur, ll l, ll r) {
    if (cur->l == l && cur->r == r) {
        cur->mi++;
        cur->lazy++;
        return;
    }
    int mid = cur->l + cur->r >> 1;
    if (!cur->lson) cur->lson = newNode(cur->l, mid);
    if (!cur->rson) cur->rson = newNode(mid + 1, cur->r);
    pushdown(cur);
    if (r <= mid)
        insert(cur->lson, l, r);
    else if (l > mid)
        insert(cur->rson, l, r);
    else
        insert(cur->lson, l, mid), insert(cur->rson, mid + 1, r);
    update(cur);
}

int main() {
    read(n), read(H), read(M), read(k);
    if (k == 1) cout << 0 << " " << 0, exit(0);
    root = newNode(0, M / 2 - 1);
    for (int i = 1; i <= n; i++) {
        read(h[i]), read(m[i]);

        if (m[i] + 1 <= M / 2 - 1)
            insert(root, max(k - 1, m[i] + 1), min(M / 2, m[i] + k) - 1);
        if (m[i] + k - 1 - M / 2 >= k - 1 && m[i] + 1 - M / 2 <= M / 2 - 1)
            insert(root, max(k - 1, m[i] + 1 - M / 2), min(M / 2, m[i] + k - M / 2) - 1);

        if (m[i] + k - 1 - M >= 0)
            insert(root, 0, min(k - 2, m[i] + k - 1 - M));
        if (m[i] + 1 <= k - 2) 
            insert(root, m[i] + 1, k - 2);
        if (m[i] + k - 1 - M / 2 >= 0 && m[i] + 1 - M / 2 <= k - 2)
            insert(root, max(0ll, m[i] + 1 - M / 2), min(k - 2, m[i] + k - 1 - M / 2));
    }
    cout << root->mi << " " << root->id << endl;
    int t = root->id;
    for (int i = 1; i <= n; i++) {
        if (t >= k - 1) {
            if (t - k + 1 <= m[i] && m[i] <= t - 1)
                cout << i << " ";
            else if (t - k + 1 + M / 2 <= m[i] && m[i] <= t - 1 + M / 2)
                cout << i << " ";
        } else {
            if (t >= 1 && m[i] <= t - 1)
                cout << i << " ";
            else if (t - k + 1 + M <= m[i] && m[i] <= M - 1)
                cout << i << " ";
            else if (t - k + 1 + M / 2 <= m[i] && m[i] <= t - 1 + M / 2)
                cout << i << " ";
        }
    }
    return 0;
}
```



# E Inverse Genealogy
[йўҳзӣ®й“ҫжҺҘ](https://codeforces.ml/contest/1379/problem/E)

## Solution
з»“и®әйўҳгҖӮи®ҫеҪ“еүҚжңү $n$ дёӘиҠӮзӮ№пјҢе…¶дёӯжңү $k$ дёӘдёҚе№іиЎЎзӮ№гҖӮжҳҫз„¶пјҢжңүжңҖеӨҡдёҚе№іиЎЎзӮ№зҡ„ж ‘жҳҜжҜӣжҜӣиҷ«ж ‘пјҢеҚі $n$ дёӘиҠӮзӮ№дёӯжңҖеӨҡжңү $\frac{n-3}2$ дёӘдёҚе№іиЎЎзӮ№гҖӮеҰӮжһң $k = 0$пјҢеҲҷеә”жңү $n=2^p-1$пјӣеҰӮжһң $k=1$пјҢеҲҷ $n \neq 2^p-1$гҖӮеҗҢж—¶еҪ“ $n=9,k=2$ ж—¶ж— и§ЈгҖӮйӘҢиҜҒ $n$ дёӘиҠӮзӮ№пјҢжһ„йҖ  $k$ дёӘдёҚе№іиЎЎзӮ№зҡ„еҸҜиЎҢжҖ§еҗҺжҡҙеҠӣжһ„йҖ еҚіеҸҜгҖӮе…·дҪ“зҡ„пјҢи®©е·Ұеӯҗж ‘дёҚе№іиЎЎзӮ№ж•°зӣ®дёә 0пјҢеҚідҪҝе·Ұеӯҗж ‘еӨ§е°Ҹдёә $2^p-1$пјҢжҺҘдёӢжқҘеңЁеҸіеӯҗж ‘дёӯжһ„йҖ еү©дҪҷзҡ„дёҚе№іиЎЎзӮ№гҖӮ
## Code
```cpp Inverse Genealogy
#include <bits/stdc++.h>

using namespace std;

int n, k, cnt;

bool check(int cntNode, int cntCritical) {
    if (cntNode % 2 == 0) return 0;
    if (!cntCritical) return !(cntNode & (cntNode + 1));
    if (cntCritical == 1) return cntNode & (cntNode + 1);
    if (cntNode == 9 && cntCritical == 2) return 0;
    return cntCritical > 0 && cntCritical <= (cntNode - 3) / 2;
}

void dfs(int cntNode, int cntCritical, int cur) {
    cout << cur << " ";
    int fa = ++cnt;
    if (cntNode == 1) return;
    for (int lsize = 1; lsize < cntNode; lsize = lsize * 2 + 1) {
        int rsize = cntNode - lsize - 1;
        int rem = cntCritical - (max(lsize, rsize) >= (min(lsize, rsize) * 2));
        if (check(lsize, 0) && check(rsize, rem)) {
            dfs(lsize, 0, fa);
            dfs(rsize, rem, fa);
            return;
        }
    }
}

int main() {
    cin >> n >> k;
    if (!check(n, k)) cout << "NO" << endl, exit(0);
    cout << "YES" << endl;
    dfs(n, k, 0);
    return 0;
}
```


# F Chess Strikes Back
[йўҳзӣ®й“ҫжҺҘпјҲEasy Versionпјү](https://codeforces.ml/contest/1379/problem/F1)

[йўҳзӣ®й“ҫжҺҘпјҲHard Versionпјү](https://codeforces.ml/contest/1379/problem/F2)

## Solution
е°Ҷ $2n*2m$ зҡ„жЈӢзӣҳеҲҶеүІдёә $n*m$ дёӘ $2*2$ зҡ„е°Ҹж–№ж јпјҢеҲҷй—®йўҳиҪ¬еҢ–дёәеҲӨж–ӯеңЁжҜҸдёӘе°Ҹж–№ж јзҡ„е·ҰдёҠи§’жҲ–еҸідёӢи§’ж”ҫе…ҘдёҖдёӘжЈӢеӯҗзҡ„еҸҜиЎҢжҖ§гҖӮи§„е®ҡе·ҰдёҠи§’дёҚиғҪж”ҫжЈӢеӯҗзҡ„ж–№ж јдёә $L$ еһӢпјҢеҸідёӢи§’дёҚиғҪж”ҫжЈӢеӯҗзҡ„дёә $R$ еһӢгҖӮ 

иӢҘеҪ“еүҚж–№ж ј $(i,j)$ дёә $R$ еһӢпјҢеҚіеҸӘиғҪеңЁе·ҰдёҠи§’ж”ҫжЈӢеӯҗпјҢеҲҷж»Ўи¶і $i'\le i$ дё” $j' \le j$ зҡ„ж–№ж ј $(i',j')$ дёҚиғҪжҳҜ $L$ еһӢгҖӮжҚўиҖҢиЁҖд№ӢпјҢи®ҫ $minL_i$ иЎЁзӨәз¬¬ $i$ иЎҢз¬¬дёҖдёӘ $L$ еһӢж–№ж јзҡ„еҲ—еқҗж ҮпјҢ$maxR_i$ дёәз¬¬ $i$ иЎҢжңҖеҗҺдёҖдёӘ $R$ еһӢж–№ж јзҡ„еҲ—еқҗж ҮпјҢеҲҷеҜ№ $\forall j\le i,minL_j>maxR_i$гҖӮ

иҖғиҷ‘зәҝж®өж ‘з»ҙжҠӨеҢәй—ҙ $[1,n]$ зҡ„ $minL$ е’Ң $maxR$пјҢжҜҸж¬Ўжӣҙж–°еҗҺеҗҲе№¶еҢәй—ҙж—¶еҸҜд»ҘеҲӨж–ӯе·Ұеӯҗж ‘ $minL$ жҳҜеҗҰеӨ§дәҺеҸіеӯҗж ‘ $maxR$пјҢиӢҘдёҚжҳҜеҲҷж— и§ЈгҖӮиҮідәҺ $minL_i$ е’Ң $maxR_i$пјҢз”ұдәҺжңүеҲ йҷӨж“ҚдҪңпјҢеҸҜз”Ё $n$ дёӘ $set$ еӯҳеӮЁпјҢжҜҸж¬ЎиҜўй—®ж—¶еҸ–зӣёеә” $set$ зҡ„е…ғзҙ е№¶еңЁзәҝж®өж ‘дёҠиҝӣиЎҢеҚ•зӮ№дҝ®ж”№еҚіеҸҜгҖӮ 
## Code
```cpp Chess Strikes Back
#include <bits/stdc++.h>

using namespace std;

const int MAXN = 2e5 + 5;
int n, m, q, x, y;
unordered_map<int, unordered_map<int, int> > state[2];
set<int> L[MAXN], R[MAXN];

template <class T>
void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Node {
    Node *lson, *rson;
    int l, r;
    int miL, mxR;
    bool tag;
    Node(int _l, int _r) {
        l = _l, r = _r;
        miL = m + 1, mxR = 0;
        tag = 1;
    }
} * root;

void update(Node* cur) {
    cur->miL = min(cur->lson->miL, cur->rson->miL);
    cur->mxR = max(cur->lson->mxR, cur->rson->mxR);
    if (!cur->lson->tag || !cur->rson->tag || cur->lson->miL <= cur->rson->mxR)
        cur->tag = 0;
    else
        cur->tag = 1;
}

void build(Node*& cur, int l, int r) {
    cur = new Node(l, r);
    if (l == r) return;
    int mid = l + r >> 1;
    build(cur->lson, l, mid);
    build(cur->rson, mid + 1, r);
}

void modify(Node* cur, int x, int val, int tag) {
    if (cur->l == x && cur->r == x) {
        if (tag == 2)
            cur->mxR = val;
        else
            cur->miL = val;
        cur->tag = cur->miL > cur->mxR;
        return;
    }
    int mid = cur->l + cur->r >> 1;
    if (x <= mid)
        modify(cur->lson, x, val, tag);
    else
        modify(cur->rson, x, val, tag);
    update(cur);
}

int main() {
    read(n), read(m);
    read(q);
    build(root, 1, n);
    while (q--) {
        read(x), read(y);
        int i = x + 1 >> 1, j = y + 1 >> 1;
        if (!state[x & 1][i][j]) {
            if (x & 1) {
                state[x & 1][i][j] = 1;
                L[i].insert(j);
                modify(root, i, *L[i].begin(), 1);
            } else {
                state[x & 1][i][j] = 1;
                R[i].insert(j);
                auto it = R[i].end();
                modify(root, i, *(--it), 2);
            }
        } else {
            if (x & 1) {
                state[x & 1][i][j] = 0;
                L[i].erase(j);
                modify(root, i, L[i].empty() ? m + 1 : *L[i].begin(), 1);
            } else {
                state[x & 1][i][j] = 0;
                R[i].erase(j);
                auto it = R[i].end();
                modify(root, i, R[i].empty() ? 0 : *(--it), 2);
            }
        }
        if (!root->tag)
            puts("NO");
        else
            puts("YES");
    }
    return 0;
}
```

