е…·дҪ“зҡ„пјҢи®ҫеҪ“еүҚдҪҚзҪ®дёә $i$пјҢеҸӘйңҖжұӮ $i$ д№ӢеүҚеҪўеҰӮ $[111...1][222...2]$ зҡ„жңҖй•ҝеӯҗеәҸеҲ—е’Ң $i$ д№ӢеҗҺеҪўеҰӮ $[111...1][222...2]$ зҡ„жңҖй•ҝеӯҗеәҸеҲ—пјҢеҚіжұӮ $1 \to i$ зҡ„жңҖй•ҝдёҚдёӢйҷҚеӯҗеәҸеҲ—д»ҘеҸҠ $n \to i+1$ зҡ„жңҖй•ҝдёҚдёҠеҚҮеӯҗеәҸеҲ—гҖӮеҲҶеҲ«д»ҺеүҚеҫҖеҗҺгҖҒд»ҺеҗҺеҫҖеүҚжү«дёҖйҒҚз”Ё $DP$ з»ҙжҠӨеәҸеҲ—й•ҝеәҰжңҖеӨ§еҖјеҚіеҸҜгҖӮ

ж—¶з©әеӨҚжқӮеәҰ $O(n)$гҖӮ

# Code
```cpp
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 2005;
int n, ans, a[MAXN];
int pre[MAXN][2], pos[MAXN][2];

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> a[i];
    for (int i = 1; i <= n; i++) {
        if (a[i] == 2) {
            pre[i][2] = max(pre[i - 1][2], pre[i - 1][1]) + 1;
            pre[i][1] = pre[i - 1][1];
        } else {
            pre[i][2] = pre[i - 1][2];
            pre[i][1] = pre[i - 1][1] + 1;
        }
    }
    for (int i = n; i; i--) {
        if (a[i] == 2) {
            pos[i][2] = pos[i + 1][2] + 1;
            pos[i][1] = pos[i + 1][1];
        } else {
            pos[i][2] = pos[i + 1][2];
            pos[i][1] = max(pos[i + 1][1], pos[i + 1][2]) + 1;
        }
    }
    for (int i = 1; i <= n; i++)
        ans = max(
            ans, max(pre[i][1], pre[i][2]) + max(pos[i + 1][1], pos[i + 1][2]));
    cout << ans;
    return 0;
}
