## A SP8073 CIRU - The area of the union of circles
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/SP8073)
жұӮеңҶзҡ„йқўз§Ҝе№¶
### Solution
жіЁж„ҸеҲ°зӣ®ж ҮеҮҪж•°еҖјдёҚиҝһз»ӯпјҢеҸҜиғҪеӯҳеңЁеӨ§йҮҸ0пјҢж•…еҲҶж®өиҝӣиЎҢиҫӣжҷ®жЈ®з§ҜеҲҶгҖӮ

еҸҜд»ҘйҖҡиҝҮеҲӨж–ӯеңҶзҡ„зӣёдәӨжұӮеҮәиҒ”йҖҡеқ—пјҢеҜ№иҒ”йҖҡеқ—дёҠзҡ„еңҶжұӮйқўз§Ҝе№¶гҖӮжҲ–иҖ…е°ҶеңҶзҡ„е·ҰеҸіз«ҜзӮ№еқҗж Үеӯҳе…Ҙ vector жҺ’еәҸпјҢжҜҸж¬ЎеҸ–зӣёйӮ»дё”дёҚеҗҢзҡ„еқҗж Ү $l, r$пјҢеҜ№ $[l, r]$ иҝӣиЎҢз§ҜеҲҶгҖӮ

жң¬йўҳ $f(x)$ дёҚиғҪеңЁеёёж•°ж—¶й—ҙиҺ·еҫ—пјҢеҸҜз”Ё unordered_map дјҳеҢ–гҖӮ
### Code
```cpp The area of the union of circles
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 1e3 + 3;
constexpr long double EPS = 1e-10;

int n, vis[MAXN];
vector<int> chosen, G[MAXN];

struct Circle {
    /*@param x x of center O @param y y of center O @param R radius*/
    long double x, y, R;
    /*@param l жңҖе·Ұз«Ҝ @param r жңҖеҸіз«Ҝ*/
    long double l, r;
    /*жҢүе·Ұз«ҜзӮ№жҺ’еәҸ зӣёеҗҢеҲҷжҢүеҸіз«ҜзӮ№жҺ’еәҸ*/
    friend inline bool operator<(const Circle& a, const Circle& b) {
        return a.l < b.l - EPS;
    }
} circle[MAXN];

struct Seg {
    /*@param l е·Ұз«ҜзӮ№ @param r еҸіз«ҜзӮ№*/
    long double l, r;
    /*жҢүе·Ұз«ҜзӮ№жҺ’еәҸ зӣёеҗҢеҲҷжҢүеҸіз«ҜзӮ№жҺ’еәҸ*/
    friend inline bool operator<(const Seg& a, const Seg& b) {
         return a.l < b.l - EPS;
    }
} seg[MAXN];

unordered_map<double, double> mp;
inline long double f(long double x) { //з®—xеӨ„иҰҶзӣ–зҡ„зәҝж®өжҖ»й•ҝ
    int tot = 0;
    for (auto& i : chosen) {
        long double tmp = pow(circle[i].R, 2) - pow(x - circle[i].x, 2);
        if (tmp < EPS) continue;
        seg[++tot].l = circle[i].y - sqrt(tmp);
        seg[tot].r = circle[i].y + sqrt(tmp);
    }
    sort(seg + 1, seg + tot + 1);
    long double l = seg[1].l, len = .0;
    for (int i = 1; i <= tot; i++) {
        l = max(l, seg[i].l);
        if (l < seg[i].r - EPS) len += seg[i].r - l;
        l = max(l, seg[i].r);
    }
    return len;
}

inline long double simpson(long double l, long double r) {
    long double mid = (l + r) / 2;
    return (f(l) + f(mid) * 4 + f(r)) * (r - l) / 6;
}

long double integral(long double l, long double r, long double eps) {
    long double mid = (l + r) / 2;
    long double iL = simpson(l, mid), iR = simpson(mid, r);
    long double i = simpson(l ,r);
    if (fabs(iL + iR - i) < eps * 15) return iL + iR + (iL + iR - i) / 15;
    return integral(l, mid, eps / 1.5) + integral(mid, r, eps / 1.5);
}

inline void init() {
    for (int i = 1; i <= n; i++) { //circleе·ІжҢүlжҺ’еәҸ
        if (vis[i] || circle[i].R < EPS) { //еҚҠеҫ„дёә0и·іиҝҮ
            vis[i] = true; continue;
        }
        for (int j = i + 1; j <= n; j++) {
            if (vis[j] || circle[j].R < EPS) { //еҚҠеҫ„дёә0и·іиҝҮ
                vis[j] = true; continue;
            }
            long double tmp = pow(circle[i].x - circle[j].x, 2)
                            + pow(circle[i].y - circle[j].y, 2);
            if (tmp < pow(circle[i].R - circle[j].R, 2) + EPS) {//иў«еҢ…еҗ«
                vis[j] = true; continue; //еҢ…еҗ«е…ізі»дёҚеҠ иҫ№
            }
            if (tmp < pow(circle[i].R + circle[j].R, 2) + EPS)
                G[i].push_back(j), G[j].push_back(i); //iдёҺjиҒ”йҖҡ
        }
    }
}

inline void dfs(int cur, long double& r) { //еӨ„зҗҶиҝһйҖҡеқ—
    vis[cur] = true, chosen.push_back(cur);
    for (auto& to : G[cur]) {
        if (vis[to]) continue;
        dfs(to, r = max(r, circle[to].r)); //жұӮжңҖеӨ§еҸіз«ҜзӮ№
    }
}

inline long double calc() { //и®Ўз®—йқўз§Ҝе№¶
    long double l, r, ans = .0;
    for (int i = 1; i <= n; i++) {
        if (vis[i]) continue;
        chosen.clear();
        l = circle[i].l, r = circle[i].r;
        dfs(i, r); //еӨ„зҗҶиҝһйҖҡеқ—
        if (chosen.size() == 1) ans += acos(-1) * circle[i].R * circle[i].R;
        else ans += integral(l, r, 1e-5);
    }
    return ans;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cout << setprecision(3) << fixed;
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> circle[i].x >> circle[i].y >> circle[i].R;
        circle[i].l = circle[i].x - circle[i].R;
        circle[i].r = circle[i].x + circle[i].R;
    }
    sort(circle + 1, circle + n + 1);
    init();
    cout << calc();
    return 0;
}
```

## B NOI2005 жңҲдёӢжҹ жӘ¬ж ‘
### Prolbem
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P4207)
### Solution
жҠ•еҪұдёәдёҖзі»еҲ—еңҶд»ҘеҸҠжўҜеҪўжһ„жҲҗпјҢе…¶дёӯжўҜеҪўзҡ„ж–ңиҫ№дёәзӣёйӮ»еңҶзҡ„е…¬еҲҮзәҝ (еҸҜиғҪдёҚеӯҳеңЁ)гҖӮ

еҲҮзӮ№жұӮжі•пјҡдёӨеңҶеҝғеҲҶеҲ«дёҺеҜ№еә”зҡ„еҲҮзӮ№иҝһзәҝпјҢеңҶеҝғеҗ‘иҝһзәҝеҒҡеһӮзәҝпјҢеҲҮзӮ№еҗ‘иҪҙеҒҡеһӮзәҝпјҢйҖҡиҝҮзӣёдјјдёүи§’еҪўжұӮеҮәгҖӮ

жіЁж„Ҹпјҡз”ұдәҺжҠ•еҪұе…·жңүеҜ№з§°жҖ§пјҢеҸӘйңҖеҜ№дёҖеҚҠиҝӣиЎҢз§ҜеҲҶпјҢеҗҰеҲҷеҸҜиғҪи¶…ж—¶гҖӮ
### Code
```cpp NOI2005 жңҲдёӢжҹ жӘ¬ж ‘
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 3e3 + 3;
constexpr double EPS = DBL_EPSILON;

int n;
double h[MAXN], sumH, alpha;

struct Circle {
    /*@param x x of center O @param y y of center O @param R radius*/
    double x, y, R;
    /*@param l жңҖе·Ұз«Ҝ @param r жңҖеҸіз«Ҝ*/
    double l, r;
} circle[MAXN];

struct Seg {
    double l, r;
    friend inline bool operator<(const Seg& a, const Seg& b) {
        return a.l < b.l - EPS;
    }
} seg[MAXN];

struct Trapezoid {      //жўҜеҪўзұ»
    double x1, y1; //еҸідёҠйЎ¶зӮ№
    double x2, y2; //еҸідёӢйЎ¶зӮ№
    double deltaX = 0, height = 0;
} trape[MAXN];

unordered_map<double, double> mp;
inline double f(double x) {  //з®—xеӨ„иҰҶзӣ–зҡ„зәҝж®өжҖ»й•ҝ
    if (mp.count(x)) return mp[x];
    int tot = 0;
    for (int i = 1; i <= n; i++) { //еңҶеҪў
        double tmp = pow(circle[i].R, 2) - pow(x - circle[i].x, 2);
        if (tmp < EPS) continue;
        seg[++tot].l = circle[i].y - sqrt(tmp);
        seg[tot].r = circle[i].y + sqrt(tmp);
    }
    for (int i = 1; i <= n; i++) {  //жўҜеҪў
        double l = min(trape[i].x1, trape[i].x2);
        double r = max(trape[i].x1, trape[i].x2);
        if (r < x + EPS) continue;
        if (x < l + EPS) {
            seg[++tot].l = trape[i].y2, seg[tot].r = trape[i].y1;
            continue;
        }
        double delta = trape[i].x2 - x;
        double ratio = abs(delta / trape[i].deltaX);
        if (trape[i].deltaX > EPS) {
            seg[++tot].r = trape[i].y2 + trape[i].height * ratio;
            seg[tot].l = trape[i].y2;
        } else if (trape[i].deltaX < EPS) {
            seg[++tot].l = trape[i].y2 + trape[i].height * ratio;
            seg[tot].r = trape[i].y1;
        }
    }
    sort(seg + 1, seg + tot + 1);
    double len = .0, l = seg[1].l;
    for (int i = 1; i <= tot; i++) {
        l = max(l, seg[i].l);
        if (l < seg[i].r - EPS) len += seg[i].r - l;
        l = max(l, seg[i].r);
    }
    return mp[x] = len;
}

inline double simpson(double l, double r) {
    double mid = (l + r) / 2;
    return (f(l) + f(mid) * 4 + f(r)) * (r - l) / 6;
}

double integral(double l, double r, double eps, double i) {
    double mid = (l + r) / 2;
    double iL = simpson(l, mid), iR = simpson(mid, r);
    if (fabs(iL + iR - i) <= eps * 15) return iL + iR + (iL + iR - i) / 15;
    return integral(l, mid, eps / 1.6, iL) + integral(mid, r, eps / 1.6, iR);
}

inline double calc() {  //и®Ўз®—йқўз§Ҝе№¶
    for (int i = 1; i <= n; i++) {
        double dis = circle[i + 1].y - circle[i].y;  //еңҶеҝғи·қзҰ»
        if (dis < abs(circle[i].R - circle[i + 1].R) + EPS) continue;
        double theta = acos((circle[i].R - circle[i + 1].R) / dis);
        trape[i].x1 = circle[i + 1].R * sin(theta); //еҸідёҠйЎ¶зӮ№
        trape[i].y1 = circle[i + 1].y + circle[i + 1].R * cos(theta);
        trape[i].x2 = circle[i].R * sin(theta); //еҸідёӢйЎ¶зӮ№
        trape[i].y2 = circle[i].y + circle[i].R * cos(theta);
        trape[i].deltaX = trape[i].x2 - trape[i].x1; //
        trape[i].height = trape[i].y1 - trape[i].y2; //й«ҳеәҰ
    }
    double l = circle[1].l, r = circle[1].r;
    for (int i = 2; i <= n; i++)
        l = min(l, circle[i].l), r = max(r, circle[i].r);
    return integral(0, r, 5e-4, simpson(l, r)) * 2; //еҜ№з§°жҖ§ еҜ№1иҫ№з§ҜеҲҶ
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cout << setprecision(2) << fixed;
    cin >> n >> alpha;
    for (int i = 0; i <= n; i++) cin >> h[i];
    sumH = h[0];
    for (int i = 1; i <= n; i++) {
        cin >> circle[i].R;
        circle[i].x = 0, circle[i].y = sumH / tan(alpha);
        circle[i].l = -circle[i].R, circle[i].r = circle[i].R;
        sumH += h[i];
    }
    circle[n + 1].x = 0, circle[n + 1].y = sumH / tan(alpha);
    circle[n + 1].l = 0, circle[n + 1].r = 0;  //йЎ¶зӮ№
    cout << calc() << endl;
    return 0;
}
```
## C дёүи§’еҪў
### Description
[йўҳзӣ®й“ҫжҺҘ](https://www.luogu.com.cn/problem/P1222)
жұӮзӯүи…°зӣҙи§’дёүи§’еҪўзҡ„йқўз§Ҝе№¶
### Solution
жіЁж„ҸеҲ°еҚідҪҝдёүи§’еҪўжңүдәӨйӣҶпјҢзӣ®ж ҮеҮҪж•°д№ҹдјҡдёҚиҝһз»ӯгҖӮж•…дёҚиғҪжұӮиҝһйҖҡеқ—пјҢиҖҢжҳҜж”№дёәе°Ҷдёүи§’еҪўзҡ„е·ҰеҸіз«Ҝеқҗж Үеӯҳе…Ҙ vector жҺ’еәҸпјҢеҲҶж®өз§ҜеҲҶгҖӮ
### Code
```cpp дёүи§’еҪў
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 2e3 + 3;
constexpr double EPS = DBL_EPSILON;

struct Triangle {
    /*@param x1 дёҠйЎ¶xеқҗж Ү @param y1 дёҠйЎ¶yеқҗж Ү*/
    int x1, y1;
    /*@param x2 дёӢйЎ¶xеқҗж Ү @param y2 дёӢйЎ¶yеқҗж Ү*/
    int x2, y2;
    friend inline bool operator<(const Triangle& a, const Triangle& b) {
        return a.x1 < b.x1;
    }
} tri[MAXN];

int n, vis[MAXN], st, ed;
vector<int> G[MAXN], posX, chosen;
pair<double, double> seg[MAXN];

unordered_map<double, double> mp;
inline double f(double x) {
    if (mp.count(x)) return mp[x];
    int tot = 0;
    for (auto& i : chosen) {
        if (x < -EPS + tri[i].x1 || tri[i].x2 < -EPS + x) continue;
        seg[++tot].first = 1.0 * tri[i].y2;
        seg[tot].second = 1.0 * tri[i].y2 + tri[i].x2 - x;
    }
    sort(seg + 1, seg + tot + 1);
    double len = 0, l = seg[1].first;
    for (int i = 1; i <= tot; i++) {
        l = max(l, seg[i].first);
        if (l < seg[i].second - EPS) len += seg[i].second - l;
        l = max(l, seg[i].second);
    }
    return mp[x] = len;
}

inline double simpson(double l, double r) {
    double mid = (l + r) / 2;
    return (f(l) + f(mid) * 4 + f(r)) * (r - l) / 6;
}

double integral(double l, double r, double eps, double i) {
    double mid = (l + r) / 2;
    double iL = simpson(l, mid), iR = simpson(mid, r);
    if (fabs(iL + iR - i) <= eps * 15) return iL + iR + (iL + iR - i) / 15;
    return integral(l, mid, eps / 2, iL) + integral(mid, r, eps / 2, iR);
}

inline void init(double res = 0) {
    sort(tri + 1, tri + n + 1);
    sort(posX.begin(), posX.end());
    auto edIt = unique(posX.begin(), posX.end());
    for (auto it = posX.begin() + 1; it != edIt; it++) {
        double l = *(it - 1), r = *(it);
        chosen.clear();
        for (int i = 1; i <= n; i++) {
            if ((tri[i].x1 <= l && l <= tri[i].x2) ||
                (tri[i].x1 <= r && r <= tri[i].x2)) {
                chosen.push_back(i);
            }
        }
        l += 2e-9, r -= 2e-9;
        res += integral(l, r, 1e-4, simpson(l, r));
    }
    cout << setprecision(1) << fixed << res << endl;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 1, x, y, m; i <= n; i++) {
        cin >> x >> y >> m;
        tri[i].x1 = x, tri[i].y1 = y + m;
        tri[i].x2 = x + m, tri[i].y2 = y;
        posX.push_back(x), posX.push_back(x + m);
    }
    init();
    return 0;
}
