зәҝж®өзұ»(жһҒи§’жҺ’еәҸпјҢеҜ№еә”зӣҙзәҝзҡ„дәӨзӮ№)
```cpp зәҝж®өзұ»
struct Seg {  //зәҝж®өзұ» иө·зӮ№s, з»ҲзӮ№t
    Seg() = default;
    Seg(Vec2 _s, Vec2 _t) : s(_s), t(_t) { theta = atan2((t - s).y, (t - s).x); }
    /*comparison of two Seg @return bool*/
    friend inline bool operator<(const Seg& a, const Seg& b) {//жҜ”иҫғжһҒи§’
        // theta1 != theta2 жҢүthetaжҺ’еәҸ
        if (abs(a.theta - b.theta) > EPS) return a.theta < b.theta;
        // theta1 == theta2 еҲӨж–ӯеҗ‘йҮҸaеңЁbзҡ„е“Әиҫ№пјҢд»ӨжңҖйқ е·Ұзҡ„жҺ’еңЁжңҖе·Ұиҫ№
        return (b.s - a.s) * (b.t - a.s) > EPS;
    }
    /*intersection of two Seg @return Vec2(x, y)*/
    inline friend Vec2 intersect(const Seg& a, const Seg& b) {
        double ratio = ((b.t - b.s) * (a.s - b.s)) / ((a.t - a.s) * (b.t - b.s));
        return a.s + (a.t - a.s) * ratio;
    }
    /*@param s иө·зӮ№ @param t з»ҲзӮ№*/
    Vec2 s, t;
    /*@param theta жһҒи§’*/
    double theta = 1e9;
} seg[MAXN], q[MAXN]/*deque йҳҹеҲ—дёӯеӯҳж”ҫзәҝж®ө*/;
