//жұӮеҗ‘йҮҸе·Ұдҫ§зҡ„еҚҠе№ійқўдәӨ 
//йҳҹеҲ—дёӯзәҝж®өиҢғеӣҙ (l, r]пјҢиӢҘеҚҠе№ійқўдәӨдёҚй—ӯеҗҲпјҢеҲҷиҢғеӣҙдёә (l, r)
//з¬¬дёҖдёӘдәӨзӮ№жҳҜ its[l + 2]пјҢеӣ дёә seg[l + 2] дёәз¬¬дәҢжқЎзәҝж®ө
inline void halfPlaneIntersection() {
    sort(seg + 1, seg + tot + 1);
    int l = 0, r = 0;
    for (int i = 1; i <= tot; i++) {
        if (abs(seg[i].theta - seg[i - 1].theta) > EPS) {
            while (r - l > 1 && (seg[i].t - its[r]) * (seg[i].s - its[r]) > EPS)
                --r;
            while (r - l > 1 && (seg[i].t - its[l + 2]) * (seg[i].s - its[l + 2]) > EPS)
                ++l;
            q[++r] = seg[i];
            if (r - l > 1) its[r] = intersect(q[r], q[r - 1]); //жұӮж–°дәӨзӮ№
        }
    }
    while (r - l > 1 && (q[l + 1].t - its[r]) * (q[l + 1].s - its[r]) > EPS)
        --r; //еҲ йҷӨеӨҡдҪҷе…ғзҙ 
    its[r + 1] = intersect(q[l + 1], q[r]), ++r; //з»ҲзӮ№зәҝж®өдёҺиө·зӮ№зәҝж®өзӣёдәӨ

    double ans(0);
    for (int i = l + 2; i < r; i++) { // l + 2 жҳҜиө·е§ӢдәӨзӮ№ дёүи§’еү–еҲҶжұӮйқўз§Ҝ
        ans += (its[i] * its[i + 1]) / 2;
    }
    ans += (its[r] * its[l + 2]) / 2;
    cout << setprecision(3) << fixed << ans << endl;
}
```

