# E Logs
## Description
жңү $N$ дёӘжңЁеӨҙпјҢзҺ°йңҖиҰҒе°ҶиҝҷдәӣжңЁеӨҙз Қ $K$ ж¬Ў(и®ҫйҖүеҸ–зҡ„жңЁеӨҙй•ҝеәҰдёәLпјҢеҲҷз ҚдәҶд№ӢеҗҺеҫ—еҲ°й•ҝеәҰдёә $t$ ($0 < t < L$), $L - t$ зҡ„жңЁеӨҙпјҢз ҚдәҶд№ӢеҗҺзҡ„жңЁеӨҙиҝҳиғҪз»§з»ӯз Қ)пјҢжұӮ $K$ ж¬Ўж“ҚдҪңеҗҺиҝҷдәӣжңЁеӨҙдёӯжңҖеӨ§й•ҝеәҰзҡ„жңҖе°ҸеҖј(еҗ‘дёҠеҸ–ж•ҙ)гҖӮ
## Solution
дәҢеҲҶжңЁеӨҙжңҖеӨ§й•ҝеәҰзҡ„жңҖе°ҸеҖј $mid$пјҢе№¶ $check$ жҠҠжүҖжңүжңЁеӨҙеҲҶдёәй•ҝеәҰ $l \le\ mid$ зҡ„жңЁеӨҙжүҖйңҖиҰҒзҡ„ж¬Ўж•°пјҢдёҺ $k$ жҜ”иҫғеҚіеҸҜгҖӮ
жіЁж„ҸжңЁеӨҙзҡ„жңҖе°Ҹй•ҝеәҰеә”еҸ– 1 иҖҢдёҚжҳҜ 0гҖӮ
## Code
```cpp Logs
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 3e5 + 5;

array<int, MAXN> a;

int n, k;

inline bool check(int mid) {
    int cnt(0);
    for (int i = 1; i <= n; i++) {
        if (a[i] % mid == 0) cnt += a[i] / mid - 1;
        else cnt += a[i] / mid;
    }
    return cnt <= k; //
}

signed main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 1; i <= n; i++) cin >> a[i];
    int l = 1, r = 2e9, ans = 0;
    while (l <= r) {
        int mid = (l + r) >> 1;
        if (check(mid)) {
            ans = mid, r = mid - 1;
        } else l = mid + 1;
    }
    cout << ans << endl;
    return 0;
}
```

# F Range Set Query
## Description
з»ҷе®ҡдёҖдёӘеәҸеҲ—пјҢеӨҡж¬ЎиҜўй—®еҢәй—ҙ $[l_i, r_i]$ дёҚеҗҢж•°еӯ—зҡ„дёӘж•°гҖӮ
## Solution
- и®°еҪ• $a_i$ еүҚдёҖж¬ЎеҮәзҺ°зҡ„дҪҚзҪ® $pre[a_i]$(иӢҘ $a_i$ з¬¬дёҖж¬ЎеҮәзҺ°еҲҷдёә 0)
- еҜ№дәҺеҢәй—ҙ $[l, r]$пјҢеҰӮжһңеҢәй—ҙзҡ„дёҖдёӘж•° $per[a_i] \le l$пјҢеҲҷиҜҘж•°еңЁеҢәй—ҙеҶ…з¬¬дёҖж¬ЎеҮәзҺ°пјҢеҸҜи®Ўе…Ҙзӯ”жЎҲ
- дәҺжҳҜд»ҘдёӢж ҮдёәеҖјеҹҹпјҢе»әз«ӢеҸҜжҢҒд№…еҢ–иҮідәҺзәҝж®өж ‘гҖӮжҜҸдёӘзүҲжң¬еңЁ $pre[a_i]$ дҪҚзҪ®жқғеҖјеҠ  1пјҢжңҖеҗҺз»ҹи®Ў $[0, l_i - 1]$ зҡ„жқғеҖјжҖ»е’ҢеҚіеҸҜ

## Code
```cpp Range Set Query
#include <bits/stdc++.h>

constexpr int MAXN = 5e5 + 5;
constexpr int MAXA = 5e5 + 6;
constexpr int LOG = 30;
using namespace std;

inline int read() {
    int x = 0, f = 1;
    char ch = getchar();
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = (x << 3) + (x << 1) + ch - 48, ch = getchar();
    return x * f;
}

struct Node {
    Node *lson, *rson;
    int cnt;
} Tree[MAXN * LOG], *root[MAXN];
int tot, n, m, cnt, arr[MAXN], pre[MAXA], last[MAXN];

inline Node *newNode(Node *&root) { return root = &Tree[tot++]; }

inline void build(int L, int R, Node *root) {
    if (L == R) return;
    int mid = (L + R) >> 1;
    build(L, mid, newNode(root->lson)), build(mid + 1, R, newNode(root->rson));
}

inline void modify(Node *pre, Node *cur, int L, int R, int pos) {
    cur->cnt = pre->cnt;
    if (L == R) {
        cur->cnt++;
        return;
    }
    int mid = (L + R) >> 1;
    if (pos <= mid)
        cur->rson = pre->rson,
        modify(pre->lson, newNode(cur->lson), L, mid, pos);
    else
        cur->lson = pre->lson,
        modify(pre->rson, newNode(cur->rson), mid + 1, R, pos);
    cur->cnt = cur->lson->cnt + cur->rson->cnt;
}

inline int query2(Node *pre, Node *cur, int L, int R, int qL, int qR) {
    if (qL == L && R == qR) return cur->cnt - pre->cnt;
    int mid = (L + R) >> 1;
    if (qR <= mid)
        return query2(pre->lson, cur->lson, L, mid, qL, qR);
    else if (qL > mid)
        return query2(pre->rson, cur->rson, mid + 1, R, qL, qR);
    else
        return query2(pre->lson, cur->lson, L, mid, qL, mid) +
               query2(pre->rson, cur->rson, mid + 1, R, mid + 1, qR);
}

int main() {
    n = read(), m = read();
    build(0, n, newNode(root[0]));
    for (int i = 1; i <= n; i++) {
        arr[i] = read(), last[i] = pre[arr[i]], pre[arr[i]] = i;
        modify(root[i - 1], newNode(root[i]), 0, n, last[i]);
    }
    while (m--) {
        int l = read(), r = read();
        printf("%d\n", query2(root[l - 1], root[r], 0, n, 0, l - 1));
    }
    return 0;
}

```

