## Solution
е…ҲдёҚиҖғиҷ‘ $\forall i \in[1,N], A_i \neq B_i$ иҝҷдёҖжқЎд»¶пјҢйӮЈд№ҲжҖ»е…ұзҡ„ж–№жЎҲж•°дёә $(A_M^N)^2$гҖӮ

жҺҘдёӢжқҘеҸӘйңҖиҰҒеҺ»йҷӨдҪҝ $A,B$ ж•°з»„дёӯжҹҗеҮ дҪҚзӣёеҗҢзҡ„ж–№жЎҲгҖӮи®ҫ $P_i$ иЎЁзӨәдәӢд»¶: $A_i = B_i$гҖӮйӮЈд№ҲдёҚеҗҲжі•зҡ„ж–№жЎҲжһ„жҲҗзҡ„йӣҶеҗҲдёә $P_1\cup P_2 \cup ...\cup P_n$гҖӮз”ұе®№ж–ҘеҺҹзҗҶжңү $|P_1\cup P_2 \cup ...\cup P_n|=\sum\limits_{1<=i<=n}|P_i|-\sum\limits_{1<=i<j<=n}|P_i\cap P_j|$
$+\sum\limits_{1<=i<j<k<=n}|P_i\cap P_j\cap P_k|-...+(-1)^{n-1}|P_1\cap P_2 \cap ...\cap P_n|$гҖӮ

и®ҫдёҖдёӢж ҮйӣҶеҗҲ $S$пјҢйӣҶеҗҲеӨ§е°Ҹдёә $|S|$пјҢеҲҷе®ғеҜ№еә”зҡ„ж»Ўи¶і $\forall i \in S, A_i = B_i$зҡ„ $A,B$ж•°з»„ жңү$A_M^{|S|}(A_{M-|S|}^{N-|S|})^2$ еҜ№ ($|S|$дҪҚзӣёеҗҢеҜ№еә”$A_M^{|S|}$пјҢеү©дёӢ$N-|S|$дҪҚд»Һеү©дёӢ$M-|S|$дёӘж•°дёӯд»»еҸ–)гҖӮ
ж №жҚ®е®№ж–ҘеҺҹзҗҶ,иҝҷдёҖйӣҶеҗҲеҜ№дёҚеҗҲжі•ж–№жЎҲзҡ„иҙЎзҢ®дёә $(-1)^{|S|-1}A_M^{|S|}(A_{M-|S|}^{N-|S|})^2$гҖӮжҳҫз„¶пјҢиҝҷж ·зҡ„йӣҶеҗҲжңү$C_N^{|S|}$дёӘгҖӮдәҺжҳҜжүҖжңүеӨ§е°Ҹдёә $|S|$ зҡ„йӣҶеҗҲзҡ„иҙЎзҢ®дёә
  $C_N^{|S|}(-1)^{|S|-1}A_M^{|S|}(A_{M-|S|}^{N-|S|})^2$гҖӮе°ҶжүҖжңүеӨ§е°Ҹзҡ„йӣҶеҗҲзҡ„иҙЎзҢ®зҙҜеҠ еҚіеҸҜеҫ—еҲ°дёҚеҗҲжі•зҡ„ж–№жЎҲж•°, жҠҠе®ғд»ҺжҖ»зҡ„ж–№жЎҲж•°дёӯеҮҸеҺ»еҚіеҸҜгҖӮ
## Code
```cpp
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;
const int MOD = 1e9 + 7;
const int maxn = 5e5 + 5;
int n, m;
ll inv[maxn], fac[maxn], ans;

ll qpow(ll a, ll b) {
    ll ans = 1, base = a;
    while (b) {
        if (b & 1) ans = ans * base % MOD;
        b >>= 1, base = base * base % MOD;
    }
    return ans;
}

void init() {
    fac[0] = 1;
    for (int i = 1; i <= m; i++) fac[i] = fac[i - 1] * i % MOD;
    for (int i = 0; i <= m; i++) inv[i] = qpow(fac[i], MOD - 2);
}

ll A(ll a, ll b) { return fac[a] * inv[a - b] % MOD; }

ll C(ll a, ll b) { return fac[a] * inv[b] % MOD * inv[a - b] % MOD; }

int main() {
    cin >> n >> m;
    init();
    ans = qpow(A(m, n), 2);
    for (int s = 1; s <= n; s++) {
        ans -= (s & 1 ? 1 : -1) * C(n, s) * A(m, s) % MOD *
               qpow(A(m - s, n - s), 2) % MOD;
        ans %= MOD;
    }
    cout << (ans + MOD) % MOD;
    return 0;
}
```

