## Solution
иҰҒеҒҡжң¬йўҳйҰ–е…ҲиҰҒзӣҙеҲ°иҝҷдёӘз»“и®әпјҡеҗҺеҮәжүӢзҡ„дәәжңүеҝ…иғңзӯ–з•ҘеҪ“дё”д»…еҪ“ $A_1вҠ•A_2вҠ•...вҠ•A_N=0$

и®ҫд»Һз¬¬дёҖе Ҷз§»еҠЁзҹіеӯҗж•°дёә $x(0<=x<A_1)$пјҢд»Ө $a=A_1-x,b=A_2+x$пјҢе…¶дёӯ$1<=a<=A_1$пјҢйӮЈд№Ҳжңү $a+b=A_1+A_2 =S,aвҠ•b=A_3вҠ•A_4вҠ•...вҠ•A_N=X$гҖӮйўҳзӣ®иҰҒжұӮжңҖе°Ҹзҡ„ $x$пјҢеҚіжұӮжңҖеӨ§зҡ„ $a$пјҢдҪҝеүҚйқўдёӨдёӘејҸеӯҗжҲҗз«ӢгҖӮ

з”ұдәҺ $a+b=aвҠ•b+2*(a\&b)$ ($aвҠ•b$ еҸҜи§ҶдёәдёҚиҝӣдҪҚзҡ„еҠ жі•пјҢеҠ дёҠ $(a \& b)<<1$ еҚіе°ҶиҝӣдҪҚеҠ дёҠ)пјҢеҸҜд»Ҙеҫ—еҮә $(a\&b)=(S-X)/2=D$гҖӮеҰӮжһң $S-X$ дёҚжҳҜеҒ¶ж•°пјҢ$D$ е°ҸдәҺ0пјҢжҲ–иҖ… $D$ дёҺ $X$ еңЁдәҢиҝӣеҲ¶дёӢжҹҗдёҖдҪҚеҗҢдёә 1 ($a\&b$ еңЁжҹҗдёҖдҪҚдёә 1 д»…еҪ“ $a,b$ еңЁиҝҷдёҖдҪҚеҗҢдёә 1пјҢиҖҢжӯӨж—¶$aвҠ•b$ еңЁиҝҷдёҖдҪҚзҡ„з»“жһңеә”дёә 0)пјҢжң¬йўҳж— и§ЈгҖӮ

е°Ҷ $X$ еңЁдәҢиҝӣеҲ¶дёӢжӢҶеҲҶжҲҗдёӨдёӘж•° $Y,Z$пјҢж»Ўи¶і$Y\&Z=0,YвҠ•Z=X$,еҚі $X$ жҹҗдёҖдҪҚдёә 1 ж—¶пјҢ$Y,Z$ еңЁиҝҷдёҖдҪҚдёҚеҗҢж—¶дёә1гҖӮеҸҜд»Ҙи§ЈеҮә $a=DвҠ•Y,b=DвҠ•Z$,еҸҜд»ҘиҜҒжҳҺж— е…¶е®ғеҪўејҸзҡ„и§ЈгҖӮж №жҚ®еүҚйқўзҡ„з»“и®әпјҢ$D$ дёҺ $Y$ дёҚеӯҳеңЁжҹҗдёҖдҪҚеҗҢдёә 1 зҡ„жғ…еҶөпјҢжүҖд»Ҙ $DвҠ•Y\ge D$пјҢеӣ жӯӨ $a$ зҡ„жңҖе°ҸеҖјдёә $D$гҖӮеҰӮжһң $D > A_1$ еҲҷжң¬йўҳж— и§ЈгҖӮжҺҘдёӢжқҘд»Һй«ҳдҪҚеҲ°дҪҺдҪҚиҖғеҜҹ $X$ дәҢиҝӣеҲ¶дёӢзҡ„жҜҸдёҖдҪҚпјҢеҰӮжһңиҝҷдёҖдҪҚдёә 1пјҢе°қиҜ•е°ҶиҝҷдёҖдҪҚеҠ еҲ° $a$ дёӯпјҢзңӢеҫ—еҲ°зҡ„з»“жһңжҳҜеҗҰеӨ§дәҺ $A_1$, еҰӮжһңеӨ§дәҺеҲҷдёҚиғҪеҠ дёҠиҝҷдёҖдҪҚгҖӮжңҖеҗҺпјҢиӢҘ $a=0$пјҢеҚі$x=A_1$пјҢжң¬йўҳж— и§ЈгҖӮеҗҰеҲҷпјҢиҫ“еҮә $A_1-a$ еҚідёәз§»еҠЁзҹіеӯҗзҡ„жңҖе°Ҹж•°йҮҸгҖӮ
## Code
```cpp
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;
int N;
ll A1, A2, A, ans, X;

bool check(ll a, ll b) {
    for (int i = 41; ~i; i--) {
        int ai = (a >> i) & 1;
        int bi = (b >> i) & 1;
        if (ai == 1 && bi == 1) return false;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> N;
    cin >> A1 >> A2;
    ll S = A1 + A2;
    for (int i = 3; i <= N; i++) cin >> A, X ^= A;
    ll D = (S - X) >> 1;
    if (((S - X) & 1) || D < 0 || D > A1 || !check(D, X)) cout << -1, exit(0);
    ans = D;
    for (int i = 41; ~i; i--) {
        bool Xi = (X >> i) & 1;
        if (Xi && ((ans | (1ll << i)) <= A1)) ans |= 1ll << i;
    }
    cout << (ans ? A1 - ans : -1);
    return 0;
}
```

