# Solution
иҰҒж»Ўи¶іжҜҸдёӘж јеӯҗйғҪиғҪиў«е…ұеҮ»пјҢйӮЈд№Ҳе°ұиҰҒдҪҝжҜҸдёҖиЎҢйғҪжңүиҪҰпјҢжҲ–иҖ…жҜҸдёҖеҲ—йғҪжңүиҪҰгҖӮд»ҘжҜҸдёҖиЎҢйғҪжңүиҪҰдёәдҫӢпјҢи®ҫжңү $j$ еҲ—ж”ҫдәҶиҪҰгҖӮз”ұдәҺжҜҸеӨҡдёҖеҲ—пјҢиғҪзӣёдә’е…ұеҮ»зҡ„иҪҰзҡ„еҜ№ж•°е°ұдјҡеҮҸ 1пјҢеӣ жӯӨж”ҫ $j$ еҲ—иҪҰе°ұжңү $n-j$ еҜ№иҪҰиғҪзӣёдә’е…ұеҮ»гҖӮйўҳзӣ®иҰҒжұӮ $k$ еҜ№иҪҰиғҪзӣёдә’е…ұеҮ»пјҢйӮЈд№ҲеҸӘиғҪеңЁ $n-k$ еҲ—ж”ҫзҪ®иҪҰ (жҳҫз„¶ $k\geqslant\ n$ж—¶зӯ”жЎҲдёә 0)гҖӮд»Һ $n$ еҲ—йҖүеҸ– $n-k$ еҲ—зҡ„ж–№жЎҲж•°дёә $C_n^{n-k}$гҖӮжҺҘдёӢжқҘиҖғиҷ‘еңЁ $n-k$ еҲ—дёӯж”ҫе…Ҙ $n$ дёӘиҪҰпјҢжҜҸеҲ—дёҚз©әзҡ„ж–№жЎҲж•°гҖӮ

д»Ө $P_i$ иЎЁзӨәдәӢд»¶: еңЁиҝҷ $n-k$ еҲ—дёӯз¬¬ $i$ еҲ—жІЎжңүж”ҫиҪҰгҖӮз”ұе®№ж–ҘеҺҹзҗҶжңү $|\overline{P_1} \cap \overline{P_2} \cap ...\cap \overline{P_{n-k}}|= N-\sum\limits_{1<=i<={n-k}}|P_i|+\sum\limits_{1<=i<j<={n-k}}|P_i\cap P_j|$ $-\sum\limits_{1<=i<j<q<={n-k}}|P_i\cap P_j\cap P_q|+...+(-1)^{n-k}|P_1\cap P_2 \cap ...\cap P_{n-k}|$гҖӮ

и®ҫдёҖ**еҲ—дёӢж ҮйӣҶеҗҲ** $S$пјҢеӨ§е°Ҹдёә$|S|(|S|<=n-k)$пјҢиҝҷж ·зҡ„йӣҶеҗҲжңү$C_{n-k}^{|S|}$дёӘгҖӮеҲҷж»Ўи¶і $\forall i \in S$пјҢз¬¬ $i$ еҲ—жІЎжңүж”ҫиҪҰзҡ„ж–№жЎҲж•°дёә $(n-k-|S|)^n$пјҢеҚі $n$ дёӘиҪҰж”ҫеңЁеү©дёӢ $n-k-|S|$ еҲ—зҡ„д»»ж„ҸдёҖдёӘдёӯзҡ„ж–№жЎҲж•°гҖӮж №жҚ®еүҚйқўзҡ„е…¬ејҸпјҢе®№жҳ“еҫ—еҮәжҜҸдёҖиЎҢйғҪжңүиҪҰдё”ж»Ўи¶ійўҳзӣ®жқЎд»¶зҡ„ж–№жЎҲж•°дёә $C_n^{n-k}\sum\limits_{i=0}^{n-k}(-1)^iC_{n-k}^{i}(n-k-i)^n$гҖӮеҰӮжһң $k$ дёҚзӯүдәҺ 0пјҢеҲҷжҜҸдёҖиЎҢйғҪжңүиҪҰе’ҢжҜҸдёҖеҲ—йғҪжңүиҪҰдёҚзӯүд»·пјҢжҖ»зҡ„зӯ”жЎҲеә”иҜҘд№ҳд»Ҙ 2пјҢеҚі $2C_n^{n-k}\sum\limits_{i=0}^{n-k}(-1)^iC_{n-k}^{i}(n-k-i)^n$гҖӮ

# Code
```cpp
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;
const int MOD = 998244353;
const int maxn = 2e5 + 5;
ll n, k, inv[maxn], fac[maxn], ans;

ll qpow(ll a, ll b) {
    ll ans = 1, base = a;
    while (b) {
        if (b & 1) ans = ans * base % MOD;
        b >>= 1, base = base * base % MOD;
    }
    return ans;
}

void init() {
    fac[0] = 1;
    for (int i = 1; i <= n; i++) fac[i] = fac[i - 1] * i % MOD;
    for (int i = 0; i <= n; i++) inv[i] = qpow(fac[i], MOD - 2);
}

ll C(ll a, ll b) { return fac[a] * inv[b] % MOD * inv[a - b] % MOD; }

int main() {
    cin >> n >> k;
    if (k >= n) cout << 0, exit(0);
    init();
    for (int s = 0; s <= n - k; s++) {
        ans += (s & 1 ? -1 : 1) * C(n - k, s) * qpow(n - k - s, n) % MOD;
        ans %= MOD;
    }
    ans = ans * (!k ? 1 : 2) * C(n, n - k) % MOD;
    cout << (ans + MOD) % MOD;
    return 0;
}
```

