## A дәҺжҳҜд»–й”ҷиҜҜзҡ„зӮ№еҗҚејҖе§ӢдәҶ
### Description
[P2580 дәҺжҳҜд»–й”ҷиҜҜзҡ„зӮ№еҗҚејҖе§ӢдәҶ](https://www.luogu.com.cn/problem/P2580)
### Solution
йҰ–е…ҲжҠҠз»ҷеҮәзҡ„ $n$ дёӘеӯ—з¬ҰдёІжҸ’е…Ҙ $trie$ ж ‘дёӯгҖӮд№ӢеҗҺиҜўй—®ж—¶пјҢеҰӮжһңз»ҷеҮәзҡ„еӯ—з¬ҰдёІеңЁ $trie$ ж ‘дёӯдёҚеӯҳеңЁпјҢеҗҰеҲҷеңЁеӯ—з¬ҰдёІжң«е°ҫеҜ№еә”иҠӮзӮ№жү“дёҠж Үи®°пјҢеҰӮжһңиҝҷдёӘзӮ№д№ӢеүҚе·Із»Ҹиў«жү“иҝҮж Үи®°пјҢиҜҙжҳҺиҝҷдёӘеӯ—з¬ҰдёІеңЁд№ӢеүҚе·Із»Ҹиў«иҜўй—®иҝҮдәҶгҖӮ
### Code
```cpp дәҺжҳҜд»–й”ҷиҜҜзҡ„зӮ№еҗҚејҖе§ӢдәҶ
#include <bits/stdc++.h>

using namespace std;

struct trie {
    trie *son[26];
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        tag = 0;
    }
    bool tag;
};

trie *root = new trie;
int n, m;
string s;

void insert(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - 'a';
        if (cur->son[temp] == NULL) cur->son[temp] = new trie;
        cur = cur->son[temp];
    }
}

int search(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - 'a';
        if (cur->son[temp] == NULL) return 0;
        cur = cur->son[temp];
        if (i == s.size() - 1) {
            if (!cur->tag)
                return cur->tag = 1, 1;
            else
                return 2;
        }
    }
}

int main() {
    cin >> n;
    while (n--) cin >> s, insert(s);
    cin >> m;
    while (m--) {
        cin >> s;
        int now = search(s);
        if (now == 0)
            cout << "WRONG" << endl;
        else if (now == 1)
            cout << "OK" << endl;
        else
            cout << "REPEAT" << endl;
    }
    return 0;
}
```
