### Code
```cpp
#include <bits/stdc++.h>

using namespace std;

struct trie {
    trie *son[10];
    trie() {
        for (int i = 0; i < 10; i++) son[i] = NULL;
        visTag = isEnd = 0;
    }
    bool visTag, isEnd;
} * root;

int n, T;
bool ans;
string s;

void insert(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - '0';
        if (cur->son[temp] == NULL) cur->son[temp] = new trie;
        cur = cur->son[temp];
        if (cur->isEnd) {
            ans = 0;
            break;
        }
        if (i == s.size() - 1) {
            cur->isEnd = 1;
            if (cur->visTag) ans = 0;
        }
        cur->visTag = 1;
    }
}

void trie_delete(trie *cur) {
    for (int i = 0; i < 10; i++)
        if (cur->son[i]) trie_delete(cur->son[i]);
    delete cur;
}

int main() {
    cin >> T;
    while (T--) {
        root = new trie;
        ans = 1;
        cin >> n;
        for (int i = 1; i <= n; i++) cin >> s, insert(s);
        puts(ans ? "YES" : "NO");
        trie_delete(root);
    }
    return 0;
}
```

