$log_2(S)$гҖӮ

жіЁпјҡз”ЁжҢҮй’ҲзүҲ $trie$ ж ‘зӣҙжҺҘ $new$ зҡ„иҜқеёёж•°иҫғеӨ§пјҢдјҡиў«еҚЎгҖӮеҸҜд»ҘиҮӘе·ұжүӢеҶҷ$newNode$ еҮҪж•°пјҢжҲ–иҖ…ж”№з”Ёж•°з»„зүҲгҖӮ
### Code
```cpp Xor Sum
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;
const int BIT = 32;

struct trie {
    int son[2];
    trie() { son[0] = son[1] = -1; }
} trie[16000000];

int root = 0;
int n, m;

ll read() {
    char ch = getchar();
    ll x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(ll val) {
    static int tot;
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
}

void query(ll val) {
    int cur = root;
    ll ans = 0;
    for (int i = BIT; ~i; i--) {
        ll now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1)
            ans |= (now ^ 1) << i, cur = trie[cur].son[now ^ 1];
        else
            ans |= now << i, cur = trie[cur].son[now];
    }
    printf("%lld\n", ans);
}

int main() {
    n = read(), m = read();
    for (int i = 1; i <= n; i++) insert(read());
    for (int i = 1; i <= m; i++) query(read());
    return 0;
}
```
## B Chip Factory
### Description
[HDU 5536 - Chip Factory](https://www.luogu.com.cn/problem/U109897)
### Solution
еҒҡжі•е’ҢдёҠдёҖйҒ“зұ»дјјгҖӮе…ҲжҠҠз»ҷеҮәзҡ„ $n$ дёӘж•°жҸ’е…Ҙ $trie$ ж ‘пјҢз„¶еҗҺжһҡдёҫ $i$ е’Ң $j$пјҢжҠҠ $s[i] + s[j]$ ж”ҫеҲ° $trie$ ж ‘дёҠиҙӘеҝғең°жҹҘиҜўеҚіеҸҜ,еҚ•ж¬ЎжҹҘиҜўеӨҚжқӮеәҰдёә $log_2(s)$гҖӮйңҖиҰҒжіЁж„Ҹзҡ„жҳҜпјҢйўҳзӣ®иҰҒжұӮ $i,j,k$ дә’дёҚзӣёеҗҢпјҢеӣ жӯӨйҖүдәҶ $s[i],s[j]$ еҗҺпјҢеә”е°Ҷе®ғд»¬д»Һ $trie$ ж ‘дёҠеҲ йҷӨгҖӮе…·дҪ“зҡ„пјҢжҜҸдёӘиҠӮзӮ№и®°дёҖдёӘ $cnt$пјҢ еҲ йҷӨзҡ„ж—¶еҖҷи®© $cnt-1$ пјҢжҹҘиҜўж—¶еҰӮжһңиҜҘиҠӮзӮ№ $cnt$ дёә 0 иҜҙжҳҺе·Іиў«еҲ йҷӨпјҢеҲҷдёҚиғҪйҖүиҝҷдёӘиҠӮзӮ№гҖӮеҚ•ж¬ЎжҹҘиҜўз»“жқҹеҗҺеҶҚжҠҠ  $s[i],s[j]$ жҸ’е…Ҙ $trie$ ж ‘еҚіеҸҜпјҢиҝҷж ·дёҚеҪұе“Қд№ӢеҗҺзҡ„жҹҘиҜўгҖӮ
### Code
```cpp Chip Factory
#include <bits/stdc++.h>

using namespace std;

int n, a[1001], mx = 0;
const int BIT = 31;

struct trie {
    int son[2];
    int cnt;
    trie() {
        son[0] = son[1] = -1;
        cnt = 0;
    }
} trie[1001 * (BIT + 1)];
int root = 0;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(int val) {
    static int tot;
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
        trie[cur].cnt++;
    }
}

void trie_delete(int val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        cur = trie[cur].son[now];
        trie[cur].cnt--;
    }
}

void trie_add(int val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        cur = trie[cur].son[now];
        trie[cur].cnt++;
    }
}

void query(int val, int x, int y) {
    trie_delete(a[x]), trie_delete(a[y]);
    int cur = root;
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1 && trie[trie[cur].son[now ^ 1]].cnt)
            ans |= 1 << i, cur = trie[cur].son[now ^ 1];
        else if (trie[trie[cur].son[now]].cnt)
            cur = trie[cur].son[now];
        else
            return;
    }
    trie_add(a[x]), trie_add(a[y]);
    mx = max(mx, ans);
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) a[i] = read();
    for (int i = 1; i <= n; i++) insert(a[i]);
    for (int i = 1; i <= n; i++)
        for (int j = i + 1; j <= n; j++) query(a[i] + a[j], i, j);
    cout << mx;
    return 0;
}
```
## C Nikitosh and xor
### Description
[Codechef REBXOR - Nikitosh and xor](https://www.luogu.com.cn/problem/U109923)
### Solution
и®° $preMx[i]$ иЎЁзӨәд»Һ $1$ еҲ° $i$ зҡ„жңҖеӨ§иҝһз»ӯзүҮж®өејӮжҲ–е’ҢпјҢ$posMx[i]$ иЎЁзӨәд»Һ $i$ еҲ° $n$ зҡ„жңҖеӨ§иҝһз»ӯзүҮж®өејӮжҲ–е’ҢгҖӮжҳҫз„¶пјҢзӯ”жЎҲдёә $\max\limits_{0<i<n}(preMx[i]+posMx[i+1])$гҖӮжҺҘдёӢжқҘеҸӘйңҖиҰҒйў„еӨ„зҗҶеҮә $preMx[i]$ е’Ң $posMx[i]$ еҚіеҸҜгҖӮ
и®° $preXor[i]$ иЎЁзӨә $1$ еҲ° $i$ зҡ„еүҚзјҖејӮжҲ–е’ҢгҖӮеҗҢж—¶и®ҫ $preXor[k](0<=k <i)$ е·Іи®Ўз®—еҮәпјҢе№¶дё”е·Іиў«жҸ’е…Ҙ $trie$ дёӯ, йӮЈд№Ҳж №жҚ®ејӮжҲ–иҝҗз®—зҡ„жҖ§иҙЁпјҢжңү $preMx[i]=\max\limits_{0<=k<i}(preMx[i-1], preXor[i]вҠ•preXor[k])$пјҢиҖҢ$\max\limits_{0<=k<i}(preXor[i]вҠ•preXor[k])$ еҸҜд»ҘеңЁ $trie$ ж ‘дёҠпјҢеңЁ $log_2(a)$зҡ„ж—¶й—ҙеҶ…иҙӘеҝғең°жұӮеҮәгҖӮеҗҢж ·зҡ„пјҢе®№жҳ“жұӮеҮә $posMx[i]$гҖӮ
### Code
```cpp Nikitosh and xor
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;
const int BIT = 31;
const int maxn = 400005;
int n, a[maxn], tot;
ll preXor = 0, posXor = 0, preMx[maxn], posMx[maxn];
ll ans = 0;

struct trie {
    int son[2];
    trie() { son[0] = son[1] = -1; }
} trie[maxn * BIT * 2];
int root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(ll val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
}

ll query(ll val) {
    int cur = root;
    ll ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1)
            ans |= 1ll << i, cur = trie[cur].son[now ^ 1];
        else
            cur = trie[cur].son[now];
    }
    return ans;
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) a[i] = read();

    insert(0);
    for (int i = 1; i <= n; i++) {
        preXor ^= a[i];
        insert(preXor);
        preMx[i] = max(preMx[i - 1], query(preXor));
    }
    for (int i = 0; i <= tot; i++) trie[i].son[0] = trie[i].son[1] = -1;
    tot = 0;

    insert(0);
    for (int i = n; i >= 1; i--) {
        posXor ^= a[i];
        insert(posXor);
        posMx[i] = max(posMx[i + 1], query(posXor));
    }
    for (int i = 1; i <= n - 1; i++) ans = max(ans, posMx[i + 1] + preMx[i]);
    cout << ans;
    return 0;
}
```
## D жңҖй•ҝејӮжҲ–и·Ҝеҫ„
### Descritiption
[P4551 жңҖй•ҝејӮжҲ–и·Ҝеҫ„](https://www.luogu.com.cn/problem/P4551)
### Solution
йҰ–е…Ҳ $dfs$ жұӮеҮәжҜҸдёӘзӮ№ $i$ еҲ°ж №иҠӮзӮ№и·Ҝеҫ„дёҠзҡ„ејӮжҲ–е’ҢпјҢи®°дёә Xor[i]гҖӮжҳҫз„¶пјҢзӯ”жЎҲдёә $\max\limits_{1<=u<=n}( \max\limits_{1<=v<=n}(Xor[u]вҠ•Xor[v]))$гҖӮеҜ№дәҺд»»ж„ҸиҠӮзӮ№ $u$пјҢе®ғе’Ңе…¶е®ғиҠӮзӮ№зҡ„жңҖеӨ§ејӮжҲ–еҖјеҸҜд»ҘеңЁ $trie$ ж ‘дёҠеңЁ $log_2(w)$ зҡ„ж—¶й—ҙеҶ…иҙӘеҝғең°жұӮеҫ—гҖӮ

### Code
```cpp жңҖй•ҝејӮжҲ–и·Ҝеҫ„
#include <bits/stdc++.h>

using namespace std;

const int maxn = 100005;
const int BIT = 30;

int p[maxn], XOR[maxn];
int n, u, v, w, ans;
bool vis[maxn];

struct trie {
    trie *son[2];
    int val;
    trie() { son[0] = son[1] = NULL; }
} * root;

struct edge {
    int nxt, to, val;
} e[maxn * 2];

template <class T>
void read(T &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void add(int from, int to, int val) {
    static int t;
    e[t].to = to, e[t].val = val, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, int val) {
    XOR[now] = val, vis[now] = 1;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!vis[to]) dfs(to, val ^ e[i].val);
    }
}

void insert(int val) {
    trie *cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
    }
}

int query(int val) {
    trie *cur = root;
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now ^ 1] != NULL)
            ans |= 1 << i, cur = cur->son[now ^ 1];
        else
            cur = cur->son[now];
    }
    return ans;
}

int main() {
    memset(p, -1, sizeof(p));
    read(n);
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v), read(w);
        add(u, v, w), add(v, u, w);
    }
    dfs(1, 0);
    root = new trie;
    for (int i = 1; i <= n; i++) insert(XOR[i]);
    for (int i = 1; i <= n; i++) ans = max(ans, query(XOR[i]));
    cout << ans;
    return 0;
}
```

