## A USACO08DEC Secret Message G
### Descritption
[P2922 USACO08DEC Secret Message G](https://www.luogu.com.cn/problem/P2922)

### Solution
йҰ–е…ҲжҢүйўҳж„Ҹе»әеҘҪ $trie$ ж ‘гҖӮеҜ№дәҺдёҖдёӘжҡ—еҸ·пјҢйңҖиҰҒжұӮеҮәжңүеӨҡе°‘жқЎдҝЎжҒҜжҳҜе®ғзҡ„еүҚзјҖпјҢд»ҘеҸҠе®ғжҳҜеӨҡе°‘жқЎдҝЎжҒҜзҡ„еүҚзјҖгҖӮз”Ё $cntEnd$ иЎЁзӨәжңүеӨҡе°‘жқЎдҝЎжҒҜд»ҘиҜҘиҠӮзӮ№дёәз»“е°ҫпјҢ$sum$ иЎЁзӨәиҜҘиҠӮзӮ№еҜ№еә”дҝЎжҒҜжҳҜеӨҡе°‘жқЎдҝЎжҒҜзҡ„еүҚзјҖгҖӮжҜҸж¬ЎжҹҘиҜўеҸҜд»ҘжұӮеҮәеңЁжңҖеҗҺдёҖдҪҚд№ӢеүҚиҜҘжҡ—еҸ·еүҚзјҖзҡ„дёӘж•°пјҢеңЁжңҖеҗҺдёҖдёӘиҠӮзӮ№йҖҡиҝҮ $sum$ еҸҜд»Ҙеҫ—еҲ°иҝҷдёӘжҡ—еҸ·жҳҜеӨҡе°‘жқЎдҝЎжҒҜзҡ„еүҚзјҖпјҢеҠ иө·жқҘеҺ»дёӘйҮҚеҚіеҸҜгҖӮ
### Code
```cpp Secret Message G
#include <bits/stdc++.h>

using namespace std;

int m, n, k;
bool v;

struct trie {
    trie* son[2];
    int cntEnd, sum;
    trie() {
        son[1] = son[0] = NULL;
        cntEnd = sum = 0;
    }
} * root;

template <class T>
void read(T& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void insert(vector<bool>& bin) {
    trie* cur = root;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sum++;
    }
    cur->cntEnd++;
}

int query(vector<bool>& bin) {
    trie* cur = root;
    int ans = 0;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) return ans;
        cur = cur->son[now];
        ans += cur->cntEnd;
    }
    ans += cur->sum - cur->cntEnd;
    return ans;
}

int main() {
    read(m), read(n);
    root = new trie;
    for (int i = 1; i <= m; i++) {
        read(k);
        vector<bool> bin;
        for (int i = 1; i <= k; i++) read(v), bin.push_back(v);
        insert(bin);
    }
    for (int i = 1; i <= n; i++) {
        read(k);
        vector<bool> bin;
        for (int i = 1; i <= k; i++) read(v), bin.push_back(v);
        cout << query(bin) << endl;
    }
    return 0;
}
