## B IOI2008 Type Printer жү“еҚ°жңә
### Descritption
[P4683 IOI2008 Type Printer жү“еҚ°жңә](https://www.luogu.com.cn/problem/P4683)

### Solution
е®№жҳ“еҸ‘зҺ°пјҢжүҖжңүеӯ—з¬ҰдёІйғҪиҰҒжү“еҚ°пјҢйҷӨдәҶжңҖеҗҺдёҖдёӘеӨ–йғҪиҰҒеҲ йҷӨгҖӮиҰҒдҪҝжҢүй”®ж¬Ўж•°жңҖе°‘пјҢжңҖеҗҺжү“еҚ°зҡ„еӯ—з¬ҰдёІеҝ…йЎ»жңҖй•ҝгҖӮеҜ№жңҖй•ҝзҡ„еӯ—з¬ҰдёІеңЁ $trie$ ж ‘дёҠжү“дёӘж Үи®°пјҢ$dfs$ ж—¶жҠҠжңүж Үи®°зҡ„иҠӮзӮ№ж”ҫеңЁжңҖеҗҺжҗңзҙўе°ұиЎҢдәҶгҖӮ

### Code
```cpp Type Printer
#include <bits/stdc++.h>

using namespace std;

int n;
char s[21];
vector<char> ans;
struct trie {
    int son[26];
    bool isEnd, tag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = -1;
        isEnd = tag = 0;
    }
} trie[25000 * 20];
int root, tot;

void insert(const string& s) {
    int cur = root;
    for (int i = 0; i < s.size(); i++) {
        int now = s[i] - 'a';
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
    trie[cur].isEnd = 1;
}

void addTag(const string& s) {
    int cur = root;
    for (int i = 0; i < s.size(); i++) {
        cur = trie[cur].son[s[i] - 'a'];
        trie[cur].tag = 1;
    }
}

void dfs(int now) {
    int last = -1;
    for (int i = 0; i < 26; i++) {
        if (trie[now].son[i] != -1) {
            if (!trie[trie[now].son[i]].tag) {
                ans.push_back(i + 'a');
                if (trie[trie[now].son[i]].isEnd) ans.push_back('P');
                dfs(trie[now].son[i]);
                ans.push_back('-');
            } else
                last = i;
        }
    }
    if (last != -1) {
        ans.push_back(last + 'a');
        if (trie[trie[now].son[last]].isEnd) ans.push_back('P');
        dfs(trie[now].son[last]);
    }
}

int main() {
    scanf("%d", &n);
    int mxLen = 0;
    string lastString;
    for (int i = 1; i <= n; i++) {
        scanf("%s", s);
        if (strlen(s) > mxLen) mxLen = strlen(s), lastString = s;
        insert(s);
    }
    addTag(lastString);
    dfs(root);
    printf("%d\n", ans.size());
    for (int i = 0; i < ans.size(); i++) putchar(ans[i]), putchar('\n');
    return 0;
}
```
## C USACO12DEC First! G
### Description
[P3065 USACO12DEC First! G](https://www.luogu.com.cn/problem/P3065)

### Solution
йҰ–е…Ҳе»әеҮә $trie$ ж ‘пјҢз„¶еҗҺжһҡдёҫжҜҸдёҖдёӘеӯ—з¬ҰдёІпјҢиҖғеҜҹе®ғиғҪеҗҰжҺ’еңЁз¬¬дёҖдёӘгҖӮе…·дҪ“зҡ„пјҢе°ҶдёҖдёӘеӯ—з¬ҰдёІж”ҫеңЁ $trie$ ж ‘дёҠжҹҘиҜўпјҢеҰӮжһңйҖ”еҫ„жҹҗдёӘзӮ№пјҢиҝҷдёӘзӮ№жҳҜе…¶е®ғдёІзҡ„з»“е°ҫпјҢйӮЈд№ҲиҜҘдёІдёҚеҸҜиғҪжҺ’з¬¬дёҖпјӣеҗҰеҲҷеҸҜд»Ҙж №жҚ®иҠӮзӮ№и®ҝй—®йЎәеәҸе»әз«Ӣе…ідәҺеӯ—жҜҚдјҳе…Ҳзә§зҡ„еӣҫпјҢз”ЁжӢ“жү‘жҺ’еәҸеҲӨж–ӯжҳҜеҗҰеӯҳеңЁзҺҜпјҢиӢҘеӯҳеңЁзҺҜиҜҙжҳҺиҜҘеӯ—з¬ҰдёІдёҚиғҪжҺ’еңЁз¬¬дёҖдёӘгҖӮ

### Code
```cpp USACO12DEC First! G
#include <bits/stdc++.h>

using namespace std;

const int maxn = 30005;
int n, ans;
string s[maxn];
int inDegree[26];
vector<int> v[26];
vector<int> firstId;

struct trie {
    trie* son[26];
    bool isEnd;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        isEnd = 0;
    }
} * root;

void insert(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) cur->son[s[i] - 'a'] = new trie;
        if (i == s.size() - 1) cur->son[s[i] - 'a']->isEnd = 1;
        cur = cur->son[s[i] - 'a'];
    }
}

bool check(const string& s) {
    for (int i = 0; i < 26; i++) {
        v[i].clear();
        inDegree[i] = 0;
    }
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        for (int j = 0; j < 26; j++)
            if (cur->son[j] != NULL && j != s[i] - 'a') {
                v[s[i] - 'a'].push_back(j);
                inDegree[j]++;
            }
        if (i != s.size() - 1 && cur->son[s[i] - 'a']->isEnd) return false;
        cur = cur->son[s[i] - 'a'];
    }
    stack<int> st;
    for (int i = 0; i < 26; i++)
        if (!inDegree[i]) st.push(i);
    while (!st.empty()) {
        int now = st.top();
        st.pop();
        for (int i = 0; i < v[now].size(); i++) {
            inDegree[v[now][i]]--;
            if (!inDegree[v[now][i]]) st.push(v[now][i]);
        }
    }
    for (int i = 0; i < 26; i++)
        if (inDegree[i]) return false;
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n;
    root = new trie;
    for (int i = 1; i <= n; i++) cin >> s[i], insert(s[i]);
    for (int i = 1; i <= n; i++)
        if (check(s[i])) firstId.push_back(i), ans++;
    cout << ans << endl;
    for (int i = 0; i < firstId.size(); i++) cout << s[firstId[i]] << endl;
    return 0;
}
```
## D CQOI2016 и·Ҝз”ұиЎЁ
