е…ҲжҠҠIPең°еқҖжҢүйўҳзӣ®иҰҒжұӮиҪ¬еҢ–дёәдәҢиҝӣеҲ¶жҸ’е…Ҙ $trie$ ж ‘пјҢйЎәдҫҝеҜ№жңҖеҗҺи®ҝй—®зҡ„иҠӮзӮ№и®°еҪ• $inTime$ е’Ң $length$, еҲҶеҲ«иЎЁзӨәиҝҷдёӘ $IP$ ең°еқҖиў«жҸ’е…Ҙзҡ„ж—¶й—ҙе’ҢжҺ©з Ғй•ҝеәҰгҖӮжҹҘиҜўж—¶пјҢеҜ№дәҺ $inTime$ еңЁ $a$ е’Ң $b$ д№Ӣй—ҙзҡ„ $IP$ ең°еқҖпјҢи®°еҪ•еҜ№еә”жҺ©з Ғй•ҝеәҰ, е°ҶиҝҷдёӨдёӘдҝЎжҒҜеӯҳе…Ҙ $Vector$пјӣеҜ№дәҺ $inTime$ еңЁ $a$ д№ӢеүҚзҡ„иҠӮзӮ№пјҢжӣҙж–°жҺ©з Ғй•ҝеәҰжңҖеӨ§еҖјгҖӮжңҖеҗҺеҜ№ $Vector$ жҢүз…§ $IP$ ең°еқҖжҢүжҸ’е…Ҙж—¶й—ҙжҺ’еәҸпјҢз„¶еҗҺд»ҺеүҚеҲ°еҗҺжү«дёҖйҒҚ $Vector$пјҢеҗҢж—¶жӣҙж–°жҺ©з Ғй•ҝеәҰжңҖеӨ§еҖјпјҢе°ұеҸҜд»ҘзҹҘйҒ“иҜҘеҫ…жҹҘиҜўзҡ„IPең°еқҖзҡ„и·Ҝз”ұиЎЁйЎ№йҖүжӢ©еҸ‘з”ҹдәҶеӨҡе°‘ж¬ЎеҸҳеҢ–гҖӮ
### Code
```cpp CQOI2016 и·Ҝз”ұиЎЁ
#include <bits/stdc++.h>
#define pii pair<int, int>

using namespace std;

int n, x, cntAdd, len, a, b;
char type;
struct trie {
    trie* son[2];
    int inTime, length;
    trie() {
        son[1] = son[0] = NULL;
        inTime = length = 0;
    }
} * root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(vector<bool>& bin, int l, int id) {
    trie* cur = root;
    for (int i = 0; i < l; i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        if (i == l - 1) {
            cur->inTime = id;
            cur->length = l;
        }
    }
}

void query(vector<bool>& bin, int l, int r) {
    trie* cur = root;
    int cnt = 0, mx = 0;
    vector<pii> tmp;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) break;
        cur = cur->son[now];
        if (cur->inTime >= l && cur->inTime <= r)
            tmp.push_back(make_pair(cur->inTime, cur->length));
        else if (cur->inTime < l)
            mx = max(mx, cur->length);
    }
    sort(tmp.begin(), tmp.end());
    for (int i = 0; i < tmp.size(); i++)
        if (tmp[i].second > mx) mx = tmp[i].second, cnt++;
    printf("%d\n", cnt);
}

int main() {
    n = read();
    root = new trie;
    for (int i = 1; i <= n; i++) {
        type = getchar();
        if (type == 'A') {
            cntAdd++;
            vector<bool> bin;
            for (int i = 1; i <= 4; i++) {
                x = read();
                for (int j = 7; ~j; j--) bin.push_back((x >> j) & 1);
            }
            len = read();
            insert(bin, len, cntAdd);
        } else {
            vector<bool> bin;
            for (int i = 1; i <= 4; i++) {
                x = read();
                for (int j = 7; ~j; j--) bin.push_back((x >> j) & 1);
            }
            a = read(), b = read();
            query(bin, a, b);
        }
    }
    return 0;
}
