## E JSOI2009 з”өеӯҗеӯ—е…ё
### Description
[P4407 JSOI2009 з”өеӯҗеӯ—е…ё](https://www.luogu.com.cn/problem/P4407)

### Solution
жҢүз…§йўҳж„ҸзӣҙжҺҘжҡҙжҗңеҚіеҸҜпјҢжіЁж„ҸеҲӨйҮҚгҖӮ
### Code
```cpp JSOI2009
#include <bits/stdc++.h>

using namespace std;

int n, m, ans, tot;
string s;
struct trie {
    trie* son[26];
    int endTag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        endTag = 0;
    }
} * root;
unordered_map<int, bool> vis;

void insert(const string& s, int id) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) cur->son[s[i] - 'a'] = new trie;
        cur = cur->son[s[i] - 'a'];
    }
    cur->endTag = id;
}

bool isWord(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) return false;
        cur = cur->son[s[i] - 'a'];
        if (i == s.size() - 1 && cur->endTag) return true;
    }
    return false;
}

void dfs(trie* now, int i, bool canOpt) {
    if (i == s.size()) {
        if (now->endTag && !vis[now->endTag]) ans++, vis[now->endTag] = 1;
        if (canOpt) {
            for (int k = 0; k < 26; k++)
                if (now->son[k] != NULL && now->son[k]->endTag &&
                    !vis[now->son[k]->endTag])
                    ans++, vis[now->son[k]->endTag] = 1;
        }
        return;
    }
    if (!canOpt && now->son[s[i] - 'a'] == NULL) return;
    if (now->son[s[i] - 'a'] != NULL) dfs(now->son[s[i] - 'a'], i + 1, canOpt);
    if (canOpt) {
        //еўһеҠ дёҖдҪҚ
        for (int k = 0; k < 26; k++)
            if (now->son[k] != NULL) dfs(now->son[k], i, 0);
        //еҲ йҷӨдёҖдҪҚ
        dfs(now, i + 1, 0);
        //дҝ®ж”№дёҖдҪҚ
        for (int k = 0; k < 26; k++)
            if (now->son[k] != NULL) dfs(now->son[k], i + 1, 0);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> m;
    root = new trie;
    for (int i = 1; i <= n; i++) {
        cin >> s;
        insert(s, i);
    }
    for (int i = 1; i <= m; i++) {
        vis.clear();
        cin >> s;
        if (isWord(s))
            cout << -1 << endl;
        else {
            ans = 0;
            dfs(root, 0, 1);
            cout << ans << endl;
        }
    }
    return 0;
}
```
## F AHOI2005 з—…жҜ’жЈҖжөӢ
### Description
[P2536 AHOI2005 з—…жҜ’жЈҖжөӢ](https://www.luogu.com.cn/problem/P2536)

### Solution
жҢүз…§йўҳж„Ҹе»әеҮә $trie$ ж ‘пјҢз„¶еҗҺи®°еҝҶеҢ–жҗңзҙўеҚіеҸҜгҖӮжң¬йўҳжңүеҠ ејәзүҲпјҢйңҖиҰҒдҪҝз”Ё AC иҮӘеҠЁжңәе®һзҺ°йҖҡй…Қз¬ҰжЁЎзіҠеҢ№й…ҚгҖӮ(еҶҷе®Ң AC иҮӘеҠЁжңәеҚҡе®ўеҶҚжҠҠй“ҫжҺҘиҙҙдёҠ)

### Code
```cpp AHOI2005 з—…жҜ’жЈҖжөӢ
#include <bits/stdc++.h>

using namespace std;

const int maxn = 505;
int n, ans, len;
char s[maxn], T[maxn * 2];
int isVirus[maxn], firstId[maxn];
int to[200];
bitset<1001> vis[maxn * maxn];

struct trie {
    trie* son[4];
    int endTag, num;
    trie() {
        for (int i = 0; i < 4; i++) son[i] = NULL;
        endTag = num = 0;
    }
} * root;

void insert(const string& s, const int& id) {
    static int tot;
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[to[s[i]]] == NULL) cur->son[to[s[i]]] = new trie;
        cur = cur->son[to[s[i]]];
        cur->num = ++tot;
    }
    if (!cur->endTag) cur->endTag = id;
    firstId[id] = cur->endTag;
}

void match(trie* now, int i) {
    if (i == len) {
        isVirus[now->endTag] = 1;
        return;
    }
    if (vis[now->num][i]) return;
    vis[now->num][i] = 1;
    if (T[i] == '*') {
        match(now, i + 1);
        for (int k = 0; k < 4; k++)
            if (now->son[k] != NULL)
                match(now->son[k], i + 1), match(now->son[k], i);
    } else if (T[i] == '?') {
        for (int k = 0; k < 4; k++)
            if (now->son[k] != NULL) match(now->son[k], i + 1);
    } else {
        if (now->son[to[T[i]]] != NULL) match(now->son[to[T[i]]], i + 1);
    }
}

int main() {
    to['A'] = 0, to['T'] = 1, to['C'] = 2, to['G'] = 3;
    scanf("%s%d", T, &n);
    len = strlen(T);
    root = new trie;
    for (int i = 1; i <= n; i++) scanf("%s", s), insert(s, i);
    for (int i = 0; i < maxn * maxn; i++) vis[i].reset();
    match(root, 0);
    for (int i = 1; i <= n; i++)
        if (isVirus[firstId[i]]) ans++;
    printf("%d\n", n - ans);
    return 0;
}
```
## G SCOI2016 иғҢеҚ•иҜҚ
### Description
[P3294 SCOI2016 иғҢеҚ•иҜҚ](https://www.luogu.com.cn/problem/P3294)

### Solution
жҳҫз„¶пјҢжғ…еҪў $3$ жҜ”жғ…еҪў $1$ е’Ң $2$ жӣҙдјҳпјҢеӣ дёәжғ…еҪў $1$ е’Ңжғ…еҪў $2$ дёҚз®ЎжҖҺж ·йғҪдјҡеҗғеӨ§дәҺзӯүдәҺ $x$ дёӘжіЎжӨ’гҖӮеҸӘйңҖиҰҒиҖғиҷ‘жғ…еҪў $3$пјҢеҜ№дәҺжғ…еҪў $3$ жҲ‘д»¬йңҖиҰҒжһ„е»әдёҖз§Қж–№жЎҲпјҢдҪҝеҫ—$\sum(x-y)$ жңҖе°ҸгҖӮ

йҰ–е…Ҳе°Ҷиҫ“е…Ҙзҡ„еӯ—з¬ҰдёІеҸҚиҪ¬еҗҺжҸ’е…Ҙ $trie$ ж ‘дёӯпјҢиҝҷж ·иҪ¬еҢ–дёәеүҚзјҖж–№дҫҝеӨ„зҗҶгҖӮ
е®№жҳ“еҸ‘зҺ°пјҢйҷӨдәҶ $root$ е’Ң дёҖдёӘдёІжңҖеҗҺдёҖдёӘеӯ—з¬ҰеҜ№еә”иҠӮзӮ№еӨ–пјҢе…¶е®ғиҠӮзӮ№еҜ№зӯ”жЎҲжІЎжңүеҪұе“ҚпјҢжҲ‘д»¬ж №жҚ®иҝҷдәӣз»ҲзӮ№иҠӮзӮ№йҮҚж–°жһ„е»ә $trie$ ж ‘пјҢе°ҶеӨҡдҪҷзҡ„иҠӮзӮ№еҲ жҺүгҖӮд»ҘдёӢеӣҫдёәдҫӢпјҡ

и®ҫжңүеӯ—з¬ҰдёІпјҡ$CA,GDA,HDA,EA,IFB$

еҺҹжқҘзҡ„ $trie$ ж ‘:
![](https://s2.ax1x.com/2019/10/28/K6m0Rf.png)

йҮҚж–°жһ„е»әзҡ„ $trie$ ж ‘:
![](https://s2.ax1x.com/2019/10/28/K6mwJP.png)

е®№жҳ“еҸ‘зҺ°пјҢдёҖдёӘиҠӮзӮ№(еҜ№еә”дёҖдёӘеӯ—з¬ҰдёІ)зҡ„иҙЎзҢ®еҸ–еҶідәҺе®ғе’Ңе®ғзҲ¶дәІиў«йҖүеҸ–зҡ„ж—¶й—ҙе·®гҖӮеҸҜд»ҘиҜҒжҳҺпјҢжҢүdfsйҖүеҸ–пјҢдё”е…Ҳи®ҝй—®sizeе°Ҹзҡ„еӯҗж ‘жңҖдјҳгҖӮ

е…ҲиҜҒжҳҺжҢү $dfs$ еәҸйҖүеҸ–дёҖе®ҡжңҖдјҳпјҢеҜ№дәҺд»ҘеҗҢдёҖж·ұеәҰзҡ„иҠӮзӮ№дёәж №зҡ„дёҖзі»еҲ—еӯҗж ‘пјҢеңЁдёҖйў—дёӯжүҫдёҖдёӘеҸ¶еӯҗиҠӮзӮ№ $j$,еңЁеҸҰдёҖйў—йҮҢжүҫдёҖдёӘж №иҠӮзӮ№ $i$ (еҪ“еүҚеәҸеҲ—дёӯjжүҖеңЁзҡ„еӯҗж ‘зҡ„ж №еңЁiд№ӢеүҚеҮәзҺ°)гҖӮйңҖиҰҒжҳҺзЎ®зҡ„жҳҜпјҢеҸӘжңүиҝҷдёӨз§ҚиҠӮзӮ№й—ҙжүҚиғҪдәӨжҚўйЎәеәҸпјҢеҗҰеҲҷеҫ—еҲ°еәҸеҲ—дёҚж»Ўи¶іжғ…еҪў $3$ гҖӮеҒҮи®ҫ $j$ еңЁ $i$ д№ӢеүҚд»Јд»·жңҖе°ҸпјҢе°қиҜ•е°Ҷ $j$ ж”ҫеңЁ $i$ зҡ„еҗҺйқўгҖӮеҸҜд»ҘеҸ‘зҺ°еҸ‘зҺ° $i$ зҡ„еӯ©еӯҗд»¬е’Ң $i$ зҡ„и·қзҰ»йғҪдјҡеҠ  1пјҢжүҖд»ҘжҖ»д»Јд»·дјҡеўһеҠ пјҢиҖҢ $j$ е’Ң $j$ зҡ„зҲ¶дәІзҡ„и·қзҰ»дёҖе®ҡд№ҹдјҡеўһеҠ пјҢжүҖд»ҘжҖ»д»Јд»·д№ҹдјҡеўһеҠ гҖӮ

еҶҚиҜҒжҳҺдјҳе…ҲйҖүеҸ–sizeе°Ҹзҡ„еӯҗж ‘жӣҙдјҳгҖӮе®һйҷ…дёҠпјҢжҢүз…§dfsеәҸпјҢз¬¬iдёӘйҖүеҸ–зҡ„еӯҗж ‘зҡ„ж №зҡ„иҙЎзҢ®зӯүдәҺд№ӢеүҚйҖүеҸ–зҡ„еӯҗж ‘зҡ„sizeзҡ„е’ҢпјҢжүҖд»Ҙsizeе°Ҹзҡ„еә”иҜҘж”ҫеңЁеүҚйқўгҖӮ

### Code SCOI2016 иғҢеҚ•иҜҚ
```cpp
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 510005;
int n, sz[maxn], in[maxn];
string s;
ll ans;
vector<int> v[maxn];

struct trie {
    int son[26];
    int tag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = -1;
        tag = 0;
    }
} trie[maxn];
int root, tot;

void insert(const string &s) {
    int cur = root;
    for (int i = s.size() - 1; ~i; i--) {
        int now = s[i] - 'a';
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
        if (!i) trie[cur].tag = 1;
    }
}

void rebuild(int now, int pre) {
    for (int i = 0; i < 26; i++) {
        if (trie[now].son[i] != -1) {
            if (trie[trie[now].son[i]].tag) {
                v[pre].push_back(trie[now].son[i]);
                rebuild(trie[now].son[i], trie[now].son[i]);
            } else
                rebuild(trie[now].son[i], pre);
        }
    }
}

bool cmp(const int &a, const int &b) { return sz[a] < sz[b]; }
void dfs(int now) {
    sz[now] = 1;
    for (int i = 0; i < v[now].size(); i++) {
        dfs(v[now][i]);
        sz[now] += sz[v[now][i]];
    }
    sort(v[now].begin(), v[now].end(), cmp);
}

void dfs2(int now) {
    static int tim;
    in[now] = tim++;
    for (int i = 0; i < v[now].size(); i++) {
        ans += tim - in[now];
        dfs2(v[now][i]);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> s, insert(s);
    rebuild(root, root);
    dfs(root);
    dfs2(root);
    cout << ans;
    return 0;
}
```

## H HAOI2017 дҫӣз»ҷдҫ§ж”№йқ©
### Description
[P3732 HAOI2017 дҫӣз»ҷдҫ§ж”№йқ©](https://www.luogu.com.cn/problem/P3732)

### Solution
еңЁзәҝдёҚеӨӘеҘҪеҒҡпјҢиҖғиҷ‘зҰ»зәҝеӨ„зҗҶпјҢе°ҶиҜўй—®жҢүеҸіз«ҜзӮ№жҺ’еәҸ,д»Һ $1$ еҲ° $n$ жһҡдёҫиө·е§ӢдҪҚ $i$пјҢе°Ҷиө·е§ӢдҪҚзҪ® $i$ еҲ°жңҖеҗҺдёҖдҪҚзҡ„йғЁеҲҶжҸ’е…Ҙ $trie$ ж ‘дёӯпјҢз„¶еҗҺжҹҘиҜўеҜ№еҸіз«ҜзӮ№дёә $i$ зҡ„иҜўй—®зҡ„зӯ”жЎҲгҖӮе®һйҷ…дёҠпјҢз”ұдәҺж•°жҚ®йҡҸжңәз”ҹжҲҗпјҢе®№жҳ“жҺЁеҮәжңҖй•ҝе…¬е…ұеүҚзјҖй•ҝеәҰдёҚи¶…иҝҮ40пјҢжүҖд»ҘеҸӘйңҖиҰҒд»Һиө·е§ӢдҪҚ $i$ ејҖе§ӢеҫҖеҗҺжҸ’е…Ҙ $40$ дҪҚе°ұеҸҜд»ҘдәҶгҖӮ

еҜ№д»»ж„ҸдҪҚзҪ®$i$пјҢи®° $pos[k]$ еҜ№еә”жңҖеӨ§е·Ұз«ҜзӮ№пјҢдҪҝеҫ— $data(pos[k],i)=k$гҖӮжҳҫз„¶пјҢ$k$ и¶ҠеӨ§пјҢ$pos[k]$ и¶Ҡе°ҸгҖӮеҗҢж—¶ $trie$ ж ‘дёҠжҜҸдёӘиҠӮзӮ№и®°дёҖдёӘ $last$пјҢиЎЁзӨәдёҠж¬Ўиў«и®ҝй—®ж—¶еҜ№еә”дёІзҡ„иө·зӮ№дҪҚзҪ®гҖӮжҸ’е…Ҙж—¶пјҢе®№жҳ“з®—еҮәд№ӢеүҚзҡ„жҸ’е…Ҙзҡ„дёІе’ҢеҪ“еүҚдёІ
иў«жҸ’е…ҘйғЁеҲҶзҡ„е…¬е…ұеүҚзјҖзҡ„й•ҝеәҰ $l$, е№¶жӣҙж–° $pos[l]$ = $\max(pos[l],last)$,еҜ№еә”ж–°зҡ„жңҖеӨ§е·Ұз«ҜзӮ№гҖӮ

жҜҸж¬ЎжҸ’е…ҘеҗҺпјҢеҜ№жүҖжңүд»Ҙ $i$ дёәеҸіз«ҜзӮ№зҡ„иҜўй—®пјҢжһҡдёҫе…¬е…ұеүҚзјҖзҡ„й•ҝеәҰ $k$пјҢж №жҚ® $pos$ дёӯзҡ„дҝЎжҒҜеҚіеҸҜжұӮеҫ—иҜҘиҜўй—®зҡ„зӯ”жЎҲгҖӮ

### Code
```cpp HAOI2017 дҫӣз»ҷдҫ§ж”№йқ©
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 100005;
int n, m, pos[50];
// pos[k]еҜ№еә”жңҖеӨ§е·Ұз«ҜзӮ№пјҢдҪҝеҫ— data(pos[k],i)=k;
//еӨ§дәҺpos[k]зҡ„дҪҚзҪ®пјҢdata(pos[k],i)<k
char s[maxn];
ll ans[maxn];
struct trie {
    trie* son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} * root;

struct Question {
    int l, r, qId;
    bool operator<(const Question& other) { return r < other.r; }
} Q[maxn];

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(int st) {
    trie* cur = root;
    for (int i = st; i <= min(st + 39, n); i++) {
        int now = s[i] - '0';
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        if (cur->last) pos[i - st + 1] = max(pos[i - st + 1], cur->last);
        cur->last = st;
    }
}

int main() {
    n = read(), m = read();
    scanf("%s", s + 1);
    for (int i = 1; i <= m; i++) Q[i].l = read(), Q[i].r = read(), Q[i].qId = i;
    sort(Q + 1, Q + m + 1);
    root = new trie;
    for (int i = 1, j = 1; i <= n; i++) {
        insert(i); //жҸ’е…Ҙиө·е§ӢдҪҚзҪ®еңЁiзҡ„дёІ
        while (j <= m && Q[j].r == i) {//д»Ҙiз»“е°ҫиҜўй—®
            for (int k = 1; k <= 40; k++) {//жһҡдёҫй•ҝеәҰ
                if (pos[k] >= Q[j].l)// pos[k]еңЁ[l,r]еҶ…
                    ans[Q[j].qId] +=k * (pos[k] - max(pos[k + 1] + 1, Q[j].l) +1); 
                else
                    break;  
                    // data(pos[k+1]+1,pos[k])=k
                    //з”ұposеҚ•и°ғжҖ§еҸҜзҹҘжӣҙеӨ§зҡ„kйғҪдёҚеҗҲжі•
            }
            j++;  //дёӢдёҖдёӘиҜўй—®
        }
    }
    for (int i = 1; i <= m; i++) printf("%lld\n", ans[i]);
    return 0;
}
```
## I BJOI2016 IPең°еқҖ
### Description
[P5460 BJOI2016 IPең°еқҖ](https://www.luogu.com.cn/problem/P5460)

### Solution
дёҖдёӘ $ip$ ең°еқҖеңЁж“ҚдҪң $[l+1,r]$ еҢ№й…ҚеҲ°зҡ„з”ҹж•Ҳи§„еҲҷеҸҳеҢ–зҡ„ж¬Ўж•°зӯүдәҺ еңЁ $[1,r]$ зҡ„еҸҳеҢ–ж¬Ўж•°**еҮҸеҺ»** еңЁ$[1,l]$ зҡ„еҸҳеҢ–ж¬Ўж•°гҖӮе®№жҳ“еҸ‘зҺ°пјҢдёҚи®әеҲ йҷӨиҝҳжҳҜжҸ’е…ҘжҹҗдёҖи§„еҲҷпјҢеңЁ $trie$ ж ‘дёӯпјҢеҸӘдјҡеҜ№**еҪ“еүҚи§„еҲҷзҡ„з»“е°ҫ**е’Ң**еҪ“еүҚи§„еҲҷз»“е°ҫеҫҖдёӢзҡ„з¬¬дёҖдёӘз»“е°ҫ**д№Ӣй—ҙзҡ„е…ЁйғЁиҠӮзӮ№дә§з”ҹеҪұе“ҚгҖӮ

з”Ё $cnt$ и®°еҪ•еҲ°еҪ“еүҚиҠӮзӮ№еҢ№й…ҚеҲ°зҡ„з”ҹж•Ҳи§„еҲҷеҸҳеҢ–зҡ„ж¬Ўж•°пјҢ$lazyTag$дҪңдёәе»¶иҝҹдёӢж”ҫж Үи®°пјҢ$endTag$ и®°еҪ•жҳҜеҗҰдёәжҹҗжқЎи§„еҲҷзҡ„з»“е°ҫгҖӮеңЁжҸ’е…Ҙ/еҲ йҷӨдёҖдёӘи§„еҲҷж—¶пјҢеңЁз»“е°ҫеӨ„жӣҙж–° $endTag= endTag + type$($type$ дёә 1 иЎЁзӨәжҸ’е…ҘпјҢ-1 иЎЁзӨәеҲ йҷӨ)пјҢ$cnt++$ иЎЁзӨәеҢ№й…ҚеҲ°зҡ„з”ҹж•Ҳи§„еҲҷеҸ‘з”ҹдәҶдёҖж¬ЎеҸҳеҢ–пјҢеҗҢж—¶жӣҙж–° $lazyTag$гҖӮжҸ’е…Ҙ/еҲ йҷӨзҡ„еҗҢж—¶жІҝйҖ”дёӢж”ҫж Үи®°пјҢзӣҙеҲ°йҒҮеҲ°дёӢдёҖдёӘз»“е°ҫеҒңжӯўгҖӮ  

е°Ҷж“ҚдҪңжҢү 1 еҲ° $n$ зҡ„йЎәеәҸиҝӣиЎҢпјҢеҜ№дәҺж“ҚдҪң $i$, еҸҜд»Ҙйў„еӨ„зҗҶеҮәе“ӘдәӣиҜўй—®зҡ„е·Ұз«ҜзӮ№жҲ–еҸіз«ҜзӮ№жҳҜ $i$гҖӮе°ҶиҝҷдәӣиҜўй—®зҡ„ IP ең°еқҖж”ҫеңЁеҪ“еүҚзҡ„ $trie$ дёҠжҹҘиҜўпјҢеҗҢж—¶жІҝйҖ”дёӢж”ҫж Үи®°, иҝ”еӣһжң«е°ҫеӨ„зҡ„ $cnt$ еҚіеҸҜжұӮеҫ—иҜҘ IP ең°еқҖеңЁж“ҚдҪң$[1,i]$ еҢ№й…ҚеҲ°зҡ„з”ҹж•Ҳи§„еҲҷеҸҳеҢ–зҡ„ж¬Ўж•°гҖӮеҰӮжһңжҳҜе·Ұз«ҜзӮ№пјҢеҲҷиҝҷдёӘиҜўй—®зҡ„зӯ”жЎҲеә”еҮҸеҺ» $cnt$; еҗҰеҲҷпјҢиҝҷдёӘиҜўй—®зҡ„зӯ”жЎҲеә”еҠ дёҠ $cnt$гҖӮ

### Code
```cpp BJOI2016 IPең°еқҖ
#include <bits/stdc++.h>

using namespace std;
const int maxn = 1e5 + 5;

int n, m;
char opt[4];
string principle[maxn], ip[maxn];
int l[maxn], r[maxn], type[maxn], ans[maxn];
vector<int> vl[maxn], vr[maxn];

struct trie {
    trie* son[2];
    int lazyTag, endTag, cnt;
    trie() {
        son[0] = son[1] = NULL;
        lazyTag = endTag = cnt = 0;
    }
} * root;

void pushDown(trie* cur) {
    if (cur->son[0] == NULL) cur->son[0] = new trie;
    if (cur->son[1] == NULL) cur->son[1] = new trie;

    if (!cur->son[0]->endTag)
        cur->son[0]->lazyTag += cur->lazyTag, cur->son[0]->cnt += cur->lazyTag;
    if (!cur->son[1]->endTag)
        cur->son[1]->lazyTag += cur->lazyTag, cur->son[1]->cnt += cur->lazyTag;

    cur->lazyTag = 0;
}

void insert(const string& s, int type) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        pushDown(cur);
        cur = cur->son[s[i] - '0'];
    }
    cur->endTag += type;
    cur->lazyTag++;
    cur->cnt++;
}

int query(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - '0'] == NULL) return cur->cnt;
        pushDown(cur);
        cur = cur->son[s[i] - '0'];
    }
    return cur->cnt;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++) {
        cin >> opt >> principle[i];
        type[i] = (opt[0] == 'A' ? 1 : -1);
    }
    for (int i = 1; i <= m; i++) {
        cin >> ip[i] >> l[i] >> r[i];
        vl[l[i]].push_back(i);
        vr[r[i]].push_back(i);
    }
    root = new trie;
    for (int i = 1; i <= n; i++) {
        insert(principle[i], type[i]);
        for (int j = 0; j < vl[i].size(); j++) {
            int id = vl[i][j];
            ans[id] -= query(ip[id]);
        }
        for (int j = 0; j < vr[i].size(); j++) {
            int id = vr[i][j];
            ans[id] += query(ip[id]);
        }
    }
    for (int i = 1; i <= m; i++) cout << ans[i] << endl;
    return 0;
}
```
## J Ynoi2011 з«һиөӣе®һйӘҢзҸӯ
### Description
[P5312 Ynoi2011 з«һиөӣе®һйӘҢзҸӯ](https://www.luogu.com.cn/problem/P5312)

### Solution
еҜ№дәҺж“ҚдҪң 1гҖҒ3пјҢж №жҚ®ејӮжҲ–иҝҗз®—жҖ§иҙЁ, ејҖдёҖдёӘе…ЁеұҖејӮжҲ–еҖј $X$ ( еҲқе§Ӣдёә0 пјү, жҜҸж¬Ўе°Ҷ $X$ ејӮжҲ–дёҠж“ҚдҪң 3 з»ҷеҮәзҡ„ $x$гҖӮеҪ“жҸ’е…ҘдёҖдёӘж•° $x$ ж—¶пјҢе°Ҷ $x$ ејӮжҲ–дёҠ $X$ еҶҚжҸ’е…ҘпјҢиҝҷж ·еңЁжҹҘиҜўж—¶еҶҚејӮжҲ–дёҠеҪ“еүҚзҡ„ $X$ е°ұеҸҜд»Ҙеҫ—еҲ°жҸ’е…Ҙ $x$ д№ӢеҗҺпјҢиҝӣиЎҢдёҖзі»еҲ—ж“ҚдҪң 3 еҗҺ $x$ зҡ„зңҹе®һеҖјгҖӮ

жіЁж„ҸеҲ°з»ҸиҝҮж“ҚдҪң 4пјҢ д»»ж„Ҹж—¶еҲ»зҡ„еәҸеҲ—дёҖе®ҡжҳҜеүҚеҚҠж®өжңүеәҸпјҢеҗҺеҚҠж®өж— еәҸзҡ„пјҢиҝҷдёӨж®өеҜ№еә”еҢәй—ҙи®°дёә $[1,lastN]$ е’Ң $[lastN+1,n]$гҖӮ
е®һйҷ…дёҠпјҢжһ„е»әеҮәзҡ„ $trie$ ж ‘жҹҗз§ҚзЁӢеәҰдёҠиҜҙжң¬иә«е°ұжҳҜжҺ’еҘҪеәҸзҡ„пјҢжүҖд»ҘеҜ№дәҺж“ҚдҪң 2пјҢжңүеәҸзҡ„йғЁеҲҶеҸҜд»ҘеңЁ $trie$ дёҠз”Ёзұ»дјје№іиЎЎж ‘жҹҘиҜўеүҚзјҖе’Ңзҡ„ж–№ејҸпјӣж— еәҸзҡ„йғЁеҲҶеҸҜд»Ҙз”ЁдәҢз»ҙж•°з»„и®°жҜҸдёҖдҪҚ 1 зҡ„дёӘж•°зҡ„еүҚзјҖе’ҢжұӮеҮәпјҢиҝҷдёӘеүҚзјҖе’ҢеңЁжҺ’еәҸеҗҺжё…йӣ¶гҖӮ

з»јеҗҲдёҠиҝ°еҲҶжһҗпјҢжҹҘиҜўеә”еҲҶжңүдёӨз§ҚгҖӮе…·дҪ“зҡ„пјҢеҜ№дәҺж— еәҸйғЁеҲҶзҡ„жҹҘиҜўпјҢж №жҚ® $X$ зҡ„еҖјпјҢз»“еҗҲеүҚзјҖе’Ңж•°з»„пјҢеҸҜд»ҘжҺЁеҮәеңЁ $[lastN+1,n]$ иҝҷж®өеҢәй—ҙдёҠжҜҸдёҖдҪҚ 1 зҡ„дёӘж•°зҡ„е®һйҷ…еҖјпјҢдёҖдҪҚдёҖдҪҚзҙҜеҠ еҸҜеҫ—зӯ”жЎҲпјӣеҜ№дәҺжңүеәҸзҡ„йғЁеҲҶпјҢеә”еҲҶеҲ«жұӮеҮәеүҚ $lastN$ дёӘж•°зҡ„е’Ңд»ҘеҸҠеүҚ $l-1$ дёӘж•°зҡ„е’ҢпјҢдёӨиҖ…зӣёеҮҸеҸҜеҫ—жңүеәҸйғЁеҲҶ $[l,lastN]$ зҡ„е’ҢпјҢиҜҰи§Ғд»Јз ҒгҖӮ
### Code
```cpp Ynoi2011 з«һиөӣе®һйӘҢзҸӯ
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 1e5 + 5;
int n, m, type, l, r, X, lastN, lastXor;
int a[maxn * 2], sum[maxn * 2][31];

struct trie {
    trie* son[2];
    int sz;
    int cnt[31];
    trie() {
        son[0] = son[1] = NULL;
        for (int i = 0; i < 31; i++) cnt[i] = 0;
        sz = 0;
    }
} * root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(const int& x) {
    trie* cur = root;
    for (int i = 30; i >= 0; i--) {
        int to = (x >> i) & 1;
        if (cur->son[to] == NULL) cur->son[to] = new trie;
        cur = cur->son[to];
        cur->sz++;
        for (int k = 0; k <= 30; ++k) cur->cnt[k] += (x >> k) & 1;
    }
}

ll query2(const int& l, const int& r) {
    ll ans = 0, len = r - l + 1;
    for (int i = 0; i < 31; i++) {
        ll cnt = sum[r][i] - sum[l - 1][i];
        if ((X >> i) & 1) cnt = len - cnt;
        ans += cnt << i;
    }
    return ans;
}

ll query1(int sz) {
    if (!sz) return 0;
    ll ans = 0, val = 0; 
    //val и®°еҪ•жҺ’еҗҚз¬¬szзҡ„ж•°еңЁеҪ“еүҚж ‘дёӯзҡ„еҖјпјҢжңҖеҗҺе®һйҷ…еҖјиҰҒејӮжҲ–е…ЁеұҖX
    //ans еңЁжҹҘиҜўзҡ„ж—¶еҖҷе·Із»ҸеҜ№XејӮжҲ–иҝҮдәҶпјҢжңҖеҗҺдёҚйңҖиҰҒеҶҚејӮжҲ–
    trie* cur = root;
    for (int i = 30; i >= 0; --i) {
        int to = (lastXor >> i) & 1;  //жңҖеҗҺдёҖж¬ЎжҺ’еәҸеҗҺзҡ„ејӮжҲ–еҖј
        if (cur->son[to] != NULL && sz <= cur->son[to]->sz)
            cur = cur->son[to], val |= to << i;
        else {
            int sizeOfSon = (cur->son[to] == NULL ? 0 : cur->son[to]->sz);
            //з»ҹи®Ўson[to]зҡ„иҙЎзҢ®, жіЁж„Ҹз”Ёзҡ„жҳҜеҪ“еүҚејӮжҲ–еҖј
            for (int k = 0; k < 31; k++) {
                ll cnt = (cur->son[to] == NULL ? 0 : cur->son[to]->cnt[k]);
                if ((X >> k) & 1) cnt = sizeOfSon - cnt;//е®һйҷ…еҖјиҰҒејӮжҲ–X
                ans += cnt << k;
            }
            //иө°еҸҰеӨ–дёҖиҫ№
            sz -= sizeOfSon;
            cur = cur->son[to ^ 1];
            val |= (to ^ 1) << i;
        }
    }
    return ans + (val ^ X) * sz;  //еҸҜиғҪеӨҡдёӘж•°з»“е°ҫеңЁеҗҢдёҖй“ҫ
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) {
        a[i] = read();
        for (int k = 0; k < 31; k++)
            sum[i][k] = sum[i - 1][k] + ((a[i] >> k) & 1);
    }
    m = read();
    root = new trie;
    for (int i = 1; i <= m; i++) {
        type = read();
        if (type == 1) {
            a[++n] = read() ^ X;
            for (int k = 0; k < 31; k++)
                sum[n][k] = sum[n - 1][k] + ((a[n] >> k) & 1);
        } else if (type == 2) {
            l = read(), r = read();
            //жңүеәҸйғЁеҲҶз”ЁtrieеӨ„зҗҶпјҢж— еәҸйғЁеҲҶеҲ©з”ЁеүҚзјҖе’Ң
            if (r <= lastN)
                printf("%lld\n", query1(r) - query1(l - 1));
            else if (l > lastN)
                printf("%lld\n", query2(l, r));
            else
                printf("%lld\n",
                       query1(lastN) - query1(l - 1) + query2(lastN + 1, r));
        } else if (type == 3) {
            X ^= read();
        } else {
            for (int k = lastN + 1; k <= n; k++) insert(a[k]);
            memset(sum[n], 0, sizeof(sum[n]));
            lastN = n, lastXor = X;
        }
    }
    return 0;
}
```
## K Choosing The Commander
### Description
[CF817E Choosing The Commander](https://www.luogu.com.cn/problem/CF817E)

### Solution
жҸ’е…ҘдёҖдёӘж•°е°Ҷе…¶и®ҝй—®иҝҮзҡ„иҠӮзӮ№зҡ„ $sum++$пјҢеҲ йҷӨдёҖдёӘж•°еҲҷ $sum--$гҖӮжҹҘиҜўж—¶пјҢзұ»дјје№іиЎЎж ‘жұӮ $rank$ зҡ„еҒҡжі•гҖӮе…·дҪ“зҡ„пјҢи®° $l$ зҡ„з¬¬ $i$ дҪҚдёә $l_i$пјҢ$p$ зҡ„з¬¬ $i$ дҪҚдёә $p_i$гҖӮиӢҘ $l_i=1$,йӮЈд№Ҳзӯ”жЎҲеә”иҜҘеҠ дёҠ $son[p_i]$зҡ„ $sum$пјҢеҗҢж—¶з»§з»ӯжҹҘиҜў $son[p_iвҠ•1]$пјӣеҗҰеҲҷз»§з»ӯжҹҘиҜў $son[p_i]$гҖӮ

### Code
```cpp Choosing The Commander
#include <bits/stdc++.h>

using namespace std;

int n, p, l, type;
struct trie {
    trie* son[2];
    int sum;
    trie() {
        son[0] = son[1] = NULL;
        sum = 0;
    }
} * root;

template <class T>
void read(T& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void insert(int p, int type) {
    trie* cur = root;
    for (int i = 31; ~i; i--) {
        int now = (p >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sum += type;
    }
}

void query(int p, int l) {
    int ans = 0;
    trie* cur = root;
    for (int i = 31; ~i; i--) {
        bool pi = (p >> i) & 1;
        bool li = (l >> i) & 1;
        if (cur == NULL) break;
        if (li && cur->son[pi] != NULL) ans += cur->son[pi]->sum;
        cur = cur->son[pi ^ li];
    }
    printf("%d\n", ans);
}

int main() {
    read(n);
    root = new trie;
    for (int i = 1; i <= n; i++) {
        read(type), read(p);
        if (type == 1)
            insert(p, 1);
        else if (type == 2)
            insert(p, -1);
        else
            read(l), query(p, l);
    }
    return 0;
}
```
## L CF241B Friends
### Description
[CF241B Friends](https://www.luogu.com.cn/problem/CF241B)
### Solution
зӣҙжҺҘжұӮз¬¬ $k$ дёҚеӨӘеҘҪеӨ„зҗҶпјҢеӣ дёәйҖүеҸ–зҡ„жҳҜж— еәҸеҜ№пјҢеӯҳеңЁйҖүеҸ–йЎәеәҸй—®йўҳ,дёҚз„¶дјҡйҮҚеӨҚгҖӮдёәдәҶж–№дҫҝеҸҜд»ҘиҖғиҷ‘жұӮжүҖжңүжңүеәҸеҜ№зҡ„ејӮжҲ–еҖјпјҢз„¶еҗҺжұӮеүҚ $2k$ еӨ§зҡ„ејӮжҲ–еҖјзҡ„е’Ң пјҢйӮЈд№Ҳзӯ”жЎҲе°ұжҳҜжұӮеҫ—зҡ„е’Ңзҡ„дёҖеҚҠпјҢиҝҷж ·е°ұдёҚйңҖиҰҒиҖғиҷ‘йҮҚеӨҚдәҶгҖӮ

е»әз«ӢеҘҪ $trie$ ж ‘еҗҺпјҢз”Ёзұ»дјје№іиЎЎж ‘жұӮз¬¬ $2k$ еӨ§зҡ„ж–№жі•жұӮеҮәз¬¬ $2k$ еӨ§зҡ„дёӨдёӨејӮжҲ–еҖј $valKth$пјҢеҗҢж—¶еҸҜд»Ҙеҫ—еҲ°иҝҷж ·зҡ„еҖјжңүеӨҡе°‘дёӘгҖӮжҺҘдёӢжқҘдәҺеҜ№жҜҸдёҖдёӘж•° $val[i]$пјҢеңЁ $trie$ ж ‘дёҠпјҢжұӮдёҺд№ӢејӮжҲ–еҗҺеӨ§дәҺ $valKth$ зҡ„ж•°зҡ„е’ҢгҖӮе…·дҪ“зҡ„пјҢиӢҘ $valkth$ з¬¬ $j$ дҪҚдёә 1пјҢйӮЈд№ҲжҺҘдёӢжқҘеә”иҜҘи®ҝй—®е’Ң $val[i]$ з¬¬ $j$ дҪҚдә’иЎҘзҡ„йӮЈдёӘе„ҝеӯҗпјӣеҗҰеҲҷпјҢеә”иҜҘи®ҝй—®$val[i]$ з¬¬ $j$ дҪҚзӣёеҗҢзҡ„е„ҝеӯҗпјҢеҗҢж—¶з»ҹи®ЎдёҺ $val[i]$ еңЁз¬¬ $j$ дҪҚејӮжҲ–еҖјдёә 1 зҡ„еҖјзҡ„е’ҢгҖӮе…·дҪ“зҡ„з»ҹи®Ўж–№жі•жҳҜпјҢеңЁйў„еӨ„зҗҶж—¶е°Ҷ $val$ ж•°з»„жҺ’еәҸпјҢи®°еҪ•жҜҸдёҖдҪҚдёҠ 0/1 ж•°йҮҸзҡ„еүҚзјҖе’ҢпјҢеңЁжҸ’е…Ҙж—¶и®°еҪ•жҜҸдёӘиҠӮзӮ№еҜ№еә” $val$ зҡ„дёӢж ҮиҢғеӣҙпјҢд№ӢеҗҺж №жҚ®иҝҷдёӘиҢғеӣҙеҶ…жҜҸдёҖдҪҚ(и®ҫдёә $p$)  0/1 зҡ„дёӘж•°д»ҘеҸҠ $val[i]$ зҡ„з¬¬ $p$ дҪҚзҡ„еҖјжҢүдҪҚжұӮе’ҢеҚіеҸҜгҖӮ
### Code
```cpp CF241B Friends
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 5e4 + 5;
const int MOD = 1e9 + 7;
const int BIT = 30;
int n, val[MAXN];
ll k, pre[MAXN][BIT + 2][2];  //жҜҸдёҖдҪҚдёҠ0,1зҡ„дёӘж•°еүҚзјҖе’Ң

struct trie {
    trie* son[2];
    int sz, mx, mi;
    trie() {
        son[0] = son[1] = NULL;
        sz = mx = mi = 0;
    }
} * root;

ll qpow(ll a, ll b) {
    ll ans = 1, base = a;
    while (b) {
        if (b & 1) ans = ans * base % MOD;
        b >>= 1, base = base * base % MOD;
    }
    return ans;
}

void insert(int& id) {
    trie* cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val[id] >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sz++;
        cur->mx = id;
        cur->mi = (cur->mi ? cur->mi : id);
    }
}

ll getKth(ll& k) {
    ll ans = 0;
    trie* nodePtr[MAXN];
    for (int i = 1; i <= n; i++) nodePtr[i] = root;
    for (int j = BIT; ~j; j--) {
        ll tmp = 0;
        bool tag = 1;
        for (int i = 1; i <= n; i++)
            if (nodePtr[i] != NULL &&
                nodePtr[i]->son[((val[i] >> j) & 1) ^ 1] != NULL)
                tmp += nodePtr[i]->son[((val[i] >> j) & 1) ^ 1]->sz;
        if (tmp >= k)  //иҜҘдҪҚйҖү1зҡ„ж–№жЎҲж•°>=kпјҢеҲҷз¬¬kеӨ§зҡ„еңЁиҝҷдёҖдҪҚеҝ…дёә1
            ans |= 1ll << j;
        else  //иҜҘдҪҚйҖү1зҡ„ж–№жЎҲж•°<kпјҢеҲҷз¬¬kеӨ§зҡ„еңЁиҝҷдёҖдҪҚеҝ…дёә0пјҢдё”жҺ’еҗҚ<=k-иҜҘдҪҚйҖү1зҡ„ж–№жЎҲж•°
            k -= tmp, tag = 0;
        for (int i = 1; i <= n; i++)
            if (nodePtr[i])
                nodePtr[i] = nodePtr[i]->son[((val[i] >> j) & 1) ^ tag];
    }
    return ans;
}

void getSum(ll k) {
    ll valKth = getKth(k);
    ll ans = valKth * k % MOD;
    for (int i = 1; i <= n; i++) {
        //еҜ№дәҺжҜҸдёҖдёӘж•°пјҢжұӮдёҺд№ӢејӮжҲ–еҗҺеӨ§дәҺvalKthзҡ„ж•°зҡ„е’Ң
        trie* cur = root;
        for (int j = BIT; ~j; j--) {
            if (cur == NULL) break;
            if ((valKth >> j) & 1)
                cur = cur->son[((val[i] >> j) & 1) ^ 1];
            else {
                if (cur->son[((val[i] >> j) & 1) ^ 1] != NULL) {
                    int l = cur->son[((val[i] >> j) & 1) ^ 1]->mi - 1;
                    int r = cur->son[((val[i] >> j) & 1) ^ 1]->mx;
                    for (int p = BIT; ~p; p--) {
                        if ((val[i] >> p) & 1)
                            ans += (pre[r][p][0] - pre[l][p][0]) << p;
                        else
                            ans += (pre[r][p][1] - pre[l][p][1]) << p;
                        ans %= MOD;
                    }
                }
                cur = cur->son[(val[i] >> j) & 1];
            }
        }
    }
    cout << ans * qpow(2, MOD - 2) % MOD;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> k;
    k *= 2;
    for (int i = 1; i <= n; i++) cin >> val[i];
    sort(val + 1, val + n + 1);
    root = new trie;
    for (int i = 1; i <= n; i++) insert(i);
    for (int j = BIT; ~j; j--)
        for (int i = 1; i <= n; i++) {
            pre[i][j][0] = pre[i - 1][j][0] + !((val[i] >> j) & 1);
            pre[i][j][1] = pre[i - 1][j][1] + ((val[i] >> j) & 1);
        }
    getSum(k);
    return 0;
}
```

## L еҚҒдәҢзңҒиҒ”иҖғ2019 ејӮжҲ–зІҪеӯҗ
### Description
[P5283 еҚҒдәҢзңҒиҒ”иҖғ2019 ејӮжҲ–зІҪеӯҗ](https://www.luogu.com.cn/problem/P5283)
### Solution
дёҠдёҖйўҳзҡ„ејұеҢ–зүҲгҖӮжң¬жңәиҝҗиЎҢж—¶еҸҜиғҪзӮёеҶ…еӯҳпјҢеҸҜд»ҘйҖӮеҪ“и°ғе°Ҹ MAXN зҡ„еҖјгҖӮ
### Code
```cpp еҚҒдәҢзңҒиҒ”иҖғ2019 ејӮжҲ–зІҪеӯҗ
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 5e5 + 5;
const int BIT = 31;
int n;
ll k, pre[MAXN][BIT + 1][2], val[MAXN], x;
struct trie {
    trie* son[2];
    int sz, mx, mi;
    trie() {
        son[0] = son[1] = NULL;
        sz = mx = mi = 0;
    }
} * root;

void insert(int& id) {
    trie* cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val[id] >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sz++;
        cur->mx = id;
        cur->mi = (cur->mi ? cur->mi : id);
    }
}

ll getKth(ll& k) {
    ll ans = 0;
    trie* nodePtr[MAXN];
    for (int i = 1; i <= n + 1; i++) nodePtr[i] = root;
    for (int j = BIT; ~j; j--) {
        ll tmp = 0;
        bool tag = 1;
        for (int i = 1; i <= n + 1; i++)
            if (nodePtr[i] != NULL &&
                nodePtr[i]->son[((val[i] >> j) & 1) ^ 1] != NULL)
                tmp += nodePtr[i]->son[((val[i] >> j) & 1) ^ 1]->sz;
        if (tmp >= k)
            ans |= 1ll << j;
        else
            k -= tmp, tag = 0;
        for (int i = 1; i <= n + 1; i++)
            if (nodePtr[i])
                nodePtr[i] = nodePtr[i]->son[((val[i] >> j) & 1) ^ tag];
    }
    return ans;
}

void getSum(ll k) {
    ll valKth = getKth(k);
    ll ans = valKth * k;
    for (int i = 1; i <= n + 1; i++) {
        trie* cur = root;
        for (int j = BIT; ~j; j--) {
            if (cur == NULL) break;
            if ((valKth >> j) & 1)
                cur = cur->son[((val[i] >> j) & 1) ^ 1];
            else {
                if (cur->son[((val[i] >> j) & 1) ^ 1] != NULL) {
                    int l = cur->son[((val[i] >> j) & 1) ^ 1]->mi - 1;
                    int r = cur->son[((val[i] >> j) & 1) ^ 1]->mx;
                    for (int p = BIT; ~p; p--) {
                        if ((val[i] >> p) & 1)
                            ans += (pre[r][p][0] - pre[l][p][0]) << p;
                        else
                            ans += (pre[r][p][1] - pre[l][p][1]) << p;
                    }
                }
                cur = cur->son[(val[i] >> j) & 1];
            }
        }
    }
    cout << ans / 2;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> k;
    k *= 2;
    val[1] = 0;
    for (int i = 2; i <= n + 1; i++) {
        cin >> x;
        val[i] = val[i - 1] ^ x;
    }
    sort(val + 1, val + n + 2);
    root = new trie;
    for (int i = 1; i <= n + 1; i++) insert(i);
    for (int j = BIT; ~j; j--)
        for (int i = 1; i <= n + 1; i++) {
            pre[i][j][0] = pre[i - 1][j][0] + !((val[i] >> j) & 1);
            pre[i][j][1] = pre[i - 1][j][1] + ((val[i] >> j) & 1);
        }
    getSum(k);
    return 0;
}
