### Solution
еҒҡжі•еҗҢ CF241B FriendsгҖӮдёҚиҝҮжҢүз…§ CF241B Friends зҡ„еҒҡжі•з©әй—ҙеӨҚжқӮеәҰдёә $O(61*N)$пјҢжҳҫз„¶дёҚеҸҜиғҪжҠҠж•ҙдёӘ $trie$ ж ‘еӯҳиҝӣеҺ»гҖӮе®һйҷ…дёҠпјҢеҸӘжұӮз¬¬ $k$ еӨ§зҡ„иҜқжңүз”Ёзҡ„еҸӘжңүдёҖеұӮиҠӮзӮ№пјҢеҪ“и®ҝй—®еҲ°дёӢдёҖеұӮж—¶пјҢе°ҶдёҠдёҖеұӮиҠӮзӮ№еҲ йҷӨе°ұеҘҪдәҶгҖӮиҝҷж ·з©әй—ҙеӨҚжқӮеәҰеҸҳдёә $O(N)$пјҢж—¶й—ҙеӨҚжқӮеәҰдҫқз„¶дёә$O(61*N)$гҖӮ

жіЁ: з”Ёзі»з»ҹиҮӘеёҰзҡ„ $delete$ ж—¶дёҚзҹҘйҒ“дёәдҪ• $RE$ дәҶпјҢиҝҷйҮҢжүӢеҶҷдәҶ $new$ е’Ң $delete$ ж“ҚдҪңгҖӮ
### Code
```cpp CF1055F Tree and XOR
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 1e6 + 5;
const int BIT = 61;
int n, p[MAXN],u,tot[2];
ll k, val[MAXN], v;

template<class T>
void read(T &x, int f = 1) {
  char ch = getchar();
  x = 0;
  while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
  while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
  x *= f;
}

struct trie {
  trie* son[2];
  int sz;
  trie() {
    son[0] = son[1] = NULL;
    sz = 0;
  }
}*root,node[MAXN][2];

trie* newNode(trie* &cur,bool tag) {
  return cur=&node[tot[tag]++][tag];
}

void getKth(ll k) {
  ll ans = 0;
  newNode(root,0);
  trie *nodePtr[MAXN],*valPtr[MAXN];
  for (int i = 1; i <= n; i++) nodePtr[i] = valPtr[i] = root;
  for (int j = BIT; ~j; j--) {
    ll tmp = 0;
    bool tag = 0;
    for (int i = 1; i <= n; i++) {
      if (valPtr[i]->son[((val[i] >> j) & 1)] == NULL)
        newNode(valPtr[i]->son[((val[i] >> j) & 1)],j&1);
      valPtr[i] = valPtr[i]->son[((val[i] >> j) & 1)];
      valPtr[i]->sz++;
    }
    for (int i = 1; i <= n; i++)
      if (nodePtr[i] != NULL && nodePtr[i]->son[((val[i] >> j) & 1)] != NULL)
        tmp += nodePtr[i]->son[((val[i] >> j) & 1)]->sz;
    if (tmp < k) {
      k -= tmp, tag = 1;
      ans |= 1ll << j;
    }
    for (int i = 1; i <= n; i++)
      if (nodePtr[i] != NULL)
        nodePtr[i] = nodePtr[i]->son[((val[i] >> j) & 1) ^ tag];
    for(int i=0; i<=tot[(j&1)^1]; i++) {
      node[i][(j&1)^1].son[0]=node[i][(j&1)^1].son[1]=NULL;
      node[i][(j&1)^1].sz=0;
    }
    tot[(j&1)^1]=0;
  }
  cout << ans;
}

struct edge {
  int nxt, to;
  ll val;
} e[MAXN];

void addEdge(int from, int to, ll val) {
  static int t;
  e[t].val = val, e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, ll v) {
  val[now] = v;
  for (int i = p[now]; ~i; i = e[i].nxt) {
    int to = e[i].to;
    if (!val[to]) dfs(to, v ^ e[i].val);
  }
}

int main() {
  read(n),read(k);
  memset(p, -1, sizeof(p));
  for (int i = 1; i <= n - 1; i++) {
    read(u), read(v);
    addEdge(u, i + 1, v);
  }
  dfs(1, 0);
  getKth(k);
  return 0;
}
```
