## A жңҖеӨ§ејӮжҲ–е’Ң
### Description
[P4735 жңҖеӨ§ејӮжҲ–е’Ң](https://www.luogu.com.cn/problem/P4735)
### Solution
и®° $preXor_i$ иЎЁзӨәеүҚ $i$ дёӘж•°зҡ„ејӮжҲ–е’ҢгҖӮеҜ№дәҺжҹҘиҜўж“ҚдҪңпјҢз”ЁејӮжҲ–жҖ§иҙЁиҪ¬еҢ–дёҖдёӢпјҢеҸӘйңҖиҰҒжұӮ $preXor_NвҠ•x$ ејӮжҲ–дёҠ $preXor_{p-1}$ зҡ„жңҖеӨ§еҖјпјҲ$l-1<=p<=r-1$пјүпјҢеҚіеңЁ $r-1$ зүҲжң¬зҡ„ $trie$ ж ‘дёӯжұӮжҸ’е…Ҙж—¶й—ҙеӨ§дәҺзӯүдәҺ $l-1$ зҡ„ж•°дёҺ $preXor_NвҠ•x$ зҡ„жңҖеӨ§ејӮжҲ–е’ҢгҖӮеӣ жӯӨжҜҸдёӘзӮ№и®°дёҖдёӘ $last$пјҢиЎЁзӨәжңҖеҗҺи®ҝй—®зҡ„ж—¶й—ҙпјҢеҪ“ $last\ge l-1$ж—¶жүҚеҸҜиғҪиў«и®Ўе…Ҙзӯ”жЎҲгҖӮ 
### Code
```cpp жңҖеӨ§ејӮжҲ–е’Ң
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 3e5 + 5;

int n, m, l, r;
int preXor, x;
char type[2];
struct trie {
    trie *son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} node[MAXN * 48], *root[MAXN * 2];

void read(int &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
}

trie *newNode(trie *&cur) {
    static int cntNode;
    return cur = &node[cntNode++];
}

void initR0() {
    trie *cur = newNode(root[0]);
    for (register int i = 23; i >= 0; i--) cur = newNode(cur->son[0]);
}

void build(const int &id) {
    trie *cur = newNode(root[id]), *pre = root[id - 1];
    for (register int i = 23; ~i; i--) {
        int now = (preXor >> i) & 1;
        if (pre != NULL) {
            cur->son[now ^ 1] = pre->son[now ^ 1];
            pre = pre->son[now];
        }
        cur = newNode(cur->son[now]);
        cur->last = id;
    }
}

void query(trie *cur, const int &last, const int &val) {
    int ans = 0;
    for (register int i = 23; ~i; i--) {
        int now = (val >> i) & 1;
        trie *tmp = cur->son[now ^ 1];
        if (tmp != NULL && tmp->last >= last)
            cur = tmp, ans += 1 << i;
        else
            cur = cur->son[now];
    }
    printf("%d\n", ans);
}

int main() {
    read(n), read(m);
    initR0();
    for (int i = 1; i <= n; i++) {
        read(x);
        preXor ^= x;
        build(i);
    }
    for (int i = 1; i <= m; i++) {
        scanf("%s", type);
        if (type[0] == 'A') {
            read(x);
            preXor ^= x;
            build(++n);
        } else {
            read(l), read(r), read(x);
            query(root[r - 1], l - 1, preXor ^ x);
        }
    }
    return 0;
}
