## C JSOI2015 еӯ—з¬ҰдёІж ‘
### Description
[P6088 JSOI2015 еӯ—з¬ҰдёІж ‘](https://www.luogu.com.cn/problem/P6088)
### Solution
$dfs$ ж—¶пјҢеҜ№жҜҸдёӘзӮ№пјҢеңЁе…¶зҲ¶дәІзүҲжң¬зҡ„еҹәзЎҖдёҠе»әз«ӢеҸҜжҢҒд№…еҢ– $trie$ ж ‘гҖӮд»Ө$cnt_i$ иЎЁзӨәд»Һж №еҲ°иҠӮзӮ№еҲ° $i$ жңүеӨҡе°‘еӯ—з¬ҰдёІд»Ҙ $S$ дёәеүҚзјҖгҖӮжҳҫз„¶пјҢзӯ”жЎҲе…·жңүеҸҜеҠ жҖ§пјҢ$u,v$ д№Ӣй—ҙд»Ҙ $S$ дёәеүҚзјҖзҡ„еӯ—з¬ҰдёІж•°зӣ®дёә $cnt_u + cnt_v - 2*cnt_{lca(u,v)}$пјҢжҹҘиҜўзҡ„ж—¶еҖҷжұӮдёҖдёӢ $lca$ еҚіеҸҜгҖӮ
### Code
```cpp JSOI2015 еӯ—з¬ҰдёІж ‘
#include <bits/stdc++.h>
using namespace std;
const int MAXN = 1e5 + 5;
int n, m, u, v;
char s[11];
int p[MAXN], fa[MAXN][17], depth[MAXN];
void read(int& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}
struct trie {
    trie* son[26];
    int cnt;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        cnt = 0;
    }
} node[MAXN * 10], *root[MAXN];
trie* newNode(trie*& cur) {
    static int cntNode;
    return cur = &node[cntNode++];
}
struct edge {
    int to, nxt;
    string s;
} e[MAXN * 2];
void addEdge(int from, int to, const string& s) {
    static int t;
    e[t].s = s, e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}
void build(trie* pre, trie* cur, const string& s) {
    for (int i = 0; i < s.size(); i++) {
        int to = s[i] - 'a';
        if (pre != NULL) {
            for (int j = 0; j < 26; j++) cur->son[j] = pre->son[j];
            pre = pre->son[to];
        }
        cur = newNode(cur->son[to]);
        cur->cnt = (pre != NULL ? pre->cnt : 0) + 1;
    }
}
int query(trie* cur, const string& s) {
    for (int i = 0; i < s.size(); i++) {
        int to = s[i] - 'a';
        if (cur->son[to] != NULL)
            cur = cur->son[to];
        else
            return 0;
    }
    return cur->cnt;
}
void dfs(const int& now, int d) {
    depth[now] = d;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!depth[to] && to != 1) {
            fa[to][0] = now;
            build(root[now], newNode(root[to]), e[i].s);
            dfs(to, d + 1);
        }
    }
}
void getFa() {
    for (int j = 1; (1 << j) <= n; j++)
        for (int i = 1; i <= n; i++)
            if (fa[i][j - 1]) fa[i][j] = fa[fa[i][j - 1]][j - 1];
}
int lca(int a, int b, int i = 0) {
    if (depth[a] < depth[b]) swap(a, b);
    for (; (1 << i) <= depth[a]; i++);
    for (int j = i - 1; j >= 0; j--)
        if (depth[a] - depth[b] >= (1 << j)) a = fa[a][j];
    if (a == b) return a;
    for (int j = i - 1; j >= 0; j--)
        if (fa[a][j] && fa[a][j] != fa[b][j]) a = fa[a][j], b = fa[b][j];
    return fa[a][0];
}
int main() {
    memset(p, -1, sizeof(p));
    read(n);
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v), scanf("%s", s);
        addEdge(u, v, s), addEdge(v, u, s);
    }
    newNode(root[1]);
    dfs(1, 0);
    getFa();
    read(m);
    for (int i = 1; i <= m; i++) {
        read(u), read(v), scanf("%s", s);
        printf("%d\n", query(root[u], s) + query(root[v], s) -
                           2 * query(root[lca(u, v)], s));
    }
    return 0;
}
