## C HEOI2013 ALO
### Description
[P4098 HEOI2013 ALO](https://www.luogu.com.cn/problem/P4098)
### Solution
йҰ–е…Ҳе»әз«ӢеҸҜжҢҒд№…еҢ– $trie$ ж ‘гҖӮеҜ№дәҺ $a_i$пјҢи®ҫе·Ұиҫ№з¬¬дёҖдёӘжҜ”е®ғеӨ§зҡ„ж•°дёӢж Үдёә $l_1$, е·Ұиҫ№з¬¬дәҢдёӘжҜ”е®ғеӨ§зҡ„ж•°дёӢж Үдёә $l_2$пјӣеҸіиҫ№з¬¬дёҖдёӘжҜ”е®ғеӨ§зҡ„ж•°дёӢж Үдёә $r_1$, е·Ұиҫ№з¬¬дәҢдёӘжҜ”е®ғеӨ§зҡ„ж•°дёӢж Үдёә $r_2$гҖӮжҳҫз„¶пјҢиғҪи®© $a_i$ дёәж¬ЎеӨ§еҖјзҡ„жңҖеӨ§еҢәй—ҙдёә $[l_1+1,r_2-1]$ е’Ң $[l_2+1,r_1-1]$гҖӮеҸӘйңҖйў„еӨ„зҗҶеҮә $l_{1,2}$ е’Ң $r_{1,2}$пјҢжҺҘдёӢжқҘеңЁеҸҜжҢҒд№…еҢ– $trie$ дёҠиҙӘеҝғең°жұӮжңҖеӨ§еҖјеҚіеҸҜгҖӮ

иҖғиҷ‘еҰӮдҪ•жұӮ $l_{1,2}$ е’Ң $r_{1,2}$гҖӮе°Ҷ $a_1$ еҲ°  $a_n$ жҢүд»ҺеӨ§еҲ°е°ҸжҺ’еәҸпјҢеҗҢж—¶и®°еҪ•еҺҹжқҘзҡ„дёӢж Ү $b_i$гҖӮжҺ’еәҸеҗҺжҢүйЎәеәҸе°Ҷ $b_i$ жҸ’е…Ҙ $set$ дёӯгҖӮжҳ“зҹҘ $set$ дёӯд»»ж„Ҹе…ғзҙ  $b_k$ еҜ№еә”еҖј $a_{b_k}$дёҖе®ҡеӨ§дәҺеҪ“еүҚдҪҚзҪ® $b_i$ еҜ№еә”еҖј $a_{b_i}$(йўҳзӣ®зәҰе®ҡж•°з»„ $a$ дёӯзҡ„е…ғзҙ дёҚйҮҚеӨҚ), дё” $set$ е·ІжҢүдёӢж ҮжҺ’еҘҪеәҸпјҢз”Ё lower_bound е’Ң upper_bound е®№жҳ“жұӮеҮәеҪ“еүҚдёӢж Ү $b_i$ зҡ„еүҚй©ұе’ҢеҗҺз»§гҖӮ


### Code
```cpp HEOI2013 ALO
#include <bits/stdc++.h>

using namespace std;
const int MAXN = 5e4 + 5;
const int BIT = 30;
int n, a[MAXN], b[MAXN], l[MAXN][3], r[MAXN][3];

template <class T>
void read(T &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct trie {
    trie *son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} * root[MAXN];

void insert(int id) {
    trie *cur = root[id] = new trie, *pre = root[id - 1];
    for (int i = BIT; ~i; i--) {
        int now = (a[id] >> i) & 1;
        if (pre != NULL) {
            cur->son[now ^ 1] = pre->son[now ^ 1];
            pre = pre->son[now];
        }
        cur->son[now] = new trie;
        cur = cur->son[now];
        cur->last = id;
    }
}

int query(trie *cur, int last, int val) {
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now ^ 1] != NULL && cur->son[now ^ 1]->last >= last)
            cur = cur->son[now ^ 1], ans |= 1 << i;
        else
            cur = cur->son[now];
    }
    return ans;
}

bool cmp(const int &x, const int &y) { return a[x] > a[y]; }

int main() {
    read(n);
    root[0] = new trie;
    for (int i = 1; i <= n; i++) read(a[i]), insert(i), b[i] = i;
    sort(b + 1, b + n + 1, cmp);
    set<int> s;
    set<int>::iterator it;
    s.insert(-2), s.insert(-1), s.insert(n + 1), s.insert(n + 2);
    for (int i = 1; i <= n; i++) {
        s.insert(b[i]);
        it = s.lower_bound(b[i]);
        l[b[i]][1] = max(0, *--it);
        l[b[i]][2] = max(0, *--it);
        it = s.upper_bound(b[i]);
        r[b[i]][1] = min(n + 1, *it);
        r[b[i]][2] = min(n + 1, *++it);
    }
    int ans = 0;
    for (int i = 1; i <= n; i++)
        ans = max(ans, max(query(root[r[i][1] - 1], l[i][2] + 1, a[i]),
                           query(root[r[i][2] - 1], l[i][1] + 1, a[i])));
    printf("%d", ans);
    return 0;
}
```

