еҜ№дәҺдёӨдёӘеқҗж ҮпјҢеҰӮжһңжүҖйңҖиҰҒзҡ„жқҗж–ҷеҜ№еә”зҡ„еқҗж ҮеқҮеңЁжүҖиҝһеҗ‘йҮҸзҡ„е·Ұдҫ§(йҖҡиҝҮеҗ‘йҮҸеӨ–з§ҜеҲӨж–ӯ)пјҢеҲҷдёӨзӮ№иҝһиҫ№еҚ•еҗ‘иҫ№пјҢй•ҝеәҰдёә 1гҖӮйҖҡиҝҮеј—жҙӣдјҠеҫ·жңҖе°ҸзҺҜеҸҜеҫ—еҲ°жңҖе°‘зҡ„еҺҹж–ҷж•°гҖӮ

жіЁж„Ҹпјҡ
- иӢҘжүҖйңҖжқҗж–ҷзҡ„еқҗж ҮеңЁеҺҹжқҗж–ҷеқҗж ҮжүҖиҝһзӣҙзәҝдёҠ(жӯӨж—¶еҗ‘йҮҸеӨ–з§Ҝдёә0)пјҢеҲҷйңҖйҖҡиҝҮеҗ‘йҮҸеҶ…з§ҜеҲӨж–ӯжҳҜеҗҰеңЁеҺҹжқҗж–ҷеқҗж ҮжүҖиҝһзәҝж®өдёҠ
- жіЁж„ҸжҜ”иҫғж—¶зҡ„зІҫеәҰ $epsilon$


# Code
```cpp еҗҲйҮ‘
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 505;
constexpr double EPSILON = 1e-15;

struct Vector {
    Vector() = default;
    Vector(double _x, double _y) : x(_x), y(_y) {}

    friend inline double operator* /*Г—*/(const Vector& a, const Vector& b) {
        return a.x * b.y - a.y * b.x; //еҗ‘йҮҸеӨ–з§Ҝ
    }

    friend inline Vector operator-(const Vector& a, const Vector& b) {
        return Vector(a.x - b.x, a.y - b.y);
    }

    friend inline double dotProduct(const Vector& a, const Vector& b) {
        return a.x * b.x + a.y * b.y; //еҗ‘йҮҸеҶ…з§Ҝ
    }

    double x = .0, y = .0;
} mat[MAXN], pro[MAXN];  // material and product

int n, m, ans(0x3f3f3f3f), dis[MAXN][MAXN];

inline void init() {
    memset(dis, 0x3f, sizeof(dis));
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= m; j++) {
            bool connect = true;
            for (int k = 1; k <= n; k++) {//еҲӨж–ӯжҳҜеҗҰиғҪдҪңдёәеҮёеҢ…зҡ„иҫ№
                double cross = (mat[j] - mat[i]) * (pro[k] - mat[i]);
                double dot = dotProduct(mat[j] - pro[k], mat[i] - pro[k]);
                if (cross < -EPSILON || (abs(cross) < EPSILON && dot > EPSILON))
                    connect = false;
            }
            if (connect) dis[i][j] = 1;
        }
}

inline void floyed() { //floyedжұӮжңҖе°ҸзҺҜ
    for (int k = 1; k <= m; k++)
        for (int i = 1; i <= m; i++)
            for (int j = 1; j <= m; j++) {
                dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
            }
    for (int i = 1; i <= m; i++) ans = min(ans, dis[i][i]);
    cout << (ans == 0x3f3f3f3f ? -1 : ans) << endl;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> m >> n;

    double a, b, c;
    for (int i = 1; i <= m; i++) {
        cin >> a >> b >> c;
        mat[i] = Vector(a, b);
    }
    for (int i = 1; i <= n; i++) {
        cin >> a >> b >> c;
        pro[i] = Vector(a, b);
    }
    init();
    floyed();
    return 0;
}
```

