# Description
жңү $N$ еә§еҠһе…¬жҘјдҪҚдәҺеҗҢдёҖжқЎиЎ—дёҠпјҢе·ІзҹҘжҜҸеә§еҠһе…¬жҘји·қзҰ»еӨ§иЎ—иө·зӮ№зҡ„и·қзҰ»гҖӮзҺ°иҰҒз”Ё $K$ жқЎзҪ‘з»ңз”өзјҶе°ҶеҠһе…¬жҘјиҝһжҺҘпјҢдё”д»»ж„ҸдёҖдёӘеҠһе…¬жҘјйғҪеұһдәҺе”ҜдёҖй…ҚеҜ№з»„(еҚіиҝһжҺҘзҡ„ $2K$ дёӘеҠһе…¬жҘјдёҖе®ҡжҳҜзӣёејӮзҡ„)гҖӮжұӮ $K$ жқЎзҪ‘з»ңз”өзјҶжңҖе°Ҹзҡ„й•ҝеәҰжҖ»е’ҢгҖӮ
# Solution
е®№жҳ“еҸ‘зҺ°пјҢжңҖдјҳи§ЈдёӯжҜҸдёӨдёӘй…ҚеҜ№зҡ„еҠһе…¬жҘјдёҖе®ҡжҳҜзӣёйӮ»зҡ„гҖӮдәҺжҳҜе…ҲжұӮеҮәдёӨдёӘзӣёйӮ»еҠһе…¬жҘјд№Ӣй—ҙзҡ„и·қзҰ»пјҢи®°дёә $D_1, D_2, D_3, ..., D_{N - 1}$гҖӮдәҺжҳҜй—®йўҳеҸҜд»ҘиҪ¬еҢ–дёәпјҡд»Һж•°еҲ— $D$ дёӯйҖүеҸ–дёҚи¶…иҝҮ $K$ дёӘдёҚзӣёйӮ»зҡ„ж•°пјҢдҪҝе®ғд»¬зҡ„е’ҢжңҖе°ҸгҖӮ

иҖғиҷ‘иҙӘеҝғпјҡ
  - еҰӮжһң $K=1$пјҢзӯ”жЎҲжҳҫз„¶жҳҜж•°еҲ— D дёӯзҡ„жңҖе°ҸеҖј
  - еҰӮжһң $K=2$пјҢеҸҜд»ҘиҜҒжҳҺзӯ”жЎҲжҳҜд»ҘдёӢдёӨз§Қжғ…еҶөд№ӢдёҖпјҡ
    - йҖүеҸ– $D_i$пјҢд»ҘеҸҠйҷӨдәҶ $D_{i-1}, D_i, D_{i+1}$ д№ӢеӨ–е…¶д»–ж•°дёӯзҡ„жңҖе°ҸеҖј
    - йҖүеҸ–жңҖе°ҸеҖј $D_i$е·ҰеҸідёӨдҫ§зҡ„дёӨдёӘж•°пјҢеҚі $D_{i-1}$ е’Ң $D_{i+1}$
    - еҚіжңҖдјҳи§ЈдёӯпјҢжңҖе°ҸеҖје·ҰеҸідёӨдҫ§зҡ„ж•°иҰҒд№ҲйҖүпјҢиҰҒд№ҲйғҪдёҚйҖү
  - дёәйҳІжӯўйҖүеҸ–еұҖйғЁжңҖдјҳи§ЈпјҢеҸҜд»Ҙе…ҲйҖүеҸ–ж•°еҲ— $D$ дёӯзҡ„жңҖе°ҸеҖј $D_i$пјҢз„¶еҗҺжҠҠ $D_{i-1}, D_i, D_{i+1}$ еҲ йҷӨпјҢжҠҠ $D_{i-1}+D_{i+1}-D_i$ жҸ’е…ҘеҲ°ж•°еҲ— $D$ дёӯд№ӢеүҚжү§иЎҢеҲ йҷӨзҡ„дҪҚзҪ®гҖӮиҝҷж ·еҰӮжһңд№ӢеҗҺйҖүдәҶ $D_{i-1}+D_{i+1}-D_i$пјҢзӣёеҪ“дәҺжІЎжңүйҖү $D_i$пјҢжҚўдёҠдәҶ $D_{i-1}$ е’Ң $D_{i+1}$гҖӮ

дәҺжҳҜеҸҜе»әз«ӢдёҖдёӘеҲқе§Ӣжңү $N-1$ дёӘиҠӮзӮ№зҡ„й“ҫиЎЁпјҢй“ҫиЎЁиҠӮзӮ№и®°еҪ•ж•°еҖј $D_i$пјҢиҠӮзӮ№зј–еҸ· $Id_i$пјҢд»ҘеҸҠй“ҫиЎЁиҠӮзӮ№жҢҮй’ҲжҲ–еҜ№еә”зҡ„иҝӯд»ЈеҷЁгҖӮеҶҚе»әз«ӢдёҖдёӘдјҳе…ҲйҳҹеҲ—(е°Ҹж №е Ҷ)пјҢе°Ҷй“ҫиЎЁиҠӮзӮ№еӯҳе…ҘгҖӮK ж¬Ўж“ҚдҪңдёӯпјҢеҸ–еҮәе ҶйЎ¶зҡ„й“ҫиЎЁиҠӮзӮ№ $ListNode$пјҢеңЁй“ҫиЎЁдёӯеҲ йҷӨ $ListNode->prev$ е’Ң $ListNode->next$пјҢе№¶еҲӣе»әж–°иҠӮзӮ№(ж•°еҖјдёә $ListNode->prev->data+ListNode->next->data-ListNode->data$)жҸ’е…Ҙй“ҫиЎЁе’Ңдјҳе…ҲйҳҹеҲ—гҖӮ

жіЁж„ҸпјҡдёәйҳІжӯўи¶Ҡз•ҢжҲ–з®ҖеҢ–иҫ№з•Ңжғ…еҶөеҲӨж–ӯпјҢеҸҜд»ҘеңЁй“ҫиЎЁиө·е§Ӣе’Ңжң«е°ҫжҸ’е…ҘжһҒеӨ§еҖјгҖӮ

# Code
## жҢҮй’ҲзүҲеҸҢеҗ‘й“ҫиЎЁ
```cpp жҢҮй’ҲзүҲеҸҢеҗ‘й“ҫиЎЁ
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 1e5 + 5;
constexpr LL INF = 1e18;

LL n, k, dis[MAXN], ans, cnt;

struct ListNode {
    ListNode() = default;
    bool operator<(const ListNode &other) const {
        return this->data == other.data ? this->id > other.id : this->data > other.data;
    }
    ListNode *prev = NULL, *next = NULL, *cur = NULL;
    LL data = 0, id = -1;
};
map<int, bool> deleted;

struct List {
    List() { //жһ„йҖ еҮҪж•°
        this->head = new ListNode(), this->tail = new ListNode();
        this->head->next = this->tail;
        this->tail->prev = this->head;
    }

    ListNode *insert(LL data) { //жҸ’е…ҘеҖјпјҢиҝ”еӣһиҠӮзӮ№жҢҮй’Ҳ
        ListNode *cur = new ListNode();
        cur->data = data, cur->id = cnt++, cur->cur = cur;
        tail->prev->next = cur, cur->prev = tail->prev;
        cur->next = tail, tail->prev = cur;
        return cur;
    }

    ListNode *erase(ListNode *cur) { //еҲ йҷӨиҠӮзӮ№пјҢиҝ”еӣһж–°иҠӮзӮ№жҢҮй’Ҳ
        LL data = cur->prev->data + cur->next->data - cur->data;
        ListNode *newListNode = new ListNode();
        newListNode->cur = newListNode;
        newListNode->data = data, newListNode->id = cnt++;

        ListNode *prev = cur->prev, *next = cur->next;
        prev->prev->next = newListNode, newListNode->prev = prev->prev;
        next->next->prev = newListNode, newListNode->next = next->next;

        deleted[prev->id] = deleted[next->id] = deleted[cur->id] = true;
        return newListNode;
    }

    ~List() {}
    ListNode *head = NULL, *tail = NULL;
} lst;

priority_queue<ListNode> q;
inline void calcLen(int tot = 0) {
    while (!q.empty() && tot < k) {
        ListNode* cur = q.top().cur;
        q.pop();
        if (deleted[cur->id]) continue;
        ans += cur->data, tot++;
        ListNode *newListNode = lst.erase(cur);
        q.push(*newListNode); //жҸ’е…Ҙж–°иҠӮзӮ№
    }
}

int main() {
    scanf("%lld %lld", &n, &k);
    for (int i = 0; i < n; ++i) scanf("%lld", dis + i);
    lst.insert(INF); //йҳІжӯўи¶Ҡз•Ң з®ҖеҢ–иҫ№з•ҢеҲӨж–ӯ
    for (int i = 0; i < n - 1; ++i) q.push(*lst.insert(dis[i + 1] - dis[i]));
    lst.insert(INF); //йҳІжӯўи¶Ҡз•Ң з®ҖеҢ–иҫ№з•ҢеҲӨж–ӯ
    calcLen(); //и®Ўз®—жҖ»й•ҝеәҰ
    printf("%lld\n", ans);
    return 0;
}
```
## STL list
$STL$ зҡ„ $list$ дёә зҺҜеҪўеҸҢеҗ‘й“ҫиЎЁ, жң¬йўҳдёӯз”ЁеҲ°д»ҘдёӢеҠҹиғҪгҖӮ
- йҖҡиҝҮ $iterator--$ жҲ– $iterator++$ иҺ·еҫ— $prev$ жҲ– $next$ зҡ„иҝӯд»ЈеҷЁгҖӮ
- insert() жҲҗе‘ҳеҮҪж•°еңЁжҢҮе®ҡдҪҚзҪ®еӨ„жҸ’е…ҘеҖјпјҢе№¶иҝ”еӣһжҸ’е…Ҙзҡ„е…ғзҙ жүҖеҜ№еә”зҡ„зҡ„иҝӯд»ЈеҷЁ
- erase() жҲҗе‘ҳеҮҪж•°еҜ№жҢҮе®ҡдҪҚзҪ®иҝӣиЎҢеҲ йҷӨпјҢиҝ”еӣһеҲ йҷӨзҡ„е…ғзҙ еҗҺдёҖдёӘдҪҚзҪ®зҡ„иҝӯд»ЈеҷЁ

```cpp STL list
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 1e5 + 5;
constexpr LL INF = 1e15;

LL n, k, dis[MAXN], ans, cnt;

struct ListNode {
    ListNode() = default;
    ListNode(LL _data, LL _id) : data(_data), id(_id) {}
    bool operator<(const ListNode &other) const {
        return this->data == other.data ? this->id > other.id : this->data > other.data;
    }
    LL data = INF, id = -1;
    list<ListNode>::iterator itr;
};
list<ListNode> lst;
priority_queue<ListNode> q;
map<LL, bool> deleted;

inline void calcLen(int tot = 0) {
    while (!q.empty() && tot < k) {
        auto cur = q.top();
        q.pop();
        if (deleted[cur.id]) continue;
        ans += cur.data, tot++;
        //еҲ йҷӨ
        auto itr = cur.itr;
        --itr; //еҫ—еҲ°cur->prevзҡ„иҝӯд»ЈеҷЁ
        LL data = itr->data; deleted[itr->id] = true, itr = lst.erase(itr);
        data -= itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        data += itr->data, deleted[itr->id] = true, itr = lst.erase(itr);
        //еҲ йҷӨ
        auto newNode = ListNode(data, cnt++);
        newNode.itr = lst.insert(itr, newNode);
        q.push(newNode);
    }
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 0; i < n; ++i) cin >> dis[i];
    lst.emplace_back(ListNode(INF, cnt++)); //йҳІжӯўи¶Ҡз•Ң з®ҖеҢ–иҫ№з•ҢеҲӨж–ӯ
    for (int i = 0; i < n - 1; ++i) {
        auto newNode = ListNode(dis[i + 1] - dis[i], cnt++);
        newNode.itr = lst.insert(lst.end(), newNode); //жң«е°ҫжҸ’е…Ҙ
        q.push(newNode);
    }
    lst.emplace_back(ListNode(INF, cnt++)); //йҳІжӯўи¶Ҡз•Ң з®ҖеҢ–иҫ№з•ҢеҲӨж–ӯ
    calcLen();
    cout << ans << endl;
    return 0;
}
```

