# D Teleporter
## Description
жңү $n$ дёӘе°Ҹй•ҮпјҢе°Ҹй•Ү $i$ жңүдёҖдёӘдј йҖҒиғҪдј йҖҒеҲ°е°Ҹй•Ү $j$гҖӮд»Һе°Ҹй•Ү 1 ејҖе§Ӣдј йҖҒпјҢжұӮеҮәз»ҸиҝҮ $k$ ж¬Ўдј йҖҒжңҖз»ҲеҲ°е“ӘдёӘе°Ҹй•ҮгҖӮ
## Solution
еҸҜйҖҡиҝҮжӢ“жү‘жҺ’еәҸжүҫеҲ°зҺҜ(жӢ“жү‘жҺ’еәҸеҗҺе…ҘеәҰ $in$ дёҚдёә 0 зҡ„иҠӮзӮ№дёәзҺҜдёҠзҡ„иҠӮзӮ№)гҖӮз„¶еҗҺеӨ„зҗҶеҮәзҺҜй•ҝпјҢиө·зӮ№еҲ°зҺҜзҡ„и·қзҰ»пјҢеҚіеҸҜеҲӨж–ӯдј йҖҒ $k$ ж¬ЎеҗҺжүҖеңЁзҡ„иҠӮзӮ№зј–еҸ·гҖӮ
## Code
```cpp Teleporter
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 2e5 + 5;

int n, to[MAXN], in[MAXN], step1[MAXN], step2[MAXN], vis[MAXN];
LL k, len1, len2;

void toposort() {
    queue<int> q;
    for (int i = 1; i <= n; i++)
        if (!in[i]) q.push(i);
    while (!q.empty()) {
        int cur = q.front();
        q.pop();
        if(!(--in[to[cur]])) q.push(to[cur]);
    }
}

void getLen(int cur) {
    if (vis[cur]) return;
    vis[cur] = 1;
    if (in[cur]) step2[++len2] = to[cur], getLen(to[cur]);
    else step1[++len1] = to[cur], getLen(to[cur]);
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> k;
    for (int i = 1; i <= n; i++)
        cin >> to[i], in[to[i]]++;
    toposort(), getLen(1);
    if (k <= len1) cout << step1[k] << endl;
    else {
        k = (k - len1) % len2 ? (k - len1) % len2 : len2;
        cout << step2[k] << endl;
    }
    return 0;
}
```
# E Colorful Blocks
## Description
жңүжҺ’еҲ—дәҺдёҖиЎҢзҡ„ $N$ дёӘж јеӯҗпјҢжҜҸдёӘж јеӯҗжҹ“дёҠйўңиүІ 1 еҲ° $M$пјҢжұӮиҮіеӨҡжңү $K$ еҜ№йўңиүІзӣёеҗҢзҡ„зӣёйӮ»ж јеӯҗзҡ„жҹ“иүІж–№жЎҲж•°гҖӮ
## Solution
  - $K$ еҜ№зӣёйӮ»йўңиүІзӣёеҗҢпјҢеҲҷзӣёйӮ»йўңиүІзӣёеҗҢзҡ„дёҖеҜ№ж јеӯҗзј©жҲҗдёҖдёӘж јеӯҗпјҢеҲҷжңү $NвҲ’K$ дёӘж јеӯҗйўңиүІдә’дёҚзӣёеҗҢпјҢе…¶дёӯдёҖдёӘж јеӯҗйўңиүІжңү $M$ з§ҚеҸ–жі•пјҢе…¶е®ғж јеӯҗеҸӘжңү $MвҲ’1$ з§ҚгҖӮ
  - жүҖд»Ҙзӯ”жЎҲдёә $\Sigma C_{n-1}^im(mвҲ’1)^{nвҲ’iвҲ’1}$

## Code
```cpp Colorful Blocks
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 2e5 + 5;
constexpr LL Mod = 998244353;

LL n, m, k, ans, fac[MAXN];

inline void Init() {
    fac[0] = 1;
    for (LL i = 1; i < MAXN; i++) fac[i] = fac[i - 1] * i % Mod;
}

inline LL qpow(LL a, LL b) {  // a^b
    LL res = 1;
    while (b) {
        if (b & 1) res = res * a % Mod;
        a = a * a % Mod;
        b >>= 1;
    }
    return res;
}

inline LL C(LL N, LL M) {
    if (M > N || M < 0) return 0;
    return fac[N] * qpow(fac[M], Mod - 2) % Mod * qpow(fac[N - M], Mod - 2) % Mod;
}

int main() {
    ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m >> k;
    Init();
    for (LL i = 0 ; i <= k; i++)
        ans = (ans + C(n - 1, i) * m % Mod * qpow(m - 1, n - i - 1) % Mod) % Mod;
    cout << ans << endl;
    return 0;
}
```
# F Bracket Sequencing
