```cpp еҚ•и°ғйҳҹеҲ—
inline void dp(int cur, int cnt, LL res) {
    int st = cur, end = false, m(0);
    res = diameter[cnt];
    do {
        end = true, in[cur] = 1;
        tmpDis[++m] = dis[cur]; //ж №еҲ°иҠӮзӮ№зҡ„жңҖй•ҝи·қзҰ»
        for (auto& e : G[cur]) {
            int to = e.first, w = e.second;
            if (in[to] <= 1) continue;
            end = false, cur = to;
            cycleDis[m + 1] = cycleDis[m] + w;
            break;
        }
    } while (!end);
    for (auto& e : G[cur]) { //еӣһеҲ°иө·зӮ№
        int to = e.first, w = e.second;
        if (to == st) cycleDis[m + 1] = cycleDis[m] + w;
    }
    for (int i = 1; i < m; i++) {//ж–ӯзҺҜжҲҗй“ҫ еӨҚеҲ¶дёҖеҖҚ
        tmpDis[i + m] = tmpDis[i]; //ж №еҲ°иҠӮзӮ№зҡ„жңҖй•ҝи·қзҰ»
        cycleDis[i + m] = cycleDis[m + 1] + cycleDis[i]; //з”ЁдәҺжұӮеҮәзҺҜдёҠдёӨиҠӮзӮ№и·қзҰ»
    }
    deque<int> q;
    q.push_back(1);
    for (int i = 2; i < 2 * m; i++) {
        while (!q.empty() && i - q.front() >= m) q.pop_front();
        res = max(res, tmpDis[i] + tmpDis[q.front()] + cycleDis[i] -
                           cycleDis[q.front()]);
        //и®©tmpDis[q.front()] + cycleDis[q.front()]еҚ•и°ғйҖ’еўһ
        while (!q.empty() &&
               tmpDis[i] - cycleDis[i] >= tmpDis[q.back()] - cycleDis[q.back()])
            q.pop_back(); //жҜ”еҪ“еүҚеҖје°ҸеҲҷж— ж•ҲпјҢзӣҙжҺҘеј№еҮә
        q.push_back(i);
    }
    ans += res;
}
