# Description
з»ҷе®ҡдёҖдёӘж•°з»„пјҢиӢҘж•°з»„дёӯзӣёйӮ»зҡ„дёӨдёӘж•°зӣёеҗҢ(и®ҫйғҪдёә $a$)пјҢеҲҷе®ғд»¬еҗҲе№¶дёәдёҖдёӘж•°пјҢе…¶еҖјдёә $a + 1$гҖӮжұӮеҗҲе№¶еҗҺж•°з»„зҡ„жңҖе°Ҹй•ҝеәҰгҖӮ
# Solution
  - иҖғиҷ‘еҢәй—ҙ $DP$, и®ҫ $dp[l][r]$ иЎЁзӨәеҢәй—ҙ $[l,r]$ еҗҲе№¶еҗҺзҡ„жңҖе°Ҹй•ҝеәҰпјҢе№¶и®ҫ $w[l][r]$ иЎЁзӨәеҢәй—ҙ $[l,r]$ еҗҲе№¶еҗҺзҡ„е’Ң
  - зҠ¶жҖҒиҪ¬з§»ж–№зЁӢпјҡ$dp[l][r] = \min(dp[l][r], dp[l][mid] + dp[mid + 1][r])$
  - иӢҘ $dp[l][mid] = dp[mid + 1][r] = 1$пјҢе№¶дё” $w[l][mid] = w[mid + 1][r]$пјҢеҲҷ $dp[l][r] = 1пјҢw[l][r] = w[l][mid] + 1$

# Code
```cpp Array Shrinking
#include<bits/stdc++.h>
#define boost std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0)

using namespace std;
using LL = long long;

constexpr int MAXN = 505;
constexpr LL M = 998244353;

int n, a[MAXN], dp[MAXN][MAXN], w[MAXN][MAXN];

template <typename T> inline void read(T &x) {
    int f = 1; x = 0;
    char ch = getchar();
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

int main() {
    boost;
    cin >> n;
    memset(dp, 0x3f, sizeof(dp));
    for (int i = 1; i <= n; i++) cin >> a[i], dp[i][i] = 1, w[i][i] = a[i];
    for (int len = 2; len <= n; len++)
        for (int l = 1; l + len - 1 <= n; l++) {
            int r = l + len - 1;
            for (int mid = l; mid < r; mid++) {
                dp[l][r] = min(dp[l][r], dp[l][mid] + dp[mid + 1][r]);
                if (dp[l][mid] == 1 && dp[mid + 1][r] == 1 && w[l][mid] == w[mid + 1][r])
                    dp[l][r] = 1, w[l][r] = w[l][mid] + 1;
            }
        }
    cout << dp[1][n] << endl;
    return 0;
}
